const BEAM_NODE_MAX_PREVIEW_RANGE: i32 = 30;

fn two_buildings_mut(
    buildings: &mut [BuildingComp],
    first: usize,
    second: usize,
) -> (&mut BuildingComp, &mut BuildingComp) {
    assert_ne!(first, second);
    if first < second {
        let (left, right) = buildings.split_at_mut(second);
        (&mut left[first], &mut right[0])
    } else {
        let (left, right) = buildings.split_at_mut(first);
        (&mut right[0], &mut left[second])
    }
}

fn transfer_between_power_graphs(
    graphs: &mut [PowerGraphRuntime],
    back_index: usize,
    front_index: usize,
    amount: f32,
) {
    if back_index == front_index || amount <= 0.0 {
        return;
    }
    if back_index < front_index {
        let (left, right) = graphs.split_at_mut(front_index);
        left[back_index].transfer_power(-amount);
        right[0].transfer_power(amount);
    } else {
        let (left, right) = graphs.split_at_mut(back_index);
        right[0].transfer_power(-amount);
        left[front_index].transfer_power(amount);
    }
}

