    pub fn refresh_owned_building_update_permissions(&mut self, content: &ContentLoader) -> usize {
        let env = self.state.rules.env;
        let mut disabled = 0;
        for building in &mut self.buildings {
            let was_enabled = building.enabled;
            let supports_env = content
                .block(building.block.id)
                .is_some_and(|block| block.supports_env(env));
            let in_bounds = self.state.world.tile_pos(building.tile_pos).is_some();
            if !building.check_allow_update(supports_env, in_bounds) {
                building.enabled = false;
                if was_enabled {
                    disabled += 1;
                }
            }
        }
        disabled
    }

    fn landing_pad_config_from_building(building: &BuildingComp) -> Option<i16> {
        match building.config_value() {
            TypeValue::Content(content) if content.content_type == ContentType::Item => {
                Some(content.id)
            }
            TypeValue::Int(id) if (0..=i16::MAX as i32).contains(&id) => Some(id as i16),
            _ => None,
        }
    }

    fn landing_pad_config_for_tile(&self, tile_pos: i32) -> Option<i16> {
        self.campaign_runtime_states
            .get(&tile_pos)
            .and_then(|state| match state {
                GameRuntimeCampaignBlockState::LandingPad(state) => state.config,
                _ => None,
            })
            .or_else(|| {
                self.buildings
                    .iter()
                    .find(|building| building.tile_pos == tile_pos)
                    .and_then(Self::landing_pad_config_from_building)
            })
    }

    fn landing_pad_priority_for_tile(&self, tile_pos: i32) -> Option<i32> {
        self.campaign_runtime_states
            .get(&tile_pos)
            .and_then(|state| match state {
                GameRuntimeCampaignBlockState::LandingPad(state) => Some(state.priority),
                _ => None,
            })
    }

    fn set_landing_pad_priority(&mut self, tile_pos: i32, priority: i32) -> bool {
        let Some(GameRuntimeCampaignBlockState::LandingPad(state)) =
            self.campaign_runtime_states.get_mut(&tile_pos)
        else {
            return false;
        };
        state.priority = priority;
        true
    }

    fn landing_pad_item_capacity(content: &ContentLoader) -> i32 {
        content
            .block_by_name("landing-pad")
            .and_then(|block| match block {
                BlockDef::Campaign(campaign) if campaign.kind == CampaignBlockKind::LandingPad => {
                    Some(campaign.base.item_capacity)
                }
                _ => None,
            })
            .unwrap_or(100)
            .max(1)
    }

    fn sector_info_import_rate(info: &SectorInfo, item_id: ContentId, item_name: &str) -> f32 {
        info.import_rate_cache
            .as_ref()
            .and_then(|cache| cache.get(item_id as usize))
            .copied()
            .unwrap_or_else(|| info.imports.get(item_name).map_or(0.0, |stat| stat.mean))
    }

    fn update_landing_pad_sector_import_timers(
        info: &mut SectorInfo,
        content: &ContentLoader,
        item_capacity: i32,
        frame_delta: f32,
    ) -> usize {
        let item_capacity = item_capacity.max(1) as f32;
        let delta = if frame_delta.is_finite() {
            frame_delta.max(0.0)
        } else {
            0.0
        };
        let mut updated = 0;
        for item in content.items() {
            let item_id = item.base.mappable.base.id;
            let item_name = item.name();
            let import_rate = Self::sector_info_import_rate(info, item_id, item_name);
            let timer = info
                .import_cooldown_timers
                .entry(item_name.to_string())
                .or_insert(0.0);
            if import_rate > 0.0 {
                *timer += import_rate / 60.0 / item_capacity * delta;
            } else {
                *timer = 0.0;
            }
            updated += 1;
        }
        updated
    }

    fn update_landing_pad_import_timers(
        &mut self,
        content: &ContentLoader,
        frame_delta: f32,
    ) -> usize {
        if !self.state.is_campaign() {
            return 0;
        }
        let item_capacity = Self::landing_pad_item_capacity(content);
        let mut updated = 0;
        if let Some(sector) = self.state.rules.sector.as_mut() {
            updated += Self::update_landing_pad_sector_import_timers(
                &mut sector.info,
                content,
                item_capacity,
                frame_delta,
            );
        }
        if let Some(sector) = self.state.sector.as_mut() {
            updated += Self::update_landing_pad_sector_import_timers(
                &mut sector.info,
                content,
                item_capacity,
                frame_delta,
            );
        }
        updated
    }

    fn landing_pad_import_status(
        &self,
        content: &ContentLoader,
        item_id: ContentId,
    ) -> (bool, f32) {
        let Some(item) = content.item(item_id) else {
            return (false, 0.0);
        };
        let Some(info) = self
            .state
            .rules
            .sector
            .as_ref()
            .or(self.state.sector.as_ref())
            .map(|sector| &sector.info)
        else {
            return (false, 0.0);
        };
        let item_name = item.name();
        (
            Self::sector_info_import_rate(info, item_id, item_name) > 0.0,
            info.import_cooldown_timers
                .get(item_name)
                .copied()
                .unwrap_or(0.0),
        )
    }

    fn note_campaign_landing_pad_import(
        &mut self,
        content: &ContentLoader,
        item_id: ContentId,
        amount: i32,
    ) {
        if amount <= 0 || !self.state.is_campaign() {
            return;
        }
        let Some(item_name) = content.item(item_id).map(|item| item.name().to_string()) else {
            return;
        };
        if let Some(sector) = self.state.rules.sector.as_mut() {
            sector.info.handle_production(item_name.clone(), amount);
            sector.info.handle_item_import(item_name.clone(), amount);
        }
        if let Some(sector) = self.state.sector.as_mut() {
            sector.info.handle_production(item_name.clone(), amount);
            sector.info.handle_item_import(item_name, amount);
        }
    }

    fn start_landing_pad_landing(&mut self, content: &ContentLoader, tile_pos: i32) -> bool {
        let Some(index) = self
            .buildings
            .iter()
            .position(|building| building.tile_pos == tile_pos)
        else {
            return false;
        };
        let building = self.buildings[index].clone();
        if !self.ensure_campaign_state_for_building(content, &building) {
            return false;
        }
        let config = Self::landing_pad_config_from_building(&building);
        let Some(GameRuntimeCampaignBlockState::LandingPad(state)) =
            self.campaign_runtime_states.get_mut(&tile_pos)
        else {
            return false;
        };
        if let Some(config) = config {
            state.config = Some(config);
        }
        landing_pad_handle_landing(state)
    }

    fn process_landing_pad_waiting_queue(
        &mut self,
        content: &ContentLoader,
        report: &mut GameRuntimeLandingPadFrameReport,
    ) {
        let waiting = std::mem::take(&mut self.landing_pad_waiting);
        for (item_id, mut pads) in waiting {
            let before = pads.len();
            // v158.1 changed Java to prune mismatched configs before checking size,
            // so stale pads cannot be selected or crash an empty post-prune queue.
            pads.retain(|tile_pos| self.landing_pad_config_for_tile(*tile_pos) == Some(item_id));
            report.pruned_waiting_pads += before.saturating_sub(pads.len());
            if pads.is_empty() {
                continue;
            }

            pads.sort_by_key(|tile_pos| {
                self.landing_pad_priority_for_tile(*tile_pos)
                    .unwrap_or(i32::MAX)
            });
            let first = pads[0];
            let head = *pads.last().unwrap_or(&first);

            if self.start_landing_pad_landing(content, first) {
                report.landed_tiles.push(first);
            }

            if first != head {
                if let (Some(first_priority), Some(head_priority)) = (
                    self.landing_pad_priority_for_tile(first),
                    self.landing_pad_priority_for_tile(head),
                ) {
                    self.set_landing_pad_priority(first, head_priority);
                    self.set_landing_pad_priority(head, first_priority);
                }
            }
        }
    }

    pub fn advance_owned_landing_pads_ticks(
        &mut self,
        content: &ContentLoader,
        frame_delta: f32,
    ) -> GameRuntimeLandingPadFrameReport {
        let mut report = GameRuntimeLandingPadFrameReport::default();
        let frame_delta = if frame_delta.is_finite() {
            frame_delta.max(0.0)
        } else {
            0.0
        };

        self.update_landing_pad_import_timers(content, frame_delta);
        self.process_landing_pad_waiting_queue(content, &mut report);

        for index in 0..self.buildings.len() {
            report.visited_buildings += 1;
            let Some(BlockDef::Campaign(campaign)) =
                content.block(self.buildings[index].block.id).cloned()
            else {
                continue;
            };
            if campaign.kind != CampaignBlockKind::LandingPad {
                continue;
            }
            report.landing_pad_candidates += 1;
            if !self.buildings[index].enabled {
                continue;
            }

            let tile_pos = self.buildings[index].tile_pos;
            let building = self.buildings[index].clone();
            if !self.ensure_campaign_state_for_building(content, &building) {
                report.missing_runtime_states += 1;
                continue;
            }

            let time_scale = self.buildings[index].time_scale.max(0.0);
            let scaled_delta = frame_delta * time_scale;
            let is_fake = self.buildings[index].team.0 as i32 != self.state.rules.default_team
                || !self.state.is_campaign();
            let is_campaign_non_legacy = self.state.is_campaign();

            if let Some(config) = Self::landing_pad_config_from_building(&building) {
                if let Some(GameRuntimeCampaignBlockState::LandingPad(state)) =
                    self.campaign_runtime_states.get_mut(&tile_pos)
                {
                    state.config = Some(config);
                }
            }

            let mut arrival = None;
            if let Some(GameRuntimeCampaignBlockState::LandingPad(state)) =
                self.campaign_runtime_states.get_mut(&tile_pos)
            {
                if state.arriving.is_some() {
                    arrival = Some(landing_pad_update_arrival(
                        state,
                        campaign.arrival_duration.max(0.000001),
                        campaign.consume_liquid_amount.max(0.0),
                        campaign.base.item_capacity,
                        scaled_delta,
                    ));
                }
            }

            if let Some(step) = arrival {
                if step.removed_liquid > 0.0 {
                    if let (Some(liquid), Some(liquids)) = (
                        campaign.consume_liquid,
                        self.buildings[index].liquids.as_mut(),
                    ) {
                        liquids.remove(liquid.liquid, step.removed_liquid);
                    }
                }
                if let Some(item_id) = step.finished_item {
                    if let Some(items) = self.buildings[index].items.as_mut() {
                        items.set(item_id, step.produced_amount);
                    }
                    if !is_fake {
                        self.note_campaign_landing_pad_import(
                            content,
                            item_id,
                            step.produced_amount,
                        );
                    }
                    report.finished_arrivals += 1;
                    report.imported_items += step.produced_amount.max(0) as usize;
                }
            }

            if self.buildings[index]
                .items
                .as_ref()
                .is_some_and(|items| items.total() > 0)
            {
                report.dumped_items +=
                    self.dump_accumulated_items_from_building(content, index, 1, scaled_delta);
            }

            if let Some(GameRuntimeCampaignBlockState::LandingPad(state)) =
                self.campaign_runtime_states.get_mut(&tile_pos)
            {
                if state.arriving.is_none() {
                    landing_pad_update_cooldown(
                        state,
                        campaign.cooldown_time.max(0.000001),
                        scaled_delta,
                    );
                }
            }

            let (config, cooldown, arriving) = match self.campaign_runtime_states.get(&tile_pos) {
                Some(GameRuntimeCampaignBlockState::LandingPad(state)) => {
                    (state.config, state.cooldown, state.arriving)
                }
                _ => {
                    report.missing_runtime_states += 1;
                    continue;
                }
            };
            let Some(config) = config else {
                report.updated_pads += 1;
                continue;
            };

            let total_items = self.buildings[index]
                .items
                .as_ref()
                .map_or(0, |items| items.total());
            let (import_rate_positive, import_cooldown) =
                self.landing_pad_import_status(content, config);
            let ready_state = LandingPadState {
                config: Some(config),
                cooldown,
                arriving,
                ..LandingPadState::default()
            };
            if landing_pad_ready_to_queue(
                &ready_state,
                self.buildings[index].efficiency,
                total_items,
                is_fake,
                is_campaign_non_legacy,
                import_rate_positive,
                import_cooldown,
            ) {
                if is_fake {
                    if self.start_landing_pad_landing(content, tile_pos) {
                        report.landed_tiles.push(tile_pos);
                    }
                } else {
                    let pads = self.landing_pad_waiting.entry(config).or_default();
                    if !pads.contains(&tile_pos) {
                        pads.push(tile_pos);
                        report.queued_pads += 1;
                    }
                }
            }
            report.updated_pads += 1;
        }

        report
    }

    /// Consumes pending world-load lifecycle markers and resets tile-position keyed
    /// sidecars once. This mirrors the Java requirement that a fresh world load
    /// cannot reuse stale `Building` runtime state from a previous map.
    pub fn consume_world_load_events_and_reset_sidecars(&mut self) -> bool {
        let should_reset = !self.state.world.load_events().is_empty();
        if should_reset {
            self.reset_effect_block_sidecars();
            self.buildings.clear();
            self.state.world.clear_load_events();
        }
        should_reset
    }

    pub fn advance_owned_payload_constructors(
        &mut self,
        content: &ContentLoader,
        delta_seconds: f32,
    ) -> Option<GameRuntimePayloadConstructorFrameReport> {
        self.advance_owned_payload_constructors_with_recipe_build_time(
            content,
            delta_seconds,
            |block| Some(block.effective_build_time(content.items())),
        )
    }

    pub fn advance_owned_payload_constructors_with_recipe_build_time(
        &mut self,
        content: &ContentLoader,
        delta_seconds: f32,
        recipe_build_time: impl FnMut(&BlockDef) -> Option<f32>,
    ) -> Option<GameRuntimePayloadConstructorFrameReport> {
        self.consume_world_load_events_and_reset_sidecars();

        let advanced = self.state.advance_game_update_frame(delta_seconds);
        if !advanced.advanced {
            return None;
        }

        self.refresh_owned_building_update_permissions(content);
        self.refresh_owned_storage_core_links(content);

        let frame_delta = advanced.delta_ticks as f32;
        for building in self.buildings.iter_mut() {
            let can_overdrive = content
                .block(building.block.id)
                .map(BlockDef::can_overdrive)
                .unwrap_or(false);
            building.advance_update_timing(frame_delta, can_overdrive);
        }

        Some(self.advance_owned_payload_constructors_ticks(content, frame_delta, recipe_build_time))
    }

    fn advance_owned_payload_constructors_ticks(
        &mut self,
        content: &ContentLoader,
        frame_delta: f32,
        mut recipe_build_time: impl FnMut(&BlockDef) -> Option<f32>,
    ) -> GameRuntimePayloadConstructorFrameReport {
        let mut report = GameRuntimePayloadConstructorFrameReport::default();
        let mut pending_payload_moves = Vec::new();

        for index in 0..self.buildings.len() {
            let (tile_pos, block_id, team, enabled, efficiency, rotation, rotdeg, time_scale) = {
                let building = &self.buildings[index];
                report.visited_buildings += 1;
                (
                    building.tile_pos,
                    building.block.id,
                    building.team,
                    building.enabled,
                    building.efficiency,
                    building.rotation,
                    building.rotdeg(),
                    building.time_scale,
                )
            };

            if !enabled {
                continue;
            }

            let Some(BlockDef::PayloadConstructor(constructor)) = content.block(block_id) else {
                continue;
            };
            report.constructor_candidates += 1;

            let trns = constructor.base.size / 2 + 1;
            let (dx, dy) = autotiler_direction(rotation);
            let target_tile_pos = self
                .state
                .world
                .build(
                    point2_x(tile_pos) as i32 + dx * trns,
                    point2_y(tile_pos) as i32 + dy * trns,
                )
                .map(|target| target.tile_pos);

            let Some(GameRuntimePayloadBlockState::Constructor { recipe, .. }) =
                self.payload_runtime_states.get(&tile_pos)
            else {
                report.missing_runtime_states += 1;
                continue;
            };
            let recipe = *recipe;

            let recipe_def = recipe.and_then(|recipe_id| content.block(recipe_id));
            let recipe_build_time = recipe_def.and_then(|block| {
                recipe_build_time(block)
                    .filter(|build_time| build_time.is_finite() && *build_time > 0.0)
            });
            let recipe_requirements = recipe_def
                .map(|block| {
                    scaled_block_requirements(block, self.state.rules.build_cost_multiplier)
                })
                .unwrap_or_default();
            let has_recipe_items = building_has_items(&self.buildings[index], &recipe_requirements);

            if recipe.is_some() && recipe_build_time.is_none() {
                report.missing_recipe_build_times += 1;
            }

            let Some(GameRuntimePayloadBlockState::Constructor {
                common, producer, ..
            }) = self.payload_runtime_states.get_mut(&tile_pos)
            else {
                report.missing_runtime_states += 1;
                continue;
            };

            producer.has_payload = common.payload.is_some();
            let before_had_payload = producer.has_payload;
            let effective_efficiency = if has_recipe_items { efficiency } else { 0.0 };
            let step = block_producer_update(
                producer,
                recipe_build_time,
                effective_efficiency,
                constructor.build_speed,
                frame_delta * time_scale * effective_efficiency,
                frame_delta * time_scale,
            );
            report.updated_constructors += 1;

            if step.produced && !before_had_payload {
                if let Some(recipe_def) = recipe_def {
                    consume_building_items(&mut self.buildings[index], &recipe_requirements);
                    let payload_building = BuildingComp::new(
                        crate::mindustry::world::point2_pack(0, 0),
                        recipe_def.base().clone(),
                        team,
                    );
                    let mut build_bytes = Vec::new();
                    if payload_building.write_base(&mut build_bytes, false).is_ok() {
                        common.payload = Some(PayloadRef::Block {
                            block: recipe_def.base().id,
                            version: 0,
                            build_bytes,
                        });
                        common.pay_vector = PayloadVec2 { x: 0.0, y: 0.0 };
                        common.pay_rotation = 0.0;
                        producer.has_payload = true;
                        report.produced_payloads += 1;
                    }
                }
            }

            if common.payload.is_some() {
                report.moved_out_payloads += 1;
                let arrived = payload_block_move_out_step(
                    common,
                    rotdeg,
                    constructor.base.size,
                    TILE_SIZE as f32,
                    constructor.payload_speed,
                    constructor.payload_rotate_speed,
                    frame_delta * time_scale,
                );
                if arrived {
                    report.arrived_output_payloads += 1;
                    if let Some(target_tile_pos) = target_tile_pos {
                        pending_payload_moves.push((tile_pos, target_tile_pos));
                    }
                }
            }
        }

        for (source_tile_pos, target_tile_pos) in pending_payload_moves {
            if self.transfer_payload_output_to_front(content, source_tile_pos, target_tile_pos) {
                report.transferred_payloads += 1;
            }
        }

        report
    }

    pub fn advance_owned_payload_sources(
        &mut self,
        content: &ContentLoader,
        delta_seconds: f32,
    ) -> Option<GameRuntimePayloadSourceFrameReport> {
        self.consume_world_load_events_and_reset_sidecars();

        let advanced = self.state.advance_game_update_frame(delta_seconds);
        if !advanced.advanced {
            return None;
        }

        self.refresh_owned_building_update_permissions(content);

        let frame_delta = advanced.delta_ticks as f32;
        for building in self.buildings.iter_mut() {
            let can_overdrive = content
                .block(building.block.id)
                .map(BlockDef::can_overdrive)
                .unwrap_or(false);
            building.advance_update_timing(frame_delta, can_overdrive);
        }

        Some(self.advance_owned_payload_sources_ticks(content, frame_delta))
    }

    fn advance_owned_payload_sources_ticks(
        &mut self,
        content: &ContentLoader,
        frame_delta: f32,
    ) -> GameRuntimePayloadSourceFrameReport {
        let mut report = GameRuntimePayloadSourceFrameReport::default();
        let mut pending_payload_moves = Vec::new();
        let mut created_unit_events = Vec::new();

        for index in 0..self.buildings.len() {
            let (tile_pos, block_id, team, enabled, rotdeg, rotation, time_scale, x, y) = {
                let building = &self.buildings[index];
                report.visited_buildings += 1;
                (
                    building.tile_pos,
                    building.block.id,
                    building.team,
                    building.enabled,
                    building.rotdeg(),
                    building.rotation,
                    building.time_scale,
                    building.x,
                    building.y,
                )
            };

            if !enabled {
                continue;
            }

            let Some(BlockDef::Sandbox(sandbox)) = content.block(block_id) else {
                continue;
            };
            if sandbox.kind != SandboxBlockKind::PayloadSource {
                continue;
            }
            report.source_candidates += 1;

            let trns = sandbox.base.size / 2 + 1;
            let (dx, dy) = autotiler_direction(rotation);
            let target_tile_pos = self
                .state
                .world
                .build(
                    point2_x(tile_pos) as i32 + dx * trns,
                    point2_y(tile_pos) as i32 + dy * trns,
                )
                .map(|target| target.tile_pos);

            let Some(GameRuntimePayloadBlockState::Source { common, source }) =
                self.payload_runtime_states.get_mut(&tile_pos)
            else {
                report.missing_runtime_states += 1;
                continue;
            };

            source.has_payload = common.payload.is_some();
            let spawn = payload_source_update(source);
            report.updated_sources += 1;

            match spawn {
                PayloadSourceSpawn::None => {}
                PayloadSourceSpawn::Unit(unit_id) => {
                    let Some(unit) = content.unit(unit_id) else {
                        source.has_payload = common.payload.is_some();
                        report.unknown_config_units += 1;
                        continue;
                    };
                    match Self::create_common_unit_payload_ref(
                        content,
                        unit,
                        unit_id,
                        team,
                        x,
                        y,
                        rotdeg,
                        source.command_pos,
                    ) {
                        Ok(payload) => {
                            common.payload = Some(payload);
                            common.pay_vector = PayloadVec2::ZERO;
                            common.pay_rotation = rotdeg;
                            source.has_payload = true;
                            report.spawned_unit_payloads += 1;
                            created_unit_events.push((unit.name().to_string(), team, tile_pos));
                        }
                        Err(_) => {
                            source.has_payload = common.payload.is_some();
                            report.skipped_unit_payloads += 1;
                        }
                    }
                }
                PayloadSourceSpawn::Block(block_id) => {
                    let Some(block_def) = content.block(block_id) else {
                        source.has_payload = common.payload.is_some();
                        report.unknown_config_blocks += 1;
                        continue;
                    };

                    let payload_building = BuildingComp::new(
                        crate::mindustry::world::point2_pack(0, 0),
                        block_def.base().clone(),
                        team,
                    );
                    let mut build_bytes = Vec::new();
                    if payload_building.write_base(&mut build_bytes, false).is_ok() {
                        common.payload = Some(PayloadRef::Block {
                            block: block_def.base().id,
                            version: 0,
                            build_bytes,
                        });
                        common.pay_vector = PayloadVec2::ZERO;
                        common.pay_rotation = rotdeg;
                        source.has_payload = true;
                        report.spawned_block_payloads += 1;
                    } else {
                        source.has_payload = common.payload.is_some();
                    }
                }
            }

            if common.payload.is_some() {
                report.moved_out_payloads += 1;
                let arrived = payload_block_move_out_step(
                    common,
                    rotdeg,
                    sandbox.base.size,
                    TILE_SIZE as f32,
                    sandbox.payload_speed,
                    sandbox.payload_rotate_speed,
                    frame_delta * time_scale,
                );
                if arrived {
                    report.arrived_output_payloads += 1;
                    if let Some(target_tile_pos) = target_tile_pos {
                        pending_payload_moves.push((tile_pos, target_tile_pos));
                    }
                }
            }
        }

        for (unit_name, team, tile_pos) in created_unit_events {
            self.note_unit_create_event(None, unit_name, team, Some(tile_pos), None);
        }

        for (source_tile_pos, target_tile_pos) in pending_payload_moves {
            if self.transfer_payload_output_to_front(content, source_tile_pos, target_tile_pos) {
                report.transferred_payloads += 1;
            }
        }

        report
    }

    pub fn advance_owned_payload_deconstructors(
        &mut self,
        content: &ContentLoader,
        delta_seconds: f32,
    ) -> Option<GameRuntimePayloadDeconstructorFrameReport> {
        self.consume_world_load_events_and_reset_sidecars();

        let advanced = self.state.advance_game_update_frame(delta_seconds);
        if !advanced.advanced {
            return None;
        }

        self.refresh_owned_building_update_permissions(content);

        let frame_delta = advanced.delta_ticks as f32;
        for building in self.buildings.iter_mut() {
            let can_overdrive = content
                .block(building.block.id)
                .map(BlockDef::can_overdrive)
                .unwrap_or(false);
            building.advance_update_timing(frame_delta, can_overdrive);
        }

        Some(self.advance_owned_payload_deconstructors_ticks(content, frame_delta))
    }

    fn advance_owned_payload_deconstructors_ticks(
        &mut self,
        content: &ContentLoader,
        frame_delta: f32,
    ) -> GameRuntimePayloadDeconstructorFrameReport {
        let mut report = GameRuntimePayloadDeconstructorFrameReport::default();

        for index in 0..self.buildings.len() {
            let (tile_pos, block_id, enabled, efficiency, rotdeg, time_scale) = {
                let building = &self.buildings[index];
                report.visited_buildings += 1;
                (
                    building.tile_pos,
                    building.block.id,
                    building.enabled,
                    building.efficiency,
                    building.rotdeg(),
                    building.time_scale,
                )
            };

            if !enabled {
                continue;
            }

            let Some(BlockDef::PayloadDeconstructor(deconstructor_def)) = content.block(block_id)
            else {
                continue;
            };
            report.deconstructor_candidates += 1;

            let Some(GameRuntimePayloadBlockState::Deconstructor {
                common,
                deconstructor,
            }) = self.payload_runtime_states.get_mut(&tile_pos)
            else {
                report.missing_runtime_states += 1;
                continue;
            };

            deconstructor.has_payload = common.payload.is_some();
            deconstructor.has_deconstructing = deconstructor.deconstructing.is_some();
            if deconstructor.deconstructing.is_none() {
                deconstructor.progress = 0.0;
            }
            common.pay_rotation = Self::payload_deconstructor_pay_rotation_step(
                common.pay_rotation,
                deconstructor_def.payload_rotate_speed * frame_delta * time_scale,
            );

            if let Some(payload) = deconstructor.deconstructing.as_ref() {
                let Some(plan) = Self::payload_ref_deconstruction_plan(content, payload) else {
                    report.invalid_payloads += 1;
                    report.updated_deconstructors += 1;
                    continue;
                };
                if plan.payload_size > deconstructor_def.max_payload_size {
                    report.invalid_payloads += 1;
                    report.updated_deconstructors += 1;
                    continue;
                }

                if deconstructor
                    .accum
                    .as_ref()
                    .map(|accum| accum.len() != plan.amounts.len())
                    .unwrap_or(true)
                {
                    deconstructor.accum = Some(vec![0.0; plan.amounts.len()]);
                }

                let item_capacity = self.buildings[index].block.item_capacity;
                let Some(items) = self.buildings[index].items.as_mut() else {
                    report.invalid_payloads += 1;
                    report.updated_deconstructors += 1;
                    continue;
                };
                let mut items_total = items.total();
                let mut draw_time = 0.0;
                let before_progress = deconstructor.progress;
                let step = payload_deconstructor_update_progress(
                    &mut deconstructor.progress,
                    &mut draw_time,
                    deconstructor
                        .accum
                        .as_mut()
                        .expect("deconstructor accum should be initialized"),
                    &plan.amounts,
                    &mut items_total,
                    item_capacity,
                    frame_delta * time_scale * efficiency,
                    deconstructor_def.deconstruct_speed,
                    plan.build_time,
                    self.state.rules.build_cost_multiplier,
                );

                for (item_id, amount) in plan.item_ids.iter().zip(step.items_added.iter()) {
                    if *amount > 0 {
                        items.add(*item_id, *amount);
                        report.produced_items += *amount as usize;
                    }
                }

                if step.can_progress && (deconstructor.progress - before_progress).abs() > 0.0001 {
                    report.progressed_deconstructions += 1;
                }
                if step.finished {
                    deconstructor.deconstructing = None;
                    deconstructor.accum = None;
                    deconstructor.has_deconstructing = false;
                    report.finished_deconstructions += 1;
                }
            } else if common.payload.is_some() {
                let arrived = payload_block_move_in(
                    common,
                    false,
                    deconstructor_def.rotate,
                    rotdeg,
                    deconstructor_def.payload_speed,
                    deconstructor_def.payload_rotate_speed,
                    frame_delta * time_scale,
                );

                if arrived {
                    let Some(payload) = common.payload.as_ref() else {
                        report.updated_deconstructors += 1;
                        continue;
                    };
                    let Some(plan) = Self::payload_ref_deconstruction_plan(content, payload) else {
                        report.invalid_payloads += 1;
                        report.updated_deconstructors += 1;
                        continue;
                    };
                    if plan.payload_size <= deconstructor_def.max_payload_size {
                        deconstructor.accum = Some(vec![0.0; plan.amounts.len()]);
                        deconstructor.deconstructing = common.payload.take();
                        deconstructor.progress = 0.0;
                        deconstructor.has_payload = false;
                        deconstructor.has_deconstructing = true;
                        report.moved_in_payloads += 1;
                        report.started_deconstructions += 1;
                    } else {
                        report.invalid_payloads += 1;
                    }
                }
            }

            deconstructor.has_payload = common.payload.is_some();
            deconstructor.has_deconstructing = deconstructor.deconstructing.is_some();
            report.updated_deconstructors += 1;
        }

        report
    }

    pub fn advance_owned_payload_mass_drivers(
        &mut self,
        content: &ContentLoader,
        delta_seconds: f32,
    ) -> Option<GameRuntimePayloadMassDriverFrameReport> {
        self.consume_world_load_events_and_reset_sidecars();

        let advanced = self.state.advance_game_update_frame(delta_seconds);
        if !advanced.advanced {
            return None;
        }

        self.refresh_owned_building_update_permissions(content);

        let frame_delta = advanced.delta_ticks as f32;
        for building in self.buildings.iter_mut() {
            let can_overdrive = content
                .block(building.block.id)
                .map(BlockDef::can_overdrive)
                .unwrap_or(false);
            building.advance_update_timing(frame_delta, can_overdrive);
        }

        Some(self.advance_owned_payload_mass_drivers_ticks(content, frame_delta))
    }

    fn advance_owned_payload_mass_drivers_ticks(
        &mut self,
        content: &ContentLoader,
        frame_delta: f32,
    ) -> GameRuntimePayloadMassDriverFrameReport {
        let mut report = GameRuntimePayloadMassDriverFrameReport::default();
        let mut mass_driver_indices = Vec::new();

        for index in 0..self.buildings.len() {
            let (tile_pos, block_id, enabled, efficiency, time_scale) = {
                let building = &self.buildings[index];
                report.visited_buildings += 1;
                (
                    building.tile_pos,
                    building.block.id,
                    building.enabled,
                    building.efficiency,
                    building.time_scale,
                )
            };

            if !enabled {
                continue;
            }

            let Some(BlockDef::PayloadMassDriver(driver_def)) = content.block(block_id) else {
                continue;
            };
            report.mass_driver_candidates += 1;
            mass_driver_indices.push(index);

            let Some(GameRuntimePayloadBlockState::MassDriver { common, driver }) =
                self.payload_runtime_states.get(&tile_pos)
            else {
                report.missing_runtime_states += 1;
                continue;
            };

            let link_index = self.payload_mass_driver_link_index(index, driver.link, driver_def);
            let link_tile_pos = link_index.map(|link_index| self.buildings[link_index].tile_pos);
            if driver.link != -1 && link_index.is_none() {
                report.invalid_links += 1;
            }

            let has_payload = common.payload.is_some();
            let mut waiting_shooters = Vec::new();
            for shooter in driver.waiting_shooters.iter().copied() {
                if self.payload_mass_driver_waiting_shooter_valid(content, tile_pos, shooter)
                    && !waiting_shooters.contains(&shooter)
                {
                    waiting_shooters.push(shooter);
                }
            }
            let current_shooter_index = waiting_shooters.first().and_then(|tile_pos| {
                self.buildings
                    .iter()
                    .position(|building| building.tile_pos == *tile_pos)
            });
            let current_shooter_angle = current_shooter_index.map(|shooter_index| {
                self.payload_mass_driver_angle_between_buildings(index, shooter_index)
            });
            let had_receive_delay = driver.effect_delay_timer > 0.0;

            let Some(GameRuntimePayloadBlockState::MassDriver { common, driver }) =
                self.payload_runtime_states.get_mut(&tile_pos)
            else {
                report.missing_runtime_states += 1;
                continue;
            };

            driver.waiting_shooters = waiting_shooters;
            payload_mass_driver_discharge(
                &mut driver.charge,
                driver.charging,
                frame_delta * time_scale,
            );
            driver.effect_delay_timer -= frame_delta * time_scale;
            if had_receive_delay && driver.effect_delay_timer <= 0.0 && driver.last_other.is_some()
            {
                driver.reload_counter = 1.0;
                driver.last_other = None;
                driver.rec_payload = None;
                report.receive_effects_completed += 1;
            }
            driver.charging = false;

            if let Some(link_tile_pos) = link_tile_pos {
                driver.link = link_tile_pos;
            }

            payload_mass_driver_reload_tick(
                &mut driver.reload_counter,
                frame_delta * time_scale * efficiency,
                driver_def.reload,
            );

            if driver.state == PayloadDriverState::Idle {
                driver.state = payload_mass_driver_idle_next(
                    driver.waiting_shooters.is_empty(),
                    has_payload,
                    link_index.is_some(),
                );
            }

            match driver.state {
                PayloadDriverState::Accepting => {
                    if payload_mass_driver_accepting_should_idle(
                        current_shooter_index.is_some(),
                        has_payload,
                    ) {
                        driver.state = PayloadDriverState::Idle;
                    } else if let Some(angle) = current_shooter_angle {
                        payload_mass_driver_move_turret_toward(
                            &mut driver.turret_rotation,
                            angle,
                            driver_def.rotate_speed,
                            frame_delta,
                            efficiency,
                        );
                    }
                }
                PayloadDriverState::Shooting => {
                    if payload_mass_driver_shooting_should_idle(
                        link_index.is_some(),
                        driver.waiting_shooters.is_empty(),
                        has_payload,
                    ) {
                        driver.state = PayloadDriverState::Idle;
                    }
                }
                PayloadDriverState::Idle => {}
            }

            common.pay_rotation = common.pay_rotation.rem_euclid(360.0);
            report.updated_mass_drivers += 1;
        }

        for index in mass_driver_indices {
            let tile_pos = self.buildings[index].tile_pos;
            let Some(BlockDef::PayloadMassDriver(driver_def)) =
                content.block(self.buildings[index].block.id)
            else {
                continue;
            };

            let Some(GameRuntimePayloadBlockState::MassDriver { common, driver }) =
                self.payload_runtime_states.get(&tile_pos).cloned()
            else {
                continue;
            };

            if driver.state != PayloadDriverState::Shooting {
                continue;
            }

            let Some(link_index) =
                self.payload_mass_driver_link_index(index, driver.link, driver_def)
            else {
                continue;
            };
            let target_tile_pos = self.buildings[link_index].tile_pos;
            let target_rotation =
                self.payload_mass_driver_angle_between_buildings(index, link_index);
            let target_snapshot = match self.payload_runtime_states.get(&target_tile_pos) {
                Some(GameRuntimePayloadBlockState::MassDriver { common, driver }) => {
                    (common.clone(), driver.clone())
                }
                _ => continue,
            };

            if payload_mass_driver_shooting_should_idle(
                true,
                driver.waiting_shooters.is_empty(),
                common.payload.is_some(),
            ) {
                if let Some(GameRuntimePayloadBlockState::MassDriver { driver, .. }) =
                    self.payload_runtime_states.get_mut(&tile_pos)
                {
                    driver.state = PayloadDriverState::Idle;
                }
                continue;
            }

            let mut moved_out = false;
            let mut staged_now = false;
            if let Some(GameRuntimePayloadBlockState::MassDriver { common, driver }) =
                self.payload_runtime_states.get_mut(&tile_pos)
            {
                common.pay_rotation = {
                    let mut value = common.pay_rotation;
                    payload_mass_driver_move_turret_toward(
                        &mut value,
                        driver.turret_rotation,
                        driver_def.payload_rotate_speed,
                        frame_delta,
                        1.0,
                    );
                    value
                };

                if driver.loaded {
                    let load_length = payload_mass_driver_loaded_pay_length(
                        driver_def.length,
                        driver.reload_counter,
                        driver_def.knockback,
                    );
                    driver.pay_length +=
                        driver_def.payload_speed * frame_delta * self.buildings[index].time_scale;
                    if driver.pay_length >= load_length {
                        driver.pay_length = load_length;
                        moved_out = true;
                    }
                    let radians = driver.turret_rotation.to_radians();
                    common.pay_vector = PayloadVec2 {
                        x: radians.cos() * driver.pay_length,
                        y: radians.sin() * driver.pay_length,
                    };
                } else if common.payload.is_some()
                    && payload_block_move_in(
                        common,
                        true,
                        driver_def.rotate,
                        self.buildings[index].rotdeg(),
                        driver_def.payload_speed,
                        driver_def.payload_rotate_speed,
                        frame_delta * self.buildings[index].time_scale,
                    )
                {
                    driver.pay_length = 0.0;
                    driver.loaded = true;
                    staged_now = true;
                    report.moved_in_payloads += 1;
                }
            }
            if staged_now {
                report.staged_payloads += 1;
            }

            let source_payload = match self.payload_runtime_states.get(&tile_pos) {
                Some(GameRuntimePayloadBlockState::MassDriver { common, .. }) => {
                    common.payload.as_ref()
                }
                _ => None,
            };
            let Some(source_payload) = source_payload else {
                continue;
            };

            if !moved_out
                || target_snapshot.0.payload.is_some()
                || !Self::payload_mass_driver_payload_fits(content, driver_def, source_payload)
            {
                continue;
            }

            if let Some(GameRuntimePayloadBlockState::MassDriver {
                common: target_common,
                driver: target_driver,
            }) = self.payload_runtime_states.get_mut(&target_tile_pos)
            {
                if target_common.payload.is_none()
                    && !target_driver.waiting_shooters.contains(&tile_pos)
                {
                    target_driver.waiting_shooters.push(tile_pos);
                    report.queued_shooters += 1;
                }
            }

            let target_snapshot = match self.payload_runtime_states.get(&target_tile_pos) {
                Some(GameRuntimePayloadBlockState::MassDriver { common, driver }) => {
                    (common.clone(), driver.clone())
                }
                _ => continue,
            };

            if let Some(GameRuntimePayloadBlockState::MassDriver { driver, .. }) =
                self.payload_runtime_states.get_mut(&tile_pos)
            {
                if driver.reload_counter <= 0.0 {
                    payload_mass_driver_move_turret_toward(
                        &mut driver.turret_rotation,
                        target_rotation,
                        driver_def.rotate_speed,
                        frame_delta,
                        self.buildings[index].efficiency,
                    );
                }
            }

            let source_snapshot = match self.payload_runtime_states.get(&tile_pos) {
                Some(GameRuntimePayloadBlockState::MassDriver { common, driver }) => {
                    (common.clone(), driver.clone())
                }
                _ => continue,
            };

            let ready = payload_mass_driver_ready_to_fire(
                moved_out,
                source_snapshot.0.payload.is_some(),
                target_snapshot.0.payload.is_none(),
                source_snapshot.1.reload_counter,
                target_snapshot
                    .1
                    .waiting_shooters
                    .first()
                    .map(|shooter| *shooter == tile_pos)
                    .unwrap_or(false),
                target_snapshot.1.state,
                target_snapshot.1.reload_counter,
                source_snapshot.1.turret_rotation,
                target_rotation,
                target_snapshot.1.turret_rotation,
            );

            let mut should_fire = false;
            if let Some(GameRuntimePayloadBlockState::MassDriver { driver, .. }) =
                self.payload_runtime_states.get_mut(&tile_pos)
            {
                should_fire = payload_mass_driver_charge_until_fire(
                    &mut driver.charge,
                    frame_delta
                        * self.buildings[index].time_scale
                        * self.buildings[index].efficiency,
                    driver_def.charge_time,
                    ready,
                );
                driver.charging = ready;
                if ready {
                    report.charged_shots += 1;
                }
            }

            if !should_fire {
                continue;
            }

            let Some(payload) = self
                .payload_runtime_states
                .get_mut(&tile_pos)
                .and_then(|state| match state {
                    GameRuntimePayloadBlockState::MassDriver { common, driver } => {
                        let payload = common.payload.take()?;
                        payload_mass_driver_reset_after_fire(driver);
                        common.pay_vector = PayloadVec2::ZERO;
                        Some(payload)
                    }
                    _ => None,
                })
            else {
                continue;
            };

            if let Some(GameRuntimePayloadBlockState::MassDriver {
                common: target_common,
                driver: target_driver,
            }) = self.payload_runtime_states.get_mut(&target_tile_pos)
            {
                if target_common.payload.is_none() {
                    let source_pos = PayloadVec2 {
                        x: self.buildings[index].x,
                        y: self.buildings[index].y,
                    };
                    let target_pos = PayloadVec2 {
                        x: self.buildings[link_index].x,
                        y: self.buildings[link_index].y,
                    };
                    payload_block_handle_payload(
                        target_common,
                        payload.clone(),
                        target_pos,
                        source_pos,
                        source_snapshot.0.pay_rotation,
                        self.buildings[link_index].block.size,
                        TILE_SIZE as f32,
                    );
                    target_driver.rec_payload = Some(payload);
                    target_driver.effect_delay_timer = driver_def.transfer_effect_lifetime;
                    target_driver.last_other = Some(tile_pos);
                    target_driver.loaded = false;
                    target_driver.pay_length = 0.0;
                    target_driver
                        .waiting_shooters
                        .retain(|shooter| *shooter != tile_pos);
                    report.fired_payloads += 1;
                    report.received_payloads += 1;
                }
            }
        }

        report
    }

    pub fn advance_owned_payload_loaders(
        &mut self,
        content: &ContentLoader,
        delta_seconds: f32,
    ) -> Option<GameRuntimePayloadLoaderFrameReport> {
        self.consume_world_load_events_and_reset_sidecars();

        let advanced = self.state.advance_game_update_frame(delta_seconds);
        if !advanced.advanced {
            return None;
        }

        self.refresh_owned_building_update_permissions(content);

        let frame_delta = advanced.delta_ticks as f32;
        for building in self.buildings.iter_mut() {
            let can_overdrive = content
                .block(building.block.id)
                .map(BlockDef::can_overdrive)
                .unwrap_or(false);
            building.advance_update_timing(frame_delta, can_overdrive);
        }

        Some(self.advance_owned_payload_loaders_ticks(content, frame_delta, true))
    }

    fn advance_owned_payload_loaders_ticks(
        &mut self,
        content: &ContentLoader,
        frame_delta: f32,
        run_item_transport: bool,
    ) -> GameRuntimePayloadLoaderFrameReport {
        let mut report = GameRuntimePayloadLoaderFrameReport::default();
        let mut pending_payload_moves = Vec::new();
        let mut pending_unloader_liquid_dumps = Vec::new();
        let mut pending_unloader_item_dumps = Vec::new();

        for index in 0..self.buildings.len() {
            let (tile_pos, block_id, enabled, efficiency, rotation, rotdeg, time_scale) = {
                let building = &self.buildings[index];
                report.visited_buildings += 1;
                (
                    building.tile_pos,
                    building.block.id,
                    building.enabled,
                    building.efficiency,
                    building.rotation,
                    building.rotdeg(),
                    building.time_scale,
                )
            };

            if !enabled {
                continue;
            }

            let Some(BlockDef::PayloadLoader(loader_def)) = content.block(block_id) else {
                continue;
            };
            report.loader_candidates += 1;

            let trns = loader_def.base.size / 2 + 1;
            let (dx, dy) = autotiler_direction(rotation);
            let target_tile_pos = self
                .state
                .world
                .build(
                    point2_x(tile_pos) as i32 + dx * trns,
                    point2_y(tile_pos) as i32 + dy * trns,
                )
                .map(|target| target.tile_pos);

            let Some(GameRuntimePayloadBlockState::Loader { common, loader }) =
                self.payload_runtime_states.get_mut(&tile_pos)
            else {
                report.missing_runtime_states += 1;
                continue;
            };

            Self::refresh_payload_loader_state_from_common(
                content,
                &self.buildings[index],
                common,
                loader,
            );

            match loader_def.kind {
                PayloadLoaderBlockKind::Loader => {
                    if payload_loader_should_export(loader) {
                        report.moved_out_payloads += 1;
                        let arrived = payload_block_move_out_step(
                            common,
                            rotdeg,
                            loader_def.base.size,
                            TILE_SIZE as f32,
                            loader_def.payload_speed,
                            loader_def.payload_rotate_speed,
                            frame_delta * time_scale,
                        );
                        if arrived {
                            report.arrived_output_payloads += 1;
                            if let Some(target_tile_pos) = target_tile_pos {
                                pending_payload_moves.push((tile_pos, target_tile_pos));
                            }
                        }
                    } else if payload_block_move_in(
                        common,
                        true,
                        loader_def.rotate,
                        rotdeg,
                        loader_def.payload_speed,
                        loader_def.payload_rotate_speed,
                        frame_delta * time_scale,
                    ) {
                        report.moved_in_payloads += 1;
                        Self::payload_loader_load_inner_building(
                            content,
                            loader_def,
                            &mut self.buildings[index],
                            common,
                            loader,
                            frame_delta * time_scale,
                            efficiency,
                            &mut report,
                        );
                    }
                }
                PayloadLoaderBlockKind::Unloader => {
                    loader.last_output_power = 0.0;
                    pending_unloader_item_dumps.push((
                        tile_pos,
                        loader_def.offload_speed,
                        frame_delta * time_scale,
                    ));
                    pending_unloader_liquid_dumps.push(tile_pos);
                    if payload_unloader_should_export(loader) {
                        if Self::payload_ref_block_instant_deconstruct(
                            content,
                            common.payload.as_ref(),
                        ) {
                            common.payload = None;
                            loader.has_payload = false;
                            loader.exporting = false;
                            report.destroyed_instant_payloads += 1;
                        } else {
                            report.moved_out_payloads += 1;
                            let arrived = payload_block_move_out_step(
                                common,
                                rotdeg,
                                loader_def.base.size,
                                TILE_SIZE as f32,
                                loader_def.payload_speed,
                                loader_def.payload_rotate_speed,
                                frame_delta * time_scale,
                            );
                            if arrived {
                                report.arrived_output_payloads += 1;
                                if let Some(target_tile_pos) = target_tile_pos {
                                    pending_payload_moves.push((tile_pos, target_tile_pos));
                                }
                            }
                        }
                    } else if payload_block_move_in(
                        common,
                        true,
                        loader_def.rotate,
                        rotdeg,
                        loader_def.payload_speed,
                        loader_def.payload_rotate_speed,
                        frame_delta * time_scale,
                    ) {
                        report.moved_in_payloads += 1;
                        Self::payload_unloader_unload_inner_building(
                            content,
                            loader_def,
                            &mut self.buildings[index],
                            common,
                            loader,
                            frame_delta * time_scale,
                            efficiency,
                            &mut report,
                        );
                    }
                }
            }

            report.updated_loaders += 1;
        }

        for tile_pos in pending_unloader_liquid_dumps {
            report.dumped_liquid_events +=
                self.dump_current_liquid_from_unloader(content, tile_pos);
        }

        for (tile_pos, offload_speed, delta) in pending_unloader_item_dumps {
            report.dumped_items +=
                self.dump_accumulated_items_from_unloader(content, tile_pos, offload_speed, delta);
        }
        if run_item_transport {
            let item_transport_report =
                self.advance_owned_item_transport_blocks_ticks(content, frame_delta);
            report.router_forwarded_items += item_transport_report.router_forwarded_items;
            report.item_unloader_moved_items += item_transport_report.item_unloader_moved_items;
            report.directional_unloader_moved_items +=
                item_transport_report.directional_unloader_moved_items;
            report.duct_forwarded_items += item_transport_report.duct_forwarded_items;
            report.duct_bridge_forwarded_items += item_transport_report.duct_bridge_forwarded_items;
            report.stack_router_forwarded_items +=
                item_transport_report.stack_router_forwarded_items;
            report.stack_conveyor_forwarded_items +=
                item_transport_report.stack_conveyor_forwarded_items;
            report.mass_driver_forwarded_items += item_transport_report.mass_driver_forwarded_items;
            report.bridge_forwarded_items += item_transport_report.bridge_forwarded_items;
            report.junction_forwarded_items += item_transport_report.junction_forwarded_items;
        }

        for (source_tile_pos, target_tile_pos) in pending_payload_moves {
            if self.transfer_payload_output_to_front(content, source_tile_pos, target_tile_pos) {
                report.transferred_payloads += 1;
            }
        }

        report
    }

    fn dump_accumulated_items_from_unloader(
        &mut self,
        content: &ContentLoader,
        tile_pos: i32,
        offload_speed: i32,
        delta: f32,
    ) -> usize {
        let Some(source_index) = self
            .buildings
            .iter()
            .position(|building| building.tile_pos == tile_pos)
        else {
            return 0;
        };
        let repetitions = offload_speed.max(0) as usize;
        if repetitions == 0 {
            return 0;
        }

        self.dump_accumulated_items_from_building(content, source_index, repetitions, delta)
    }

    fn dump_accumulated_items_from_unit_cargo_unload_point(
        &mut self,
        content: &ContentLoader,
        source_index: usize,
        delta: f32,
    ) -> usize {
        self.dump_accumulated_items_from_building(content, source_index, 1, delta)
    }

    fn dump_accumulated_items_from_building(
        &mut self,
        content: &ContentLoader,
        source_index: usize,
        repetitions: usize,
        delta: f32,
    ) -> usize {
        if source_index >= self.buildings.len() || repetitions == 0 {
            return 0;
        }

        let mut dumped = 0;
        for _ in 0..repetitions {
            let attempts = {
                let Some(source) = self.buildings.get_mut(source_index) else {
                    break;
                };
                source.dump_accum += delta.max(0.0);
                let mut attempts = 0usize;
                while source.dump_accum >= 1.0 {
                    source.dump_accum -= 1.0;
                    attempts += 1;
                }
                attempts
            };

            for _ in 0..attempts {
                if self.dump_one_item_from_building(content, source_index) {
                    dumped += 1;
                }
            }
        }
        dumped
    }

    fn dump_current_liquid_from_unloader(
        &mut self,
        content: &ContentLoader,
        tile_pos: i32,
    ) -> usize {
        let Some(source_index) = self
            .buildings
            .iter()
            .position(|building| building.tile_pos == tile_pos)
        else {
            return 0;
        };
        if source_index >= self.buildings.len() {
            return 0;
        }

        let (liquid_id, proximity, start_dump) = {
            let source = &self.buildings[source_index];
            let Some(liquids) = source.liquids.as_ref() else {
                return 0;
            };
            let Some(liquid_id) = liquids.current() else {
                return 0;
            };
            if liquids.get(liquid_id) <= 0.0001 || source.proximity.is_empty() {
                return 0;
            }
            (liquid_id, source.proximity.clone(), source.cdump)
        };
        let prox_len = proximity.len();
        let mut dumped = 0;
        for attempt in 0..prox_len {
            let target_ref = proximity[(start_dump + attempt) % prox_len];
            let target_index = self
                .buildings
                .iter()
                .position(|building| building.tile_pos == target_ref.tile_pos);
            if let Some(target_index) = target_index {
                if self.dump_liquid_to_target(content, source_index, target_index, liquid_id) {
                    dumped += 1;
                }
            }
            self.increment_building_dump(source_index, prox_len);
        }
        dumped
    }

    fn dump_one_item_from_building(
        &mut self,
        content: &ContentLoader,
        source_index: usize,
    ) -> bool {
        if source_index >= self.buildings.len() {
            return false;
        }
        let (proximity, start_dump, item_ids) = {
            let source = &self.buildings[source_index];
            let Some(items) = source.items.as_ref() else {
                return false;
            };
            if !source.block.has_items || items.empty() || source.proximity.is_empty() {
                return false;
            }
            let mut item_ids: Vec<_> = content
                .items()
                .iter()
                .map(|item| item.base.mappable.base.id)
                .filter(|item_id| items.get(*item_id) > 0)
                .collect();
            if item_ids.is_empty() {
                item_ids.extend(items.each().map(|(item_id, _)| item_id));
            }
            (source.proximity.clone(), source.cdump, item_ids)
        };
        let prox_len = proximity.len();
        if prox_len == 0 || item_ids.is_empty() {
            return false;
        }

        for attempt in 0..prox_len {
            let target_ref = proximity[(start_dump + attempt) % prox_len];
            let target_index = self
                .buildings
                .iter()
                .position(|building| building.tile_pos == target_ref.tile_pos);
            if let Some(target_index) = target_index {
                for item_id in &item_ids {
                    if self.dump_item_to_target(content, source_index, target_index, *item_id) {
                        self.increment_building_dump(source_index, prox_len);
                        return true;
                    }
                }
            }
            self.increment_building_dump(source_index, prox_len);
        }

        false
    }

    fn increment_building_dump(&mut self, source_index: usize, prox_len: usize) {
        if prox_len != 0 {
            if let Some(source) = self.buildings.get_mut(source_index) {
                source.cdump = (source.cdump + 1) % prox_len;
            }
        }
    }

    fn dump_item_to_target(
        &mut self,
        content: &ContentLoader,
        source_index: usize,
        target_index: usize,
        item_id: ContentId,
    ) -> bool {
        if source_index == target_index
            || source_index >= self.buildings.len()
            || target_index >= self.buildings.len()
            || !self.dump_target_accepts_item(content, source_index, target_index, item_id)
        {
            return false;
        }

        let target_is_item_void = matches!(
            content.block(self.buildings[target_index].block.id),
            Some(BlockDef::Sandbox(sandbox)) if sandbox.kind == SandboxBlockKind::ItemVoid
        );
        let target_is_item_incinerator = matches!(
            content.block(self.buildings[target_index].block.id),
            Some(BlockDef::Crafting(crafting))
                if crafting.kind == CraftingBlockKind::ItemIncinerator
        );
        let target_is_item_bridge = matches!(
            content.block(self.buildings[target_index].block.id),
            Some(BlockDef::Distribution(distribution))
                if matches!(
                    distribution.kind,
                    DistributionBlockKind::ItemBridge | DistributionBlockKind::BufferedItemBridge
                )
        );
        if target_is_item_bridge {
            return self.dump_item_to_item_bridge(content, source_index, target_index, item_id);
        }
        let target_is_junction = matches!(
            content.block(self.buildings[target_index].block.id),
            Some(BlockDef::Distribution(distribution))
                if distribution.kind == DistributionBlockKind::Junction
        );
        if target_is_junction {
            return self.dump_item_to_junction(content, source_index, target_index, item_id);
        }
        let target_is_duct_bridge = matches!(
            content.block(self.buildings[target_index].block.id),
            Some(BlockDef::Distribution(distribution))
                if distribution.kind == DistributionBlockKind::DuctBridge
        );
        if target_is_duct_bridge {
            return self.dump_item_to_duct_bridge(content, source_index, target_index, item_id);
        }
        let target_is_stack_conveyor = matches!(
            content.block(self.buildings[target_index].block.id),
            Some(BlockDef::Distribution(distribution))
                if distribution.kind == DistributionBlockKind::StackConveyor
        );
        if target_is_stack_conveyor {
            return self.dump_item_to_stack_conveyor(content, source_index, target_index, item_id);
        }
        let target_is_conveyor = matches!(
            content.block(self.buildings[target_index].block.id),
            Some(BlockDef::Distribution(distribution))
                if matches!(
                    distribution.kind,
                    DistributionBlockKind::Conveyor | DistributionBlockKind::ArmoredConveyor
                )
        );
        if target_is_conveyor {
            return self.dump_item_to_conveyor(content, source_index, target_index, item_id);
        }
        let target_is_duct = matches!(
            content.block(self.buildings[target_index].block.id),
            Some(BlockDef::Distribution(distribution))
                if matches!(
                    distribution.kind,
                    DistributionBlockKind::Duct
                        | DistributionBlockKind::DuctRouter
                        | DistributionBlockKind::OverflowDuct
                        | DistributionBlockKind::StackRouter
                )
        );
        if target_is_duct {
            return self.dump_item_to_duct(content, source_index, target_index, item_id);
        }
        let target_is_instant_transfer = matches!(
            content.block(self.buildings[target_index].block.id),
            Some(BlockDef::Distribution(distribution))
                if matches!(
                    distribution.kind,
                    DistributionBlockKind::Sorter | DistributionBlockKind::OverflowGate
                )
        );
        if target_is_instant_transfer {
            return self.dump_item_through_instant_transfer(
                content,
                source_index,
                target_index,
                item_id,
            );
        }
        let target_is_router = matches!(
            content.block(self.buildings[target_index].block.id),
            Some(BlockDef::Distribution(distribution))
                if distribution.kind == DistributionBlockKind::Router
        );
        let target_is_mass_driver = matches!(
            content.block(self.buildings[target_index].block.id),
            Some(BlockDef::Distribution(distribution))
                if distribution.kind == DistributionBlockKind::MassDriver
        );
        let source_tile_pos = self.buildings[source_index].tile_pos;
        let target_tile_pos = self.buildings[target_index].tile_pos;
        let target_item_owner_index = self.item_module_owner_index(content, target_index);
        if source_index == target_item_owner_index
            || target_item_owner_index >= self.buildings.len()
        {
            return false;
        }
        let target_max_accepted = self.maximum_accepted_for_item_owner(target_item_owner_index);
        let target_item_owner_is_core = self.building_is_core(content, target_item_owner_index);
        let target_core_authoritative =
            !target_item_owner_is_core || self.network_context.core_handle_item_authoritative();
        let target_item_owner_stored = self
            .buildings
            .get(target_item_owner_index)
            .and_then(|building| building.items.as_ref())
            .map(|items| items.get(item_id))
            .unwrap_or(0);
        let target_core_incinerates_item = target_item_owner_is_core
            && self.core_should_incinerate_handled_item(
                content,
                target_item_owner_index,
                item_id,
                target_item_owner_stored,
                target_max_accepted,
            );

        let (source, target) = if source_index < target_item_owner_index {
            let (left, right) = self.buildings.split_at_mut(target_item_owner_index);
            (&mut left[source_index], &mut right[0])
        } else {
            let (left, right) = self.buildings.split_at_mut(source_index);
            (&mut right[0], &mut left[target_item_owner_index])
        };

        let Some(source_items) = source.items.as_mut() else {
            return false;
        };
        if source_items.get(item_id) <= 0 {
            return false;
        }

        if target_is_item_void || target_is_item_incinerator {
            source_items.remove(item_id, 1);
            return true;
        }

        let Some(target_items) = target.items.as_mut() else {
            return false;
        };
        let target_full = if target_is_mass_driver {
            target_items.total() >= target.block.item_capacity
        } else if target_item_owner_is_core {
            false
        } else {
            target_items.get(item_id) >= target_max_accepted
        };
        if target_full {
            return false;
        }
        source_items.remove(item_id, 1);
        if target_core_authoritative && !target_core_incinerates_item {
            target_items.add(item_id, 1);
        }
        if target_item_owner_is_core {
            self.note_core_handle_item_side_effects(content, target_item_owner_index, item_id, 1);
            if target_core_authoritative || target_core_incinerates_item {
                self.set_core_no_effect(target_item_owner_index, !target_core_incinerates_item);
            }
        }
        if target_is_router {
            self.note_item_router_received(target_tile_pos, item_id, source_tile_pos);
        }
        true
    }

    fn dump_item_through_instant_transfer(
        &mut self,
        content: &ContentLoader,
        source_index: usize,
        instant_index: usize,
        item_id: ContentId,
    ) -> bool {
        let Some((target_index, next_rotation_bits)) = self.instant_transfer_item_destination(
            content,
            source_index,
            instant_index,
            item_id,
            true,
        ) else {
            return false;
        };
        if !self.dump_target_accepts_item(content, instant_index, target_index, item_id) {
            return false;
        }

        let target_is_sink = matches!(
            content.block(self.buildings[target_index].block.id),
            Some(BlockDef::Sandbox(sandbox)) if sandbox.kind == SandboxBlockKind::ItemVoid
        ) || matches!(
            content.block(self.buildings[target_index].block.id),
            Some(BlockDef::Crafting(crafting))
                if crafting.kind == CraftingBlockKind::ItemIncinerator
        );
        let target_accepts_simple_items = target_is_sink
            || match content.block(self.buildings[target_index].block.id) {
                Some(BlockDef::Storage(_)) => true,
                Some(BlockDef::Distribution(distribution))
                    if distribution.kind == DistributionBlockKind::Router =>
                {
                    true
                }
                _ => false,
            };
        if !target_accepts_simple_items {
            return false;
        }
        let target_is_router = matches!(
            content.block(self.buildings[target_index].block.id),
            Some(BlockDef::Distribution(distribution))
                if distribution.kind == DistributionBlockKind::Router
        );
        let instant_tile_pos = self.buildings[instant_index].tile_pos;
        let target_tile_pos = self.buildings[target_index].tile_pos;

        if source_index == target_index
            || source_index >= self.buildings.len()
            || target_index >= self.buildings.len()
        {
            return false;
        }

        let (source, target) = if source_index < target_index {
            let (left, right) = self.buildings.split_at_mut(target_index);
            (&mut left[source_index], &mut right[0])
        } else {
            let (left, right) = self.buildings.split_at_mut(source_index);
            (&mut right[0], &mut left[target_index])
        };

        let Some(source_items) = source.items.as_mut() else {
            return false;
        };
        if source_items.get(item_id) <= 0 {
            return false;
        }
        source_items.remove(item_id, 1);

        if !target_is_sink {
            let Some(target_items) = target.items.as_mut() else {
                return false;
            };
            if target_items.total() >= target.block.item_capacity {
                return false;
            }
            target_items.add(item_id, 1);
        }
        if target_is_router {
            self.note_item_router_received(target_tile_pos, item_id, instant_tile_pos);
        }

        if let Some(next_rotation_bits) = next_rotation_bits {
            if let Some(instant) = self.buildings.get_mut(instant_index) {
                instant.rotation = next_rotation_bits;
            }
        }
        true
    }

    fn instant_transfer_item_destination(
        &self,
        content: &ContentLoader,
        source_index: usize,
        instant_index: usize,
        item_id: ContentId,
        flip: bool,
    ) -> Option<(usize, Option<i32>)> {
        let instant = self.buildings.get(instant_index)?;
        let BlockDef::Distribution(distribution) = content.block(instant.block.id)? else {
            return None;
        };
        let direction = self.relative_direction_between_buildings(source_index, instant_index)?;
        let source_instant = self.building_instant_transfer(content, source_index);

        match distribution.kind {
            DistributionBlockKind::Sorter => {
                let sort_item = match self.distribution_runtime_states.get(&instant.tile_pos) {
                    Some(GameRuntimeDistributionBlockState::Sorter(state)) => state.sort_item,
                    Some(_) => return None,
                    None => None,
                };
                let direct =
                    sorter_should_direct(item_id, sort_item, distribution.invert, instant.enabled);
                if direct {
                    let target_index = self.neighbor_building_index(instant_index, direction)?;
                    if sorter_rejects_instant_three_chain(
                        direct,
                        source_instant,
                        self.building_instant_transfer(content, target_index),
                    ) {
                        return None;
                    }
                    return self
                        .instant_transfer_neighbor_accepts(
                            content,
                            instant_index,
                            target_index,
                            item_id,
                            false,
                        )
                        .then_some((target_index, None));
                }

                let left_dir = (direction - 1).rem_euclid(4);
                let right_dir = (direction + 1).rem_euclid(4);
                let left = self.neighbor_building_index(instant_index, left_dir);
                let right = self.neighbor_building_index(instant_index, right_dir);
                let left_accepts = left.is_some_and(|target| {
                    self.instant_transfer_neighbor_accepts(
                        content,
                        instant_index,
                        target,
                        item_id,
                        source_instant,
                    )
                });
                let right_accepts = right.is_some_and(|target| {
                    self.instant_transfer_neighbor_accepts(
                        content,
                        instant_index,
                        target,
                        item_id,
                        source_instant,
                    )
                });
                let (route, next_bits) = choose_side_route(
                    left_accepts,
                    right_accepts,
                    instant.rotation,
                    direction,
                    flip,
                )?;
                let target = match route {
                    SideRoute::Left => left?,
                    SideRoute::Right => right?,
                };
                Some((target, (next_bits != instant.rotation).then_some(next_bits)))
            }
            DistributionBlockKind::OverflowGate => {
                let forward = self.neighbor_building_index(instant_index, direction);
                let left_dir = (direction - 1).rem_euclid(4);
                let right_dir = (direction + 1).rem_euclid(4);
                let left = self.neighbor_building_index(instant_index, left_dir);
                let right = self.neighbor_building_index(instant_index, right_dir);
                let can_forward = forward.is_some_and(|target| {
                    self.instant_transfer_neighbor_accepts(
                        content,
                        instant_index,
                        target,
                        item_id,
                        source_instant,
                    )
                });
                let left_accepts = left.is_some_and(|target| {
                    self.instant_transfer_neighbor_accepts(
                        content,
                        instant_index,
                        target,
                        item_id,
                        source_instant,
                    )
                });
                let right_accepts = right.is_some_and(|target| {
                    self.instant_transfer_neighbor_accepts(
                        content,
                        instant_index,
                        target,
                        item_id,
                        source_instant,
                    )
                });
                let (route, next_bits) = overflow_gate_route(
                    can_forward,
                    distribution.invert == instant.enabled,
                    left_accepts,
                    right_accepts,
                    instant.rotation,
                    direction,
                    flip,
                )?;
                let target = match route {
                    OverflowRoute::Forward => forward?,
                    OverflowRoute::Left => left?,
                    OverflowRoute::Right => right?,
                };
                Some((target, (next_bits != instant.rotation).then_some(next_bits)))
            }
            _ => None,
        }
    }

    fn instant_transfer_neighbor_accepts(
        &self,
        content: &ContentLoader,
        instant_index: usize,
        target_index: usize,
        item_id: ContentId,
        source_instant: bool,
    ) -> bool {
        if source_instant && self.building_instant_transfer(content, target_index) {
            return false;
        }
        self.dump_target_accepts_item(content, instant_index, target_index, item_id)
    }

    fn building_instant_transfer(&self, content: &ContentLoader, index: usize) -> bool {
        self.buildings
            .get(index)
            .and_then(|building| content.block(building.block.id))
            .is_some_and(|block| match block {
                BlockDef::Distribution(distribution) => distribution.instant_transfer,
                _ => false,
            })
    }

    fn note_item_router_received(
        &mut self,
        router_tile_pos: i32,
        item_id: ContentId,
        source_tile_pos: i32,
    ) {
        let state = self
            .item_router_runtime_states
            .entry(router_tile_pos)
            .or_default();
        state.last_item = Some(item_id);
        state.last_input = Some(source_tile_pos);
        state.time = 0.0;
    }

    fn neighbor_building_index(&self, center_index: usize, direction: i32) -> Option<usize> {
        let center = self.buildings.get(center_index)?;
        let (dx, dy) = autotiler_direction(direction);
        let target_ref = self
            .state
            .world
            .build(center.tile_x() + dx, center.tile_y() + dy)?;
        self.buildings
            .iter()
            .position(|building| building.tile_pos == target_ref.tile_pos)
    }

    fn building_index_by_tile_pos(&self, tile_pos: i32) -> Option<usize> {
        self.buildings
            .iter()
            .position(|building| building.tile_pos == tile_pos)
    }

    pub fn advance_owned_item_transport_blocks(
        &mut self,
        content: &ContentLoader,
        delta_seconds: f32,
    ) -> Option<GameRuntimeOwnedItemTransportFrameReport> {
        self.consume_world_load_events_and_reset_sidecars();

        let advanced = self.state.advance_game_update_frame(delta_seconds);
        if !advanced.advanced {
            return None;
        }
        self.refresh_owned_building_update_permissions(content);
        for building in self.buildings.iter_mut() {
            let can_overdrive = content
                .block(building.block.id)
                .map(BlockDef::can_overdrive)
                .unwrap_or(false);
            building.advance_update_timing(advanced.delta_ticks as f32, can_overdrive);
        }
        Some(self.advance_owned_item_transport_blocks_ticks(content, advanced.delta_ticks as f32))
    }

    fn advance_owned_item_transport_blocks_ticks(
        &mut self,
        content: &ContentLoader,
        frame_delta: f32,
    ) -> GameRuntimeOwnedItemTransportFrameReport {
        let mut report = GameRuntimeOwnedItemTransportFrameReport::default();
        report.router_forwarded_items += self
            .advance_owned_item_routers_ticks(content, frame_delta)
            .moved_items;
        report.item_unloader_moved_items += self
            .advance_owned_item_unloaders_ticks(content, frame_delta)
            .moved_items;
        report.directional_unloader_moved_items += self
            .advance_owned_directional_unloaders_ticks(content, frame_delta)
            .moved_items;
        report.duct_forwarded_items += self
            .advance_owned_item_ducts_ticks(content, frame_delta)
            .moved_items;
        report.stack_router_forwarded_items += self
            .advance_owned_stack_routers_ticks(content, frame_delta)
            .moved_items;
        let duct_bridge_report = self.advance_owned_duct_bridges_ticks(content, frame_delta);
        report.duct_bridge_forwarded_items +=
            duct_bridge_report.moved_items + duct_bridge_report.dumped_items;
        let stack_report = self.advance_owned_stack_conveyors_ticks(content, frame_delta);
        report.stack_conveyor_forwarded_items +=
            stack_report.moved_stacks + stack_report.dumped_items;
        let mass_driver_report = self.advance_owned_item_mass_drivers_ticks(content, frame_delta);
        report.mass_driver_forwarded_items +=
            mass_driver_report.transferred_items + mass_driver_report.dumped_items;
        report.bridge_forwarded_items += self
            .advance_owned_item_bridges_ticks(content, frame_delta)
            .moved_items;
        report.junction_forwarded_items += self
            .advance_owned_item_junctions_ticks(content, frame_delta)
            .moved_items;
        let cargo_report = self.advance_owned_unit_cargo_blocks_ticks(content, frame_delta);
        report.unit_cargo_loader_built_units += cargo_report.0;
        report.unit_cargo_unload_dumped_items += cargo_report.1;
        report.unit_cargo_unload_stale_points += cargo_report.2;
        report
    }

    fn advance_owned_unit_cargo_blocks_ticks(
        &mut self,
        content: &ContentLoader,
        frame_delta: f32,
    ) -> (usize, usize, usize) {
        let mut built_units = 0;
        let mut dumped_items = 0;
        let mut stale_points = 0;

        for index in 0..self.buildings.len() {
            let (tile_pos, block_id, enabled, efficiency, time_scale, power_status) = {
                let building = &self.buildings[index];
                (
                    building.tile_pos,
                    building.block.id,
                    building.enabled,
                    building.efficiency,
                    building.time_scale,
                    building
                        .power
                        .as_ref()
                        .map(|power| power.status)
                        .unwrap_or(1.0),
                )
            };
            let Some(BlockDef::Distribution(distribution)) = content.block(block_id) else {
                continue;
            };
            match distribution.kind {
                DistributionBlockKind::UnitCargoLoader => {
                    let entry = self
                        .distribution_runtime_states
                        .entry(tile_pos)
                        .or_insert_with(|| {
                            GameRuntimeDistributionBlockState::UnitCargoLoader(
                                UnitCargoLoaderState::default(),
                            )
                        });
                    let state = match entry {
                        GameRuntimeDistributionBlockState::UnitCargoLoader(state) => state,
                        _ => {
                            *entry = GameRuntimeDistributionBlockState::UnitCargoLoader(
                                UnitCargoLoaderState::default(),
                            );
                            match entry {
                                GameRuntimeDistributionBlockState::UnitCargoLoader(state) => state,
                                _ => unreachable!(),
                            }
                        }
                    };
                    let should_consume = !state.has_unit;
                    let power_efficiency = if self.buildings[index].block.consumes_power
                        && distribution.consume_power > 0.0
                    {
                        consume_power_efficiency(power_status).clamp(0.0, 1.0)
                    } else {
                        1.0
                    };
                    let liquid_specs: Vec<_> = distribution
                        .consume_liquids
                        .iter()
                        .map(|liquid| LiquidStackSpec {
                            liquid_id: liquid.liquid,
                            amount: liquid.amount,
                        })
                        .collect();
                    let liquid_efficiency = if liquid_specs.is_empty() {
                        1.0
                    } else {
                        self.buildings[index]
                            .liquids
                            .as_ref()
                            .map_or(0.0, |liquids| {
                                consume_liquids_efficiency(
                                    &liquid_specs,
                                    frame_delta * time_scale,
                                    1.0,
                                    1.0,
                                    |liquid_id| liquids.get(liquid_id),
                                )
                                .clamp(0.0, 1.0)
                            })
                    };
                    let effective_efficiency = if enabled {
                        efficiency
                            .min(power_efficiency)
                            .min(liquid_efficiency)
                            .max(0.0)
                    } else {
                        0.0
                    };
                    let edelta = frame_delta * time_scale * effective_efficiency;
                    let can_create = enabled
                        && content
                            .unit_by_name("manifold")
                            .map(|unit| !self.state.rules.is_unit_banned(unit.name()))
                            .unwrap_or(false);
                    let spawned = unit_cargo_loader_update(
                        state,
                        effective_efficiency,
                        can_create,
                        edelta,
                        frame_delta * time_scale,
                        distribution.unit_build_time,
                    );
                    if should_consume && edelta > 0.0 && !distribution.consume_liquids.is_empty() {
                        let liquid_requirements =
                            scaled_liquid_requirements(&distribution.consume_liquids, edelta);
                        consume_building_liquids(&mut self.buildings[index], &liquid_requirements);
                    }
                    if spawned {
                        unit_cargo_loader_spawned(state, 0, false);
                        state.has_unit = true;
                        built_units += 1;
                    }
                }
                DistributionBlockKind::UnitCargoUnloadPoint => {
                    let before_stale = matches!(
                        self.distribution_runtime_states.get(&tile_pos),
                        Some(GameRuntimeDistributionBlockState::UnitCargoUnload(state))
                            if state.stale
                    );
                    let dumped = self.dump_accumulated_items_from_unit_cargo_unload_point(
                        content,
                        index,
                        frame_delta * time_scale,
                    );
                    dumped_items += dumped;
                    let items_total = self.buildings[index]
                        .items
                        .as_ref()
                        .map(|items| items.total())
                        .unwrap_or(0);
                    let entry = self
                        .distribution_runtime_states
                        .entry(tile_pos)
                        .or_insert_with(|| {
                            GameRuntimeDistributionBlockState::UnitCargoUnload(
                                UnitCargoUnloadPointState {
                                    item_id: None,
                                    stale_timer: 0.0,
                                    stale: false,
                                },
                            )
                        });
                    let state = match entry {
                        GameRuntimeDistributionBlockState::UnitCargoUnload(state) => state,
                        _ => {
                            *entry = GameRuntimeDistributionBlockState::UnitCargoUnload(
                                UnitCargoUnloadPointState {
                                    item_id: None,
                                    stale_timer: 0.0,
                                    stale: false,
                                },
                            );
                            match entry {
                                GameRuntimeDistributionBlockState::UnitCargoUnload(state) => state,
                                _ => unreachable!(),
                            }
                        }
                    };
                    unit_cargo_unload_update(
                        state,
                        items_total,
                        self.buildings[index].block.item_capacity,
                        dumped > 0,
                        frame_delta * time_scale,
                        distribution.stale_time_duration,
                    );
                    if !before_stale && state.stale {
                        stale_points += 1;
                    }
                }
                _ => {}
            }
        }

        (built_units, dumped_items, stale_points)
    }

    pub fn advance_owned_item_routers(
        &mut self,
        content: &ContentLoader,
        delta_seconds: f32,
    ) -> Option<GameRuntimeItemRouterFrameReport> {
        let advanced = self.state.advance_game_update_frame(delta_seconds);
        if !advanced.advanced {
            return None;
        }
        let frame_delta = advanced.delta_ticks as f32;
        Some(self.advance_owned_item_routers_ticks(content, frame_delta))
    }

    fn advance_owned_item_routers_ticks(
        &mut self,
        content: &ContentLoader,
        frame_delta: f32,
    ) -> GameRuntimeItemRouterFrameReport {
        self.refresh_owned_storage_core_links(content);
        let mut report = GameRuntimeItemRouterFrameReport::default();
        let router_indices: Vec<_> = self
            .buildings
            .iter()
            .enumerate()
            .filter_map(|(index, building)| {
                report.visited_buildings += 1;
                match content.block(building.block.id) {
                    Some(BlockDef::Distribution(distribution))
                        if distribution.kind == DistributionBlockKind::Router =>
                    {
                        report.router_candidates += 1;
                        Some(index)
                    }
                    _ => None,
                }
            })
            .collect();

        for index in router_indices {
            let Some(BlockDef::Distribution(router_block)) =
                content.block(self.buildings[index].block.id)
            else {
                continue;
            };
            if !self.buildings[index].enabled {
                continue;
            }

            let tile_pos = self.buildings[index].tile_pos;
            let mut state = self
                .item_router_runtime_states
                .get(&tile_pos)
                .copied()
                .unwrap_or_default();
            if state.last_item.is_none() {
                state.last_item = self.buildings[index]
                    .items
                    .as_ref()
                    .and_then(|items| items.each().map(|(item, _)| item).next());
            }
            let Some(item_id) = state.last_item else {
                self.item_router_runtime_states.insert(tile_pos, state);
                continue;
            };
            if !self.buildings[index]
                .items
                .as_ref()
                .is_some_and(|items| items.get(item_id) > 0)
            {
                state.last_item = None;
                state.time = 0.0;
                self.item_router_runtime_states.insert(tile_pos, state);
                continue;
            }

            state.time += if router_block.speed > 0.0 {
                frame_delta / router_block.speed
            } else {
                frame_delta
            };

            let Some((target_index, _)) =
                self.item_router_target(content, index, state.last_input, item_id, false)
            else {
                report.missing_targets += 1;
                self.item_router_runtime_states.insert(tile_pos, state);
                continue;
            };

            if state.time >= 1.0 || !self.item_router_target_delays(content, target_index) {
                report.attempted_moves += 1;
                let Some((target_index, next_rotation)) =
                    self.item_router_target(content, index, state.last_input, item_id, true)
                else {
                    report.missing_targets += 1;
                    self.item_router_runtime_states.insert(tile_pos, state);
                    continue;
                };
                if self.dump_item_to_target(content, index, target_index, item_id) {
                    if let Some(next_rotation) = next_rotation {
                        self.buildings[index].rotation = next_rotation;
                    }
                    state.last_item = None;
                    state.last_input = None;
                    state.time = 0.0;
                    report.moved_items += 1;
                }
            }

            report.updated_routers += 1;
            self.item_router_runtime_states.insert(tile_pos, state);
        }

        report
    }

    fn item_router_target(
        &self,
        content: &ContentLoader,
        router_index: usize,
        last_input: Option<i32>,
        item_id: ContentId,
        rotate: bool,
    ) -> Option<(usize, Option<i32>)> {
        let router = self.buildings.get(router_index)?;
        let prox_len = router.proximity.len();
        if prox_len == 0 {
            return None;
        }
        let mut next_rotation = router.rotation.rem_euclid(prox_len as i32);
        let start_rotation = next_rotation as usize;
        let source_is_overflow_gate = last_input
            .and_then(|tile_pos| {
                self.buildings
                    .iter()
                    .find(|building| building.tile_pos == tile_pos)
            })
            .and_then(|building| content.block(building.block.id))
            .is_some_and(|block| match block {
                BlockDef::Distribution(distribution) => {
                    distribution.kind == DistributionBlockKind::OverflowGate
                }
                _ => false,
            });

        for attempt in 0..prox_len {
            let candidate_ref = router.proximity[(attempt + start_rotation) % prox_len];
            if rotate {
                next_rotation = (next_rotation + 1).rem_euclid(prox_len as i32);
            }
            if source_is_overflow_gate && Some(candidate_ref.tile_pos) == last_input {
                continue;
            }
            let Some(candidate_index) = self
                .buildings
                .iter()
                .position(|building| building.tile_pos == candidate_ref.tile_pos)
            else {
                continue;
            };
            if self.dump_target_accepts_item(content, router_index, candidate_index, item_id) {
                return Some((
                    candidate_index,
                    (rotate && next_rotation != router.rotation).then_some(next_rotation),
                ));
            }
        }

        None
    }

    fn item_router_target_delays(&self, content: &ContentLoader, target_index: usize) -> bool {
        self.building_instant_transfer(content, target_index)
            || matches!(
                content.block(self.buildings[target_index].block.id),
                Some(BlockDef::Distribution(distribution))
                    if distribution.kind == DistributionBlockKind::Router
            )
    }

    pub fn advance_owned_item_bridges(
        &mut self,
        content: &ContentLoader,
        delta_seconds: f32,
    ) -> Option<GameRuntimeItemBridgeFrameReport> {
        let advanced = self.state.advance_game_update_frame(delta_seconds);
        if !advanced.advanced {
            return None;
        }
        Some(self.advance_owned_item_bridges_ticks(content, advanced.delta_ticks as f32))
    }

    fn advance_owned_item_bridges_ticks(
        &mut self,
        content: &ContentLoader,
        frame_delta: f32,
    ) -> GameRuntimeItemBridgeFrameReport {
        self.refresh_owned_storage_core_links(content);
        let mut report = GameRuntimeItemBridgeFrameReport::default();
        let bridge_indices: Vec<_> = self
            .buildings
            .iter()
            .enumerate()
            .filter_map(|(index, building)| {
                report.visited_buildings += 1;
                match content.block(building.block.id) {
                    Some(BlockDef::Distribution(distribution))
                        if matches!(
                            distribution.kind,
                            DistributionBlockKind::ItemBridge
                                | DistributionBlockKind::BufferedItemBridge
                        ) =>
                    {
                        report.bridge_candidates += 1;
                        Some(index)
                    }
                    _ => None,
                }
            })
            .collect();

        for index in bridge_indices {
            if !self.buildings[index].enabled {
                continue;
            }
            let Some(BlockDef::Distribution(bridge_block)) =
                content.block(self.buildings[index].block.id)
            else {
                continue;
            };
            let tile_pos = self.buildings[index].tile_pos;
            let link = self
                .ensure_item_bridge_state(tile_pos, bridge_block.kind)
                .link;
            let Some(target_index) = self.item_bridge_link_target_index(content, index, link)
            else {
                self.set_item_bridge_warmup(tile_pos, bridge_block.kind, 0.0);
                if self.dump_one_item_from_building(content, index) {
                    report.dumped_items += 1;
                } else {
                    report.missing_targets += 1;
                }
                report.updated_bridges += 1;
                continue;
            };

            let target_tile_pos = self.buildings[target_index].tile_pos;
            self.ensure_item_bridge_state(target_tile_pos, bridge_block.kind);
            self.note_item_bridge_incoming(target_tile_pos, tile_pos);
            let warmup = item_bridge_warmup_step(
                self.item_bridge_warmup(tile_pos),
                self.buildings[index].efficiency,
            );
            self.set_item_bridge_warmup(tile_pos, bridge_block.kind, warmup);

            if bridge_block.kind == DistributionBlockKind::BufferedItemBridge {
                self.advance_buffered_item_bridge_transport(
                    content,
                    index,
                    target_index,
                    bridge_block,
                    frame_delta,
                    &mut report,
                );
                report.updated_bridges += 1;
                continue;
            }

            let edelta =
                frame_delta * self.buildings[index].efficiency * self.buildings[index].time_scale;
            let counter = self
                .item_bridge_transport_counters
                .entry(tile_pos)
                .or_insert(0.0);
            let (iterations, next_counter) =
                item_bridge_transport_iterations(*counter, edelta, bridge_block.transport_time);
            *counter = next_counter;

            for _ in 0..iterations {
                let Some(item_id) = self.first_item_id_from_building(content, index) else {
                    continue;
                };
                report.attempted_moves += 1;
                if self.dump_item_to_target(content, index, target_index, item_id) {
                    self.mark_item_bridge_moved(tile_pos);
                    report.moved_items += 1;
                }
            }
            report.updated_bridges += 1;
        }

        report
    }

    pub fn advance_owned_item_junctions(
        &mut self,
        content: &ContentLoader,
        delta_seconds: f32,
    ) -> Option<GameRuntimeItemJunctionFrameReport> {
        let advanced = self.state.advance_game_update_frame(delta_seconds);
        if !advanced.advanced {
            return None;
        }
        Some(self.advance_owned_item_junctions_ticks(content, advanced.delta_ticks as f32))
    }

    fn advance_owned_item_junctions_ticks(
        &mut self,
        content: &ContentLoader,
        frame_delta: f32,
    ) -> GameRuntimeItemJunctionFrameReport {
        self.refresh_owned_storage_core_links(content);
        let mut report = GameRuntimeItemJunctionFrameReport::default();
        let junction_indices: Vec<_> = self
            .buildings
            .iter()
            .enumerate()
            .filter_map(|(index, building)| {
                report.visited_buildings += 1;
                match content.block(building.block.id) {
                    Some(BlockDef::Distribution(distribution))
                        if distribution.kind == DistributionBlockKind::Junction =>
                    {
                        report.junction_candidates += 1;
                        Some(index)
                    }
                    _ => None,
                }
            })
            .collect();

        for index in junction_indices {
            if !self.buildings[index].enabled {
                continue;
            }
            let Some(BlockDef::Distribution(junction_block)) =
                content.block(self.buildings[index].block.id)
            else {
                continue;
            };
            let tile_pos = self.buildings[index].tile_pos;
            let now = {
                let counter = self
                    .item_junction_time_counters
                    .entry(tile_pos)
                    .or_insert(0.0);
                *counter += frame_delta.max(0.0);
                *counter
            };
            let time_scale = self.buildings[index].time_scale.max(0.0001);
            let mut state = self
                .distribution_runtime_states
                .get(&tile_pos)
                .and_then(|state| match state {
                    GameRuntimeDistributionBlockState::DuctJunction(state) => Some(state.clone()),
                    _ => None,
                })
                .unwrap_or_default();

            for side in 0..4 {
                let Some(entry) = state
                    .buffer
                    .peek(side, junction_block.speed / time_scale, now)
                else {
                    continue;
                };
                let item_id = entry.item;

                let Some(target_index) = self.neighbor_building_index(index, side as i32) else {
                    report.missing_targets += 1;
                    continue;
                };

                report.attempted_moves += 1;
                if self.handle_buffered_item_to_target(content, index, target_index, item_id) {
                    state.buffer.remove(side);
                    report.moved_items += 1;
                }
            }

            self.distribution_runtime_states.insert(
                tile_pos,
                GameRuntimeDistributionBlockState::DuctJunction(state),
            );
            report.updated_junctions += 1;
        }

        report
    }

    fn advance_buffered_item_bridge_transport(
        &mut self,
        content: &ContentLoader,
        source_index: usize,
        target_index: usize,
        bridge_block: &crate::mindustry::content::blocks::DistributionBlockData,
        frame_delta: f32,
        report: &mut GameRuntimeItemBridgeFrameReport,
    ) {
        let tile_pos = self.buildings[source_index].tile_pos;
        let now = {
            let counter = self
                .item_bridge_transport_counters
                .entry(tile_pos)
                .or_insert(0.0);
            *counter += frame_delta.max(0.0);
            *counter
        };
        let capacity = bridge_block.buffer_capacity.max(0) as usize;
        if capacity > 0
            && self.buffered_item_bridge_buffer_len(tile_pos) < capacity
            && self.buildings[source_index]
                .items
                .as_ref()
                .is_some_and(|items| items.total() > 0)
        {
            if let Some(item_id) = self.first_item_id_from_building(content, source_index) {
                if let Some(items) = self.buildings[source_index].items.as_mut() {
                    if items.get(item_id) > 0 {
                        items.remove(item_id, 1);
                        self.buffered_item_bridge_push(tile_pos, capacity, item_id, now);
                    }
                }
            }
        }

        let time_scale = self.buildings[source_index].time_scale.max(0.0001);
        let delay = bridge_block.speed / time_scale;
        let Some(item_id) = self.buffered_item_bridge_ready_item(tile_pos, delay, now) else {
            return;
        };
        report.attempted_moves += 1;
        if self.handle_buffered_item_to_target(content, source_index, target_index, item_id) {
            self.buffered_item_bridge_remove_head(tile_pos);
            self.mark_item_bridge_moved(tile_pos);
            report.moved_items += 1;
        }
    }

    fn ensure_item_bridge_state(
        &mut self,
        tile_pos: i32,
        kind: DistributionBlockKind,
    ) -> &mut ItemBridgeState {
        match kind {
            DistributionBlockKind::ItemBridge => {
                let entry = self
                    .distribution_runtime_states
                    .entry(tile_pos)
                    .or_insert_with(|| {
                        GameRuntimeDistributionBlockState::ItemBridge(ItemBridgeState::default())
                    });
                let GameRuntimeDistributionBlockState::ItemBridge(state) = entry else {
                    *entry =
                        GameRuntimeDistributionBlockState::ItemBridge(ItemBridgeState::default());
                    let GameRuntimeDistributionBlockState::ItemBridge(state) = entry else {
                        unreachable!("item bridge state was just inserted")
                    };
                    return state;
                };
                state
            }
            DistributionBlockKind::BufferedItemBridge => {
                let entry = self
                    .distribution_runtime_states
                    .entry(tile_pos)
                    .or_insert_with(|| {
                        GameRuntimeDistributionBlockState::BufferedItemBridge(
                            BufferedItemBridgeState {
                                bridge: ItemBridgeState::default(),
                                index: 0,
                                buffer: Vec::new(),
                            },
                        )
                    });
                let GameRuntimeDistributionBlockState::BufferedItemBridge(state) = entry else {
                    *entry = GameRuntimeDistributionBlockState::BufferedItemBridge(
                        BufferedItemBridgeState {
                            bridge: ItemBridgeState::default(),
                            index: 0,
                            buffer: Vec::new(),
                        },
                    );
                    let GameRuntimeDistributionBlockState::BufferedItemBridge(state) = entry else {
                        unreachable!("buffered bridge state was just inserted")
                    };
                    return &mut state.bridge;
                };
                &mut state.bridge
            }
            _ => unreachable!("non item bridge kind"),
        }
    }

    fn buffered_item_bridge_buffer_len(&self, tile_pos: i32) -> usize {
        match self.distribution_runtime_states.get(&tile_pos) {
            Some(GameRuntimeDistributionBlockState::BufferedItemBridge(state)) => {
                state.index.max(0) as usize
            }
            _ => 0,
        }
    }

    fn buffered_item_bridge_push(
        &mut self,
        tile_pos: i32,
        capacity: usize,
        item_id: ContentId,
        now: f32,
    ) {
        self.ensure_item_bridge_state(tile_pos, DistributionBlockKind::BufferedItemBridge);
        let Some(GameRuntimeDistributionBlockState::BufferedItemBridge(buffered)) =
            self.distribution_runtime_states.get_mut(&tile_pos)
        else {
            return;
        };
        let index = buffered.index.max(0) as usize;
        if index >= capacity {
            return;
        }
        if buffered.buffer.len() < capacity {
            buffered.buffer.resize(capacity, 0);
        }
        buffered.buffer[index] = TimeItem::new(-1, item_id as i16, now).pack() as i64;
        buffered.index = (index + 1) as i32;
    }

    fn buffered_item_bridge_ready_item(
        &self,
        tile_pos: i32,
        delay: f32,
        now: f32,
    ) -> Option<ContentId> {
        let Some(GameRuntimeDistributionBlockState::BufferedItemBridge(state)) =
            self.distribution_runtime_states.get(&tile_pos)
        else {
            return None;
        };
        if state.index <= 0 || state.buffer.is_empty() {
            return None;
        }
        let entry = TimeItem::unpack(state.buffer[0] as u64);
        (now >= entry.time + delay || now < entry.time).then_some(entry.item)
    }

    fn buffered_item_bridge_remove_head(&mut self, tile_pos: i32) {
        let Some(GameRuntimeDistributionBlockState::BufferedItemBridge(state)) =
            self.distribution_runtime_states.get_mut(&tile_pos)
        else {
            return;
        };
        let len = state.index.max(0) as usize;
        if len == 0 {
            return;
        }
        if len > 1 {
            state.buffer.copy_within(1..len, 0);
        }
        state.index -= 1;
        let next_len = state.index.max(0) as usize;
        if next_len < state.buffer.len() {
            state.buffer[next_len] = 0;
        }
    }

    fn ensure_duct_junction_state(&mut self, tile_pos: i32) -> &mut DuctJunctionState {
        let entry = self
            .distribution_runtime_states
            .entry(tile_pos)
            .or_insert_with(|| {
                GameRuntimeDistributionBlockState::DuctJunction(DuctJunctionState::default())
            });
        let GameRuntimeDistributionBlockState::DuctJunction(state) = entry else {
            *entry = GameRuntimeDistributionBlockState::DuctJunction(DuctJunctionState::default());
            let GameRuntimeDistributionBlockState::DuctJunction(state) = entry else {
                unreachable!("duct junction state was just inserted")
            };
            return state;
        };
        state
    }

    fn handle_buffered_item_to_junction(
        &mut self,
        content: &ContentLoader,
        source_index: usize,
        target_index: usize,
        item_id: ContentId,
    ) -> bool {
        if !self.dump_target_accepts_item(content, source_index, target_index, item_id) {
            return false;
        }
        let Some(relative) = self.relative_direction_between_buildings(source_index, target_index)
        else {
            return false;
        };
        let side = relative as usize;
        let target_tile_pos = self.buildings[target_index].tile_pos;
        let now = self
            .item_junction_time_counters
            .get(&target_tile_pos)
            .copied()
            .unwrap_or(0.0);
        let state = self.ensure_duct_junction_state(target_tile_pos);
        state.buffer.accept(side, item_id, now)
    }

    fn handle_buffered_item_to_target(
        &mut self,
        content: &ContentLoader,
        source_index: usize,
        target_index: usize,
        item_id: ContentId,
    ) -> bool {
        if source_index == target_index
            || source_index >= self.buildings.len()
            || target_index >= self.buildings.len()
            || !self.dump_target_accepts_item(content, source_index, target_index, item_id)
        {
            return false;
        }

        let target_is_item_void = matches!(
            content.block(self.buildings[target_index].block.id),
            Some(BlockDef::Sandbox(sandbox)) if sandbox.kind == SandboxBlockKind::ItemVoid
        );
        let target_is_item_incinerator = matches!(
            content.block(self.buildings[target_index].block.id),
            Some(BlockDef::Crafting(crafting))
                if crafting.kind == CraftingBlockKind::ItemIncinerator
        );
        if target_is_item_void || target_is_item_incinerator {
            return true;
        }

        let target_is_junction = matches!(
            content.block(self.buildings[target_index].block.id),
            Some(BlockDef::Distribution(distribution))
                if distribution.kind == DistributionBlockKind::Junction
        );
        if target_is_junction {
            return self.handle_buffered_item_to_junction(
                content,
                source_index,
                target_index,
                item_id,
            );
        }

        let target_is_storage = matches!(
            content.block(self.buildings[target_index].block.id),
            Some(BlockDef::Storage(_))
        );
        if target_is_storage {
            let item_capacity = self.buildings[target_index].block.item_capacity;
            let Some(target_items) = self.buildings[target_index].items.as_mut() else {
                return false;
            };
            if target_items.get(item_id) >= item_capacity {
                return false;
            }
            target_items.add(item_id, 1);
            return true;
        }

        let target_tile_pos = self.buildings[target_index].tile_pos;
        let Some(target_kind) = content
            .block(self.buildings[target_index].block.id)
            .and_then(|block| match block {
                BlockDef::Distribution(distribution) => Some(distribution.kind),
                _ => None,
            })
        else {
            return false;
        };
        match target_kind {
            DistributionBlockKind::Conveyor | DistributionBlockKind::ArmoredConveyor => {
                let Some((insert_x, insert_y, insert_at)) =
                    self.conveyor_dump_insert_plan(source_index, target_index)
                else {
                    return false;
                };
                let item_capacity = self.buildings[target_index].block.item_capacity;
                let Some(target_items) = self.buildings[target_index].items.as_mut() else {
                    return false;
                };
                if target_items.total() >= item_capacity {
                    return false;
                }
                target_items.add(item_id, 1);

                let entry = self
                    .distribution_runtime_states
                    .entry(target_tile_pos)
                    .or_insert_with(|| {
                        GameRuntimeDistributionBlockState::Conveyor(ConveyorState {
                            items: Vec::new(),
                        })
                    });
                let GameRuntimeDistributionBlockState::Conveyor(conveyor) = entry else {
                    return false;
                };
                if conveyor.items.len() >= CONVEYOR_CAPACITY {
                    return false;
                }
                let insert_at = insert_at.min(conveyor.items.len());
                conveyor.items.insert(
                    insert_at,
                    ConveyorItemState {
                        item: item_id,
                        x: insert_x,
                        y: insert_y,
                    },
                );
                true
            }
            DistributionBlockKind::Duct
            | DistributionBlockKind::DuctRouter
            | DistributionBlockKind::OverflowDuct => {
                let Some(relative) =
                    self.relative_direction_between_buildings(source_index, target_index)
                else {
                    return false;
                };
                let item_capacity = self.buildings[target_index].block.item_capacity;
                let Some(target_items) = self.buildings[target_index].items.as_mut() else {
                    return false;
                };
                if target_items.total() >= item_capacity {
                    return false;
                }
                target_items.add(item_id, 1);

                match target_kind {
                    DistributionBlockKind::Duct => {
                        let entry = self
                            .distribution_runtime_states
                            .entry(target_tile_pos)
                            .or_insert_with(|| {
                                GameRuntimeDistributionBlockState::Duct(DuctState::default())
                            });
                        let GameRuntimeDistributionBlockState::Duct(state) = entry else {
                            return false;
                        };
                        state.current = Some(item_id);
                        state.rec_dir = relative;
                    }
                    DistributionBlockKind::DuctRouter | DistributionBlockKind::OverflowDuct => {
                        let entry = self
                            .distribution_runtime_states
                            .entry(target_tile_pos)
                            .or_insert_with(|| {
                                GameRuntimeDistributionBlockState::DuctRouter(DuctRouterState {
                                    sort_item: None,
                                    current: None,
                                })
                            });
                        let GameRuntimeDistributionBlockState::DuctRouter(state) = entry else {
                            return false;
                        };
                        state.current = Some(item_id);
                    }
                    _ => {}
                }
                self.item_duct_progress_states.insert(target_tile_pos, -1.0);
                true
            }
            DistributionBlockKind::ItemBridge | DistributionBlockKind::BufferedItemBridge => {
                let item_capacity = self.buildings[target_index].block.item_capacity;
                let Some(target_items) = self.buildings[target_index].items.as_mut() else {
                    return false;
                };
                if target_items.total() >= item_capacity {
                    return false;
                }
                target_items.add(item_id, 1);
                self.ensure_item_bridge_state(target_tile_pos, target_kind);
                true
            }
            DistributionBlockKind::DuctBridge => {
                let item_capacity = self.buildings[target_index].block.item_capacity;
                let Some(target_items) = self.buildings[target_index].items.as_mut() else {
                    return false;
                };
                if target_items.total() >= item_capacity {
                    return false;
                }
                target_items.add(item_id, 1);
                self.ensure_duct_bridge_state(target_tile_pos);
                true
            }
            DistributionBlockKind::StackConveyor => {
                let was_empty = self.buildings[target_index]
                    .items
                    .as_ref()
                    .is_none_or(|items| items.empty());
                let item_capacity = self.buildings[target_index].block.item_capacity;
                let Some(target_items) = self.buildings[target_index].items.as_mut() else {
                    return false;
                };
                if target_items.total() >= item_capacity
                    || (target_items.any() && target_items.get(item_id) <= 0)
                {
                    return false;
                }
                target_items.add(item_id, 1);
                let state = self.ensure_stack_conveyor_state(target_tile_pos);
                if was_empty {
                    state.link = target_tile_pos;
                    state.cooldown = 0.0;
                }
                state.last_item = Some(item_id);
                true
            }
            DistributionBlockKind::Router => {
                let item_capacity = self.buildings[target_index].block.item_capacity;
                let Some(target_items) = self.buildings[target_index].items.as_mut() else {
                    return false;
                };
                if target_items.get(item_id) >= item_capacity {
                    return false;
                }
                target_items.add(item_id, 1);
                let source_tile_pos = self.buildings[source_index].tile_pos;
                self.note_item_router_received(target_tile_pos, item_id, source_tile_pos);
                true
            }
            _ => false,
        }
    }

    fn item_bridge_warmup(&self, tile_pos: i32) -> f32 {
        match self.distribution_runtime_states.get(&tile_pos) {
            Some(GameRuntimeDistributionBlockState::ItemBridge(state)) => state.warmup,
            Some(GameRuntimeDistributionBlockState::BufferedItemBridge(state)) => {
                state.bridge.warmup
            }
            _ => 0.0,
        }
    }

    fn set_item_bridge_warmup(&mut self, tile_pos: i32, kind: DistributionBlockKind, warmup: f32) {
        self.ensure_item_bridge_state(tile_pos, kind).warmup = warmup;
    }

    fn note_item_bridge_incoming(&mut self, tile_pos: i32, incoming: i32) {
        match self.distribution_runtime_states.get_mut(&tile_pos) {
            Some(GameRuntimeDistributionBlockState::ItemBridge(state)) => {
                if !state.incoming.contains(&incoming) {
                    state.incoming.push(incoming);
                }
            }
            Some(GameRuntimeDistributionBlockState::BufferedItemBridge(state)) => {
                if !state.bridge.incoming.contains(&incoming) {
                    state.bridge.incoming.push(incoming);
                }
            }
            _ => {}
        }
    }

    fn mark_item_bridge_moved(&mut self, tile_pos: i32) {
        match self.distribution_runtime_states.get_mut(&tile_pos) {
            Some(GameRuntimeDistributionBlockState::ItemBridge(state)) => state.moved = true,
            Some(GameRuntimeDistributionBlockState::BufferedItemBridge(state)) => {
                state.bridge.moved = true;
            }
            _ => {}
        }
    }

    fn item_bridge_link(&self, tile_pos: i32) -> Option<i32> {
        match self.distribution_runtime_states.get(&tile_pos) {
            Some(GameRuntimeDistributionBlockState::ItemBridge(state)) => Some(state.link),
            Some(GameRuntimeDistributionBlockState::BufferedItemBridge(state)) => {
                Some(state.bridge.link)
            }
            _ => None,
        }
    }

    fn item_bridge_link_target_index(
        &self,
        content: &ContentLoader,
        source_index: usize,
        link: i32,
    ) -> Option<usize> {
        if link < 0 {
            return None;
        }
        let target_index = self
            .buildings
            .iter()
            .position(|building| building.tile_pos == link)?;
        self.item_bridge_link_valid_between(content, source_index, target_index)
            .then_some(target_index)
    }

    fn item_bridge_link_valid_between(
        &self,
        content: &ContentLoader,
        source_index: usize,
        target_index: usize,
    ) -> bool {
        let (Some(source), Some(target)) = (
            self.buildings.get(source_index),
            self.buildings.get(target_index),
        ) else {
            return false;
        };
        if source.team != target.team || source.block.id != target.block.id {
            return false;
        }
        let Some(BlockDef::Distribution(distribution)) = content.block(source.block.id) else {
            return false;
        };
        if !matches!(
            distribution.kind,
            DistributionBlockKind::ItemBridge | DistributionBlockKind::BufferedItemBridge
        ) {
            return false;
        }
        let dx = (source.tile_x() - target.tile_x()).abs();
        let dy = (source.tile_y() - target.tile_y()).abs();
        (dx == 0 || dy == 0) && dx.max(dy) as f32 <= distribution.range
    }

    fn item_bridge_accepts_item(
        &self,
        content: &ContentLoader,
        source_index: usize,
        target_index: usize,
    ) -> bool {
        let (Some(source), Some(target)) = (
            self.buildings.get(source_index),
            self.buildings.get(target_index),
        ) else {
            return false;
        };
        if source.team != target.team {
            return false;
        }
        if self
            .item_bridge_link(source.tile_pos)
            .is_some_and(|link| link == target.tile_pos)
            && self.item_bridge_link_valid_between(content, source_index, target_index)
        {
            return true;
        }
        let Some(link) = self.item_bridge_link(target.tile_pos) else {
            return false;
        };
        let Some(link_index) = self.item_bridge_link_target_index(content, target_index, link)
        else {
            return false;
        };
        let link_direction = self.relative_direction_between_buildings(target_index, link_index);
        let source_direction =
            self.relative_direction_between_buildings(target_index, source_index);
        link_direction.is_some() && source_direction.is_some() && link_direction != source_direction
    }

    fn first_item_id_from_building(
        &self,
        content: &ContentLoader,
        index: usize,
    ) -> Option<ContentId> {
        let building = self.buildings.get(index)?;
        let items = building.items.as_ref()?;
        content
            .items()
            .iter()
            .map(|item| item.base.mappable.base.id)
            .find(|item_id| items.get(*item_id) > 0)
            .or_else(|| items.each().map(|(item_id, _)| item_id).next())
    }

    pub fn advance_owned_stack_conveyors(
        &mut self,
        content: &ContentLoader,
        delta_seconds: f32,
    ) -> Option<GameRuntimeStackConveyorFrameReport> {
        let advanced = self.state.advance_game_update_frame(delta_seconds);
        if !advanced.advanced {
            return None;
        }
        Some(self.advance_owned_stack_conveyors_ticks(content, advanced.delta_ticks as f32))
    }

    fn advance_owned_stack_conveyors_ticks(
        &mut self,
        content: &ContentLoader,
        frame_delta: f32,
    ) -> GameRuntimeStackConveyorFrameReport {
        let mut report = GameRuntimeStackConveyorFrameReport::default();
        let stack_indices: Vec<_> = self
            .buildings
            .iter()
            .enumerate()
            .filter_map(|(index, building)| {
                report.visited_buildings += 1;
                match content.block(building.block.id) {
                    Some(BlockDef::Distribution(distribution))
                        if distribution.kind == DistributionBlockKind::StackConveyor =>
                    {
                        report.stack_candidates += 1;
                        Some(index)
                    }
                    _ => None,
                }
            })
            .collect();

        for index in stack_indices {
            let Some(BlockDef::Distribution(stack_block)) =
                content.block(self.buildings[index].block.id)
            else {
                continue;
            };
            let tile_pos = self.buildings[index].tile_pos;
            let enabled = self.buildings[index].enabled;
            let efficiency = self.buildings[index].efficiency;
            let eff = if enabled {
                efficiency + stack_block.base_efficiency
            } else {
                1.0
            };
            {
                let state = self.ensure_stack_conveyor_state(tile_pos);
                if state.cooldown > 0.0 {
                    state.cooldown = stack_conveyor_cooldown_step(
                        state.cooldown,
                        stack_block.speed,
                        eff,
                        frame_delta,
                        stack_block.recharge,
                    );
                }
            }

            let mut state = self.stack_conveyor_state(tile_pos);
            if state.link == -1 || state.cooldown > 0.0 {
                self.distribution_runtime_states.insert(
                    tile_pos,
                    GameRuntimeDistributionBlockState::StackConveyor(state),
                );
                report.updated_stacks += 1;
                continue;
            }

            if state.last_item.is_none_or(|item| {
                !self.buildings[index]
                    .items
                    .as_ref()
                    .is_some_and(|items| items.get(item) > 0)
            }) {
                state.last_item = self.first_item_id_from_building(content, index);
            }
            self.distribution_runtime_states.insert(
                tile_pos,
                GameRuntimeDistributionBlockState::StackConveyor(state),
            );

            if !enabled {
                report.updated_stacks += 1;
                continue;
            }

            let state_kind = self.stack_conveyor_state_kind(content, index);
            match state_kind {
                StackConveyorStateKind::Unload => {
                    while let Some(item_id) = self.stack_conveyor_state(tile_pos).last_item {
                        report.attempted_moves += 1;
                        if !self.stack_conveyor_dump_current_item(content, index, item_id) {
                            report.missing_targets += 1;
                            break;
                        }
                        report.dumped_items += 1;
                        if !self.buildings[index]
                            .items
                            .as_ref()
                            .is_some_and(|items| items.get(item_id) > 0)
                        {
                            let state = self.ensure_stack_conveyor_state(tile_pos);
                            state.last_item = None;
                            state.link = -1;
                            break;
                        }
                    }
                }
                StackConveyorStateKind::Move | StackConveyorStateKind::Load => {
                    let should_transfer = state_kind != StackConveyorStateKind::Load
                        || self.buildings[index].items.as_ref().is_some_and(|items| {
                            items.total() >= self.buildings[index].block.item_capacity
                        });
                    if should_transfer {
                        report.attempted_moves += 1;
                        if self.stack_conveyor_transfer_to_front_stack(content, index) {
                            report.moved_stacks += 1;
                        } else {
                            report.missing_targets += 1;
                        }
                    }
                }
            }
            report.updated_stacks += 1;
        }

        report
    }

    fn stack_conveyor_state(&self, tile_pos: i32) -> StackConveyorState {
        match self.distribution_runtime_states.get(&tile_pos) {
            Some(GameRuntimeDistributionBlockState::StackConveyor(state)) => *state,
            _ => StackConveyorState {
                link: -1,
                cooldown: 0.0,
                last_item: None,
            },
        }
    }

    fn ensure_stack_conveyor_state(&mut self, tile_pos: i32) -> &mut StackConveyorState {
        let entry = self
            .distribution_runtime_states
            .entry(tile_pos)
            .or_insert_with(|| {
                GameRuntimeDistributionBlockState::StackConveyor(StackConveyorState {
                    link: -1,
                    cooldown: 0.0,
                    last_item: None,
                })
            });
        let GameRuntimeDistributionBlockState::StackConveyor(state) = entry else {
            *entry = GameRuntimeDistributionBlockState::StackConveyor(StackConveyorState {
                link: -1,
                cooldown: 0.0,
                last_item: None,
            });
            let GameRuntimeDistributionBlockState::StackConveyor(state) = entry else {
                unreachable!("stack conveyor state was just inserted")
            };
            return state;
        };
        state
    }

    fn stack_conveyor_state_kind(
        &self,
        content: &ContentLoader,
        index: usize,
    ) -> StackConveyorStateKind {
        let Some(building) = self.buildings.get(index) else {
            return StackConveyorStateKind::Move;
        };
        let Some(BlockDef::Distribution(stack_block)) = content.block(building.block.id) else {
            return StackConveyorStateKind::Move;
        };
        let front_stack = self
            .neighbor_building_index(index, building.rotation)
            .and_then(|front| self.buildings.get(front))
            .is_some_and(|front| {
                front.team == building.team && front.block.id == building.block.id
            });
        let back_stack = self
            .neighbor_building_index(index, (building.rotation + 2).rem_euclid(4))
            .and_then(|back| self.buildings.get(back))
            .is_some_and(|back| back.team == building.team && back.block.id == building.block.id);
        if front_stack && !back_stack {
            StackConveyorStateKind::Load
        } else if !front_stack && back_stack && stack_block.output_router {
            StackConveyorStateKind::Unload
        } else {
            StackConveyorStateKind::Move
        }
    }

    fn stack_conveyor_dump_current_item(
        &mut self,
        content: &ContentLoader,
        source_index: usize,
        item_id: ContentId,
    ) -> bool {
        let rotation = self.buildings[source_index].rotation;
        if let Some(target_index) = self.neighbor_building_index(source_index, rotation) {
            if self.dump_item_to_target(content, source_index, target_index, item_id) {
                return true;
            }
        }
        self.dump_one_item_from_building(content, source_index)
    }

    fn stack_conveyor_transfer_to_front_stack(
        &mut self,
        content: &ContentLoader,
        source_index: usize,
    ) -> bool {
        let rotation = self.buildings[source_index].rotation;
        let Some(front_index) = self.neighbor_building_index(source_index, rotation) else {
            return false;
        };
        if !matches!(
            content.block(self.buildings[front_index].block.id),
            Some(BlockDef::Distribution(distribution))
                if distribution.kind == DistributionBlockKind::StackConveyor
        ) || self.buildings[front_index].team != self.buildings[source_index].team
        {
            return false;
        }
        let front_tile_pos = self.buildings[front_index].tile_pos;
        if self.stack_conveyor_state(front_tile_pos).link != -1 {
            return false;
        }

        let source_tile_pos = self.buildings[source_index].tile_pos;
        let last_item = self.stack_conveyor_state(source_tile_pos).last_item;
        let source_entries: Vec<_> = self.buildings[source_index]
            .items
            .as_ref()
            .map(|items| items.each().collect())
            .unwrap_or_default();
        if source_entries.is_empty() {
            return false;
        }

        {
            let (source, target) = if source_index < front_index {
                let (left, right) = self.buildings.split_at_mut(front_index);
                (&mut left[source_index], &mut right[0])
            } else {
                let (left, right) = self.buildings.split_at_mut(source_index);
                (&mut right[0], &mut left[front_index])
            };
            let Some(source_items) = source.items.as_mut() else {
                return false;
            };
            let Some(target_items) = target.items.as_mut() else {
                return false;
            };
            if target_items.total() > 0 {
                return false;
            }
            for (item, amount) in &source_entries {
                target_items.add(*item, *amount);
            }
            source_items.clear();
        }

        let recharge = self
            .content_stack_conveyor_recharge(content, source_index)
            .unwrap_or(2.0);
        {
            let source_state = self.ensure_stack_conveyor_state(source_tile_pos);
            source_state.link = -1;
            source_state.cooldown = recharge;
            source_state.last_item = None;
        }
        {
            let target_state = self.ensure_stack_conveyor_state(front_tile_pos);
            target_state.link = source_tile_pos;
            target_state.cooldown = 1.0;
            target_state.last_item =
                last_item.or_else(|| source_entries.first().map(|(item, _)| *item));
        }
        true
    }

    fn content_stack_conveyor_recharge(
        &self,
        content: &ContentLoader,
        index: usize,
    ) -> Option<f32> {
        match content.block(self.buildings.get(index)?.block.id) {
            Some(BlockDef::Distribution(distribution))
                if distribution.kind == DistributionBlockKind::StackConveyor =>
            {
                Some(distribution.recharge)
            }
            _ => None,
        }
    }

    pub fn advance_owned_duct_bridges(
        &mut self,
        content: &ContentLoader,
        delta_seconds: f32,
    ) -> Option<GameRuntimeDuctBridgeFrameReport> {
        let advanced = self.state.advance_game_update_frame(delta_seconds);
        if !advanced.advanced {
            return None;
        }
        Some(self.advance_owned_duct_bridges_ticks(content, advanced.delta_ticks as f32))
    }

    fn advance_owned_duct_bridges_ticks(
        &mut self,
        content: &ContentLoader,
        frame_delta: f32,
    ) -> GameRuntimeDuctBridgeFrameReport {
        let mut report = GameRuntimeDuctBridgeFrameReport::default();
        let bridge_indices: Vec<_> = self
            .buildings
            .iter()
            .enumerate()
            .filter_map(|(index, building)| {
                report.visited_buildings += 1;
                match content.block(building.block.id) {
                    Some(BlockDef::Distribution(distribution))
                        if distribution.kind == DistributionBlockKind::DuctBridge =>
                    {
                        report.bridge_candidates += 1;
                        Some(index)
                    }
                    _ => None,
                }
            })
            .collect();

        for index in bridge_indices.iter().copied() {
            if !self.buildings[index].enabled {
                continue;
            }
            let Some(BlockDef::Distribution(bridge_block)) =
                content.block(self.buildings[index].block.id)
            else {
                continue;
            };
            let tile_pos = self.buildings[index].tile_pos;
            let link_index = self.duct_bridge_find_link_index(content, index);

            if let Some(link_index) = link_index {
                let link_tile_pos = self.buildings[link_index].tile_pos;
                self.ensure_duct_bridge_state(tile_pos).last_link = Some(link_tile_pos);
                let rotation = self.buildings[index].rotation.rem_euclid(4) as usize;
                self.ensure_duct_bridge_state(link_tile_pos).occupied[rotation] = Some(tile_pos);

                if self.buildings[index]
                    .items
                    .as_ref()
                    .is_some_and(|items| items.total() > 0)
                    && self.buildings[link_index]
                        .items
                        .as_ref()
                        .is_some_and(|items| {
                            items.total() < self.buildings[link_index].block.item_capacity
                        })
                {
                    let edelta = frame_delta
                        * self.buildings[index].efficiency
                        * self.buildings[index].time_scale;
                    self.ensure_duct_bridge_state(tile_pos).progress += edelta.max(0.0);
                    while self.duct_bridge_progress(tile_pos) > bridge_block.speed {
                        let Some(item_id) = self.first_item_id_from_building(content, index) else {
                            break;
                        };
                        if self.duct_bridge_transfer_to_link(index, link_index, item_id) {
                            report.moved_items += 1;
                        }
                        self.ensure_duct_bridge_state(tile_pos).progress -= bridge_block.speed;
                        report.attempted_moves += 1;
                    }
                }
            } else {
                self.ensure_duct_bridge_state(tile_pos).last_link = None;
                if let Some(item_id) = self.first_item_id_from_building(content, index) {
                    if let Some(target_index) =
                        self.neighbor_building_index(index, self.buildings[index].rotation)
                    {
                        report.attempted_moves += 1;
                        if self.dump_item_to_target(content, index, target_index, item_id) {
                            report.dumped_items += 1;
                        }
                    } else {
                        report.missing_targets += 1;
                    }
                }
            }

            self.refresh_duct_bridge_occupied(index);
            report.updated_bridges += 1;
        }

        for index in bridge_indices {
            self.refresh_duct_bridge_occupied(index);
        }

        report
    }

    fn duct_bridge_progress(&self, tile_pos: i32) -> f32 {
        match self.distribution_runtime_states.get(&tile_pos) {
            Some(GameRuntimeDistributionBlockState::DuctBridge(state)) => state.progress,
            _ => 0.0,
        }
    }

    fn duct_bridge_transfer_to_link(
        &mut self,
        source_index: usize,
        target_index: usize,
        item_id: ContentId,
    ) -> bool {
        if source_index == target_index
            || source_index >= self.buildings.len()
            || target_index >= self.buildings.len()
            || self.buildings[source_index].team != self.buildings[target_index].team
        {
            return false;
        }

        let (source, target) = if source_index < target_index {
            let (left, right) = self.buildings.split_at_mut(target_index);
            (&mut left[source_index], &mut right[0])
        } else {
            let (left, right) = self.buildings.split_at_mut(source_index);
            (&mut right[0], &mut left[target_index])
        };

        let Some(source_items) = source.items.as_mut() else {
            return false;
        };
        if source_items.get(item_id) <= 0 {
            return false;
        }
        let Some(target_items) = target.items.as_mut() else {
            return false;
        };
        if target_items.total() >= target.block.item_capacity {
            return false;
        }

        source_items.remove(item_id, 1);
        target_items.add(item_id, 1);
        true
    }

    fn ensure_duct_bridge_state(&mut self, tile_pos: i32) -> &mut DuctBridgeState {
        let entry = self
            .distribution_runtime_states
            .entry(tile_pos)
            .or_insert_with(|| {
                GameRuntimeDistributionBlockState::DuctBridge(DuctBridgeState::default())
            });
        let GameRuntimeDistributionBlockState::DuctBridge(state) = entry else {
            *entry = GameRuntimeDistributionBlockState::DuctBridge(DuctBridgeState::default());
            let GameRuntimeDistributionBlockState::DuctBridge(state) = entry else {
                unreachable!("duct bridge state was just inserted")
            };
            return state;
        };
        state
    }

    fn duct_bridge_find_link_index(
        &self,
        content: &ContentLoader,
        source_index: usize,
    ) -> Option<usize> {
        let source = self.buildings.get(source_index)?;
        let Some(BlockDef::Distribution(distribution)) = content.block(source.block.id) else {
            return None;
        };
        if distribution.kind != DistributionBlockKind::DuctBridge {
            return None;
        }
        let (dx, dy) = autotiler_direction(source.rotation);
        let range = distribution.range.max(0.0) as i32;
        for distance in 1..=range {
            let Some(target_ref) = self.state.world.build(
                source.tile_x() + dx * distance,
                source.tile_y() + dy * distance,
            ) else {
                continue;
            };
            let Some(target_index) = self
                .buildings
                .iter()
                .position(|building| building.tile_pos == target_ref.tile_pos)
            else {
                continue;
            };
            let target = &self.buildings[target_index];
            if target.team == source.team && target.block.id == source.block.id {
                return Some(target_index);
            }
        }
        None
    }

    fn duct_bridge_accepts_item(
        &self,
        content: &ContentLoader,
        source_index: usize,
        target_index: usize,
    ) -> bool {
        let (Some(source), Some(target)) = (
            self.buildings.get(source_index),
            self.buildings.get(target_index),
        ) else {
            return false;
        };
        if source.team != target.team || target.items.is_none() {
            return false;
        }
        if self
            .duct_bridge_find_link_index(content, target_index)
            .is_none()
        {
            return false;
        }
        let Some(rel) = self.relative_direction_between_buildings(target_index, source_index)
        else {
            return false;
        };
        if rel == target.rotation {
            return false;
        }
        let occupied_slot = (rel + 2).rem_euclid(4) as usize;
        let occupied = match self.distribution_runtime_states.get(&target.tile_pos) {
            Some(GameRuntimeDistributionBlockState::DuctBridge(state)) => {
                state.occupied[occupied_slot]
            }
            Some(_) => return false,
            None => None,
        };
        occupied.is_none()
            && target
                .items
                .as_ref()
                .is_some_and(|items| items.total() < target.block.item_capacity)
    }

    fn refresh_duct_bridge_occupied(&mut self, bridge_index: usize) {
        let Some(bridge) = self.buildings.get(bridge_index) else {
            return;
        };
        let tile_pos = bridge.tile_pos;
        let Some(GameRuntimeDistributionBlockState::DuctBridge(state)) =
            self.distribution_runtime_states.get(&tile_pos)
        else {
            return;
        };
        let mut occupied = state.occupied;
        for (dir, incoming) in occupied.iter_mut().enumerate() {
            let Some(incoming_tile_pos) = *incoming else {
                continue;
            };
            let Some(incoming_index) = self
                .buildings
                .iter()
                .position(|building| building.tile_pos == incoming_tile_pos)
            else {
                *incoming = None;
                continue;
            };
            let incoming_building = &self.buildings[incoming_index];
            let valid = incoming_building.rotation == dir as i32
                && incoming_building.block.id == bridge.block.id
                && incoming_building.team == bridge.team
                && matches!(
                    self.distribution_runtime_states.get(&incoming_tile_pos),
                    Some(GameRuntimeDistributionBlockState::DuctBridge(incoming_state))
                        if incoming_state.last_link == Some(tile_pos)
                );
            if !valid {
                *incoming = None;
            }
        }
        if let Some(GameRuntimeDistributionBlockState::DuctBridge(state)) =
            self.distribution_runtime_states.get_mut(&tile_pos)
        {
            state.occupied = occupied;
        }
    }

    pub fn advance_owned_item_mass_drivers(
        &mut self,
        content: &ContentLoader,
        delta_seconds: f32,
    ) -> Option<GameRuntimeItemMassDriverFrameReport> {
        let advanced = self.state.advance_game_update_frame(delta_seconds);
        if !advanced.advanced {
            return None;
        }
        Some(self.advance_owned_item_mass_drivers_ticks(content, advanced.delta_ticks as f32))
    }

    fn advance_owned_item_mass_drivers_ticks(
        &mut self,
        content: &ContentLoader,
        frame_delta: f32,
    ) -> GameRuntimeItemMassDriverFrameReport {
        self.refresh_owned_storage_core_links(content);
        let mut report = GameRuntimeItemMassDriverFrameReport::default();
        let flight_report = self.advance_item_mass_driver_in_flight_ticks(content, frame_delta);
        report.transferred_items += flight_report.transferred_items;
        report.despawned_shots += flight_report.despawned_shots;
        report.dropped_items += flight_report.dropped_items;
        report.explosion_events += flight_report.explosion_events;
        let driver_indices: Vec<_> = self
            .buildings
            .iter()
            .enumerate()
            .filter_map(|(index, building)| {
                report.visited_buildings += 1;
                match content.block(building.block.id) {
                    Some(BlockDef::Distribution(distribution))
                        if distribution.kind == DistributionBlockKind::MassDriver =>
                    {
                        report.driver_candidates += 1;
                        Some(index)
                    }
                    _ => None,
                }
            })
            .collect();

        for index in driver_indices {
            let Some(BlockDef::Distribution(driver_block)) =
                content.block(self.buildings[index].block.id)
            else {
                continue;
            };
            let tile_pos = self.buildings[index].tile_pos;
            let efficiency = self.buildings[index].efficiency;
            let time_scale = self.buildings[index].time_scale;
            let reload = self
                .item_mass_driver_reload_counters
                .entry(tile_pos)
                .or_insert(0.0);
            if *reload > 0.0 {
                *reload = (*reload
                    - frame_delta * efficiency.max(0.0) * time_scale.max(0.0)
                        / driver_block.reload.max(0.0001))
                .clamp(0.0, 1.0);
            }

            let mut state = self.ensure_item_mass_driver_state(tile_pos);
            let link_index = self.item_mass_driver_link_target_index(content, index, state.link);
            let waiting_shooters = self.prune_item_mass_driver_waiting_shooters(content, tile_pos);
            let current_shooter_index = waiting_shooters
                .first()
                .and_then(|shooter_tile| self.building_index_by_tile_pos(*shooter_tile));
            let waiting_shooters_empty = waiting_shooters.is_empty();
            let mut available_space = self.buildings[index].block.item_capacity
                - self
                    .buildings
                    .get(index)
                    .and_then(|building| building.items.as_ref())
                    .map(|items| items.total())
                    .unwrap_or(0);
            if link_index.is_some() && state.state == MassDriverStateKind::Idle {
                if !waiting_shooters_empty && available_space >= driver_block.min_distribute {
                    state.state = MassDriverStateKind::Accepting;
                } else {
                    state.state = MassDriverStateKind::Shooting;
                }
            } else if state.state == MassDriverStateKind::Idle
                && !waiting_shooters_empty
                && available_space >= driver_block.min_distribute
            {
                state.state = MassDriverStateKind::Accepting;
            }
            if (state.state == MassDriverStateKind::Idle
                || state.state == MassDriverStateKind::Accepting)
                && self.dump_one_item_from_building(content, index)
            {
                report.dumped_items += 1;
                available_space = self.buildings[index].block.item_capacity
                    - self
                        .buildings
                        .get(index)
                        .and_then(|building| building.items.as_ref())
                        .map(|items| items.total())
                        .unwrap_or(0);
            }
            if efficiency <= 0.0 {
                self.distribution_runtime_states.insert(
                    tile_pos,
                    GameRuntimeDistributionBlockState::MassDriver(state),
                );
                report.updated_drivers += 1;
                continue;
            }

            if state.state == MassDriverStateKind::Accepting {
                if current_shooter_index.is_none() || available_space < driver_block.min_distribute
                {
                    state.state = MassDriverStateKind::Idle;
                    self.distribution_runtime_states.insert(
                        tile_pos,
                        GameRuntimeDistributionBlockState::MassDriver(state),
                    );
                    report.updated_drivers += 1;
                    continue;
                }

                let shooter_index = current_shooter_index.expect("checked above");
                state.rotation = Self::move_toward_angle(
                    state.rotation,
                    self.angle_between_buildings(index, shooter_index),
                    driver_block.rotate_speed * efficiency.max(0.0) * frame_delta.max(0.0),
                );
            }

            if state.state == MassDriverStateKind::Shooting {
                let Some(link_index) = link_index else {
                    state.state = MassDriverStateKind::Idle;
                    self.distribution_runtime_states.insert(
                        tile_pos,
                        GameRuntimeDistributionBlockState::MassDriver(state),
                    );
                    report.missing_targets += 1;
                    report.updated_drivers += 1;
                    continue;
                };
                if !waiting_shooters_empty && available_space >= driver_block.min_distribute {
                    state.state = MassDriverStateKind::Idle;
                    self.distribution_runtime_states.insert(
                        tile_pos,
                        GameRuntimeDistributionBlockState::MassDriver(state),
                    );
                    report.updated_drivers += 1;
                    continue;
                }
                let target_capacity = self.buildings[link_index].block.item_capacity;
                let source_total = self.buildings[index]
                    .items
                    .as_ref()
                    .map(|items| items.total())
                    .unwrap_or(0);
                let target_total = self.buildings[link_index]
                    .items
                    .as_ref()
                    .map(|items| items.total())
                    .unwrap_or(0);
                if source_total >= driver_block.min_distribute
                    && target_capacity - target_total >= driver_block.min_distribute
                    && self
                        .item_mass_driver_reload_counters
                        .get(&tile_pos)
                        .copied()
                        .unwrap_or(0.0)
                        <= 0.0001
                {
                    report.attempted_shots += 1;
                    self.add_item_mass_driver_waiting_shooter(
                        self.buildings[link_index].tile_pos,
                        tile_pos,
                    );
                    let target_rotation = self.angle_between_buildings(index, link_index);
                    state.rotation = Self::move_toward_angle(
                        state.rotation,
                        target_rotation,
                        driver_block.rotate_speed * efficiency.max(0.0) * frame_delta.max(0.0),
                    );
                    let target_waiting = self.prune_item_mass_driver_waiting_shooters(
                        content,
                        self.buildings[link_index].tile_pos,
                    );
                    let target_state =
                        self.ensure_item_mass_driver_state(self.buildings[link_index].tile_pos);
                    let target_ready = target_waiting.first().copied() == Some(tile_pos)
                        && target_state.state == MassDriverStateKind::Accepting
                        && Self::angle_near(state.rotation, target_rotation, 2.0)
                        && Self::angle_near(target_state.rotation, target_rotation + 180.0, 2.0);
                    let moved = if target_ready {
                        self.item_mass_driver_fire_to_link(content, index, link_index)
                    } else {
                        0
                    };
                    if moved > 0 {
                        report.shots_fired += 1;
                        self.item_mass_driver_reload_counters.insert(tile_pos, 1.0);
                        state.state = MassDriverStateKind::Idle;
                    }
                }
            }

            self.distribution_runtime_states.insert(
                tile_pos,
                GameRuntimeDistributionBlockState::MassDriver(state),
            );
            report.updated_drivers += 1;
        }

        report
    }

    fn advance_item_mass_driver_in_flight_ticks(
        &mut self,
        content: &ContentLoader,
        frame_delta: f32,
    ) -> GameRuntimeItemMassDriverFrameReport {
        if self.item_mass_driver_in_flight.is_empty() {
            return GameRuntimeItemMassDriverFrameReport::default();
        }

        let mut report = GameRuntimeItemMassDriverFrameReport::default();
        let mut pending = Vec::new();
        let bolt = MassDriverBolt::default();
        for mut shot in std::mem::take(&mut self.item_mass_driver_in_flight) {
            let delta = frame_delta.max(0.0);
            shot.elapsed_ticks = (shot.elapsed_ticks + delta).max(0.0);
            shot.remaining_ticks = (shot.travel_ticks - shot.elapsed_ticks).max(0.0);
            shot.expire_ticks -= delta;
            Self::update_item_mass_driver_shot_position(&mut shot);
            if !shot.target_lost
                && self
                    .item_mass_driver_in_flight_target_index(content, &shot)
                    .is_none()
            {
                shot.target_lost = true;
            }

            let plan = bolt.update_plan(
                shot.x,
                shot.y,
                shot.from_x,
                shot.from_y,
                shot.to_x,
                shot.to_y,
                shot.target_lost,
            );
            if let Some((x, y)) = plan.snap_position {
                shot.x = x;
                shot.y = y;
            }
            if plan.hit && !shot.target_lost {
                report.transferred_items +=
                    self.resolve_item_mass_driver_in_flight_shot(content, &shot);
                continue;
            }
            if shot.expire_ticks > 0.0 {
                pending.push(shot);
                continue;
            }

            self.remove_item_mass_driver_waiting_shooter(shot.to_tile, shot.from_tile);
            let event = self.create_item_mass_driver_despawn_event(content, &shot);
            report.dropped_items += event
                .drops
                .iter()
                .map(|drop| drop.amount_dropped.max(0) as usize)
                .sum::<usize>();
            report.despawned_shots += 1;
            report.explosion_events += 1;
            self.item_mass_driver_despawn_events.push(event);
        }
        self.item_mass_driver_in_flight = pending;
        report
    }

    fn update_item_mass_driver_shot_position(shot: &mut GameRuntimeItemMassDriverInFlight) {
        let distance = shot.speed.max(0.0) * shot.elapsed_ticks.max(0.0);
        shot.x = shot.from_x + Self::angle_trnsx(shot.rotation, distance);
        shot.y = shot.from_y + Self::angle_trnsy(shot.rotation, distance);
    }

    fn create_item_mass_driver_despawn_event(
        &self,
        content: &ContentLoader,
        shot: &GameRuntimeItemMassDriverInFlight,
    ) -> GameRuntimeItemMassDriverDespawnEvent {
        let mut item_amounts = vec![0; content.items().len()];
        for (item_id, amount) in &shot.items {
            if *item_id >= 0 {
                let index = *item_id as usize;
                if let Some(slot) = item_amounts.get_mut(index) {
                    *slot += (*amount).max(0);
                }
            }
        }
        let bolt = MassDriverBolt::default();
        let random_angle_offsets = vec![0.0; item_amounts.len()];
        let drops = bolt.despawn_drop_plans(
            &item_amounts,
            &item_amounts,
            shot.rotation,
            &random_angle_offsets,
        );
        let explosion = bolt.dynamic_explosion_plan(
            content.items(),
            &item_amounts,
            self.state.rules.damage_explosions,
        );
        GameRuntimeItemMassDriverDespawnEvent {
            from_tile: shot.from_tile,
            to_tile: shot.to_tile,
            drops,
            explosion,
        }
    }

    fn item_mass_driver_in_flight_target_index(
        &self,
        content: &ContentLoader,
        shot: &GameRuntimeItemMassDriverInFlight,
    ) -> Option<usize> {
        let target_index = self.building_index_by_tile_pos(shot.to_tile)?;
        let target = &self.buildings[target_index];
        if target.block.id != shot.to_block_id || target.team != shot.to_team {
            return None;
        }
        let Some(BlockDef::Distribution(distribution)) = content.block(target.block.id) else {
            return None;
        };
        (distribution.kind == DistributionBlockKind::MassDriver).then_some(target_index)
    }

    fn resolve_item_mass_driver_in_flight_shot(
        &mut self,
        content: &ContentLoader,
        shot: &GameRuntimeItemMassDriverInFlight,
    ) -> usize {
        let Some(target_index) = self.item_mass_driver_in_flight_target_index(content, shot) else {
            self.remove_item_mass_driver_waiting_shooter(shot.to_tile, shot.from_tile);
            return 0;
        };
        let Some(BlockDef::Distribution(target_block)) =
            content.block(self.buildings[target_index].block.id)
        else {
            self.remove_item_mass_driver_waiting_shooter(shot.to_tile, shot.from_tile);
            return 0;
        };
        let receive_event = GameRuntimeItemMassDriverReceiveEvent {
            from_tile: shot.from_tile,
            to_tile: shot.to_tile,
            x: shot.to_x,
            y: shot.to_y,
            receive_effect: target_block.receive_effect.clone(),
            receive_sound: target_block.receive_sound.clone(),
            shoot_sound_volume: target_block.shoot_sound_volume,
            shake: target_block.shake,
        };

        let target_capacity = self.buildings[target_index].block.item_capacity * 2;
        let target_total = self.buildings[target_index]
            .items
            .as_ref()
            .map(|items| items.total())
            .unwrap_or(0);
        let mut remaining_space = (target_capacity - target_total).max(0);
        let Some(target_items) = self.buildings[target_index].items.as_mut() else {
            self.remove_item_mass_driver_waiting_shooter(shot.to_tile, shot.from_tile);
            return 0;
        };

        let mut delivered = 0;
        for (item_id, amount) in &shot.items {
            if remaining_space <= 0 {
                break;
            }
            let add = (*amount).min(remaining_space);
            if add > 0 {
                target_items.add(*item_id, add);
                remaining_space -= add;
                delivered += add as usize;
            }
        }

        self.item_mass_driver_reload_counters
            .insert(shot.to_tile, 1.0);
        let mut target_state = self.ensure_item_mass_driver_state(shot.to_tile);
        target_state.state = MassDriverStateKind::Idle;
        self.remove_item_mass_driver_waiting_shooter(shot.to_tile, shot.from_tile);
        self.distribution_runtime_states.insert(
            shot.to_tile,
            GameRuntimeDistributionBlockState::MassDriver(target_state),
        );
        self.item_mass_driver_receive_events.push(receive_event);
        delivered
    }

    fn ensure_item_mass_driver_state(&mut self, tile_pos: i32) -> MassDriverState {
        match self.distribution_runtime_states.get(&tile_pos) {
            Some(GameRuntimeDistributionBlockState::MassDriver(state)) => *state,
            _ => {
                let state = MassDriverState {
                    link: -1,
                    rotation: 90.0,
                    state: MassDriverStateKind::Idle,
                };
                self.distribution_runtime_states.insert(
                    tile_pos,
                    GameRuntimeDistributionBlockState::MassDriver(state),
                );
                state
            }
        }
    }

    fn item_mass_driver_link_target_index(
        &self,
        content: &ContentLoader,
        source_index: usize,
        link: i32,
    ) -> Option<usize> {
        if link < 0 {
            return None;
        }
        let source = self.buildings.get(source_index)?;
        let target_index = self
            .buildings
            .iter()
            .position(|building| building.tile_pos == link)?;
        let target = &self.buildings[target_index];
        let Some(BlockDef::Distribution(distribution)) = content.block(source.block.id) else {
            return None;
        };
        mass_driver_link_valid(
            true,
            source.block.id == target.block.id,
            source.team == target.team,
            self.distance_between_buildings(source_index, target_index),
            distribution.range,
        )
        .then_some(target_index)
    }

    fn prune_item_mass_driver_waiting_shooters(
        &mut self,
        content: &ContentLoader,
        receiver_tile_pos: i32,
    ) -> Vec<i32> {
        let Some(waiting) = self
            .item_mass_driver_waiting_shooters
            .get(&receiver_tile_pos)
            .cloned()
        else {
            return Vec::new();
        };

        let mut cleaned = Vec::new();
        for shooter_tile_pos in waiting {
            if !cleaned.contains(&shooter_tile_pos)
                && self.item_mass_driver_shooter_valid(content, receiver_tile_pos, shooter_tile_pos)
            {
                cleaned.push(shooter_tile_pos);
            }
        }

        if cleaned.is_empty() {
            self.item_mass_driver_waiting_shooters
                .remove(&receiver_tile_pos);
        } else {
            self.item_mass_driver_waiting_shooters
                .insert(receiver_tile_pos, cleaned.clone());
        }
        cleaned
    }

    fn item_mass_driver_shooter_valid(
        &self,
        content: &ContentLoader,
        receiver_tile_pos: i32,
        shooter_tile_pos: i32,
    ) -> bool {
        let Some(receiver_index) = self.building_index_by_tile_pos(receiver_tile_pos) else {
            return false;
        };
        let Some(shooter_index) = self.building_index_by_tile_pos(shooter_tile_pos) else {
            return false;
        };
        let receiver = &self.buildings[receiver_index];
        let shooter = &self.buildings[shooter_index];
        if shooter.efficiency <= 0.0
            || shooter.block.id != receiver.block.id
            || shooter.team != receiver.team
        {
            return false;
        }
        let Some(GameRuntimeDistributionBlockState::MassDriver(shooter_state)) =
            self.distribution_runtime_states.get(&shooter_tile_pos)
        else {
            return false;
        };
        if shooter_state.link != receiver_tile_pos {
            return false;
        }
        let Some(BlockDef::Distribution(driver_block)) = content.block(receiver.block.id) else {
            return false;
        };
        self.distance_between_buildings(receiver_index, shooter_index) <= driver_block.range
    }

    fn add_item_mass_driver_waiting_shooter(
        &mut self,
        receiver_tile_pos: i32,
        shooter_tile_pos: i32,
    ) {
        let waiting = self
            .item_mass_driver_waiting_shooters
            .entry(receiver_tile_pos)
            .or_default();
        if !waiting.contains(&shooter_tile_pos) {
            waiting.push(shooter_tile_pos);
        }
    }

    fn remove_item_mass_driver_waiting_shooter(
        &mut self,
        receiver_tile_pos: i32,
        shooter_tile_pos: i32,
    ) {
        if let Some(waiting) = self
            .item_mass_driver_waiting_shooters
            .get_mut(&receiver_tile_pos)
        {
            waiting.retain(|queued| *queued != shooter_tile_pos);
            if waiting.is_empty() {
                self.item_mass_driver_waiting_shooters
                    .remove(&receiver_tile_pos);
            }
        }
    }

    fn remove_item_mass_driver_waiting_shooter_from_all(&mut self, shooter_tile_pos: i32) {
        self.item_mass_driver_waiting_shooters.retain(|_, waiting| {
            waiting.retain(|queued| *queued != shooter_tile_pos);
            !waiting.is_empty()
        });
    }

    fn distance_between_buildings(&self, from_index: usize, to_index: usize) -> f32 {
        let (Some(from), Some(to)) = (self.buildings.get(from_index), self.buildings.get(to_index))
        else {
            return f32::INFINITY;
        };
        let dx = from.x - to.x;
        let dy = from.y - to.y;
        (dx * dx + dy * dy).sqrt()
    }

    fn angle_between_buildings(&self, from_index: usize, to_index: usize) -> f32 {
        let (Some(from), Some(to)) = (self.buildings.get(from_index), self.buildings.get(to_index))
        else {
            return 90.0;
        };
        let mut angle = (to.y - from.y).atan2(to.x - from.x).to_degrees();
        if angle < 0.0 {
            angle += 360.0;
        }
        angle
    }

    fn angle_trnsx(angle: f32, len: f32) -> f32 {
        angle.to_radians().cos() * len
    }

    fn angle_trnsy(angle: f32, len: f32) -> f32 {
        angle.to_radians().sin() * len
    }

    fn move_toward_angle(from: f32, to: f32, amount: f32) -> f32 {
        let delta = Self::angle_delta(from, to);
        if delta.abs() <= amount {
            Self::normalize_angle(to)
        } else {
            Self::normalize_angle(from + delta.signum() * amount)
        }
    }

    fn angle_near(a: f32, b: f32, margin: f32) -> bool {
        Self::angle_delta(a, b).abs() <= margin
    }

    fn angle_delta(from: f32, to: f32) -> f32 {
        let mut delta = (to - from) % 360.0;
        if delta > 180.0 {
            delta -= 360.0;
        }
        if delta < -180.0 {
            delta += 360.0;
        }
        delta
    }

    fn normalize_angle(value: f32) -> f32 {
        let mut angle = value % 360.0;
        if angle < 0.0 {
            angle += 360.0;
        }
        angle
    }

    fn item_mass_driver_fire_to_link(
        &mut self,
        content: &ContentLoader,
        source_index: usize,
        target_index: usize,
    ) -> i32 {
        if source_index == target_index
            || source_index >= self.buildings.len()
            || target_index >= self.buildings.len()
        {
            return 0;
        }
        let source_capacity = self.buildings[source_index].block.item_capacity;
        let Some(BlockDef::Distribution(driver_block)) =
            content.block(self.buildings[source_index].block.id)
        else {
            return 0;
        };
        let source_tile = self.buildings[source_index].tile_pos;
        let target_tile = self.buildings[target_index].tile_pos;
        let rotation = self.angle_between_buildings(source_index, target_index);
        let (from_x, from_y) = (
            self.buildings[source_index].x + Self::angle_trnsx(rotation, driver_block.translation),
            self.buildings[source_index].y + Self::angle_trnsy(rotation, driver_block.translation),
        );
        let (to_x, to_y) = (
            self.buildings[target_index].x,
            self.buildings[target_index].y,
        );
        let time_to_arrive = mass_driver_time_to_arrive(
            self.distance_between_buildings(source_index, target_index),
            driver_block.bullet_speed,
            driver_block.bullet_lifetime,
        );
        let mut total_used = 0;
        let mut entries = Vec::new();
        for item in content.items() {
            let item_id = item.base.mappable.base.id;
            let amount = self.buildings[source_index]
                .items
                .as_ref()
                .map(|items| items.get(item_id))
                .unwrap_or(0);
            let move_amount = amount.min(source_capacity - total_used);
            if move_amount > 0 {
                entries.push((item_id, move_amount));
                total_used += move_amount;
            }
            if total_used >= source_capacity {
                break;
            }
        }
        if entries.is_empty() {
            return 0;
        }

        let Some(source_items) = self.buildings[source_index].items.as_mut() else {
            return 0;
        };
        for (item_id, amount) in &entries {
            source_items.remove(*item_id, *amount);
        }
        self.item_mass_driver_in_flight
            .push(GameRuntimeItemMassDriverInFlight {
                from_tile: source_tile,
                to_tile: target_tile,
                to_block_id: self.buildings[target_index].block.id,
                to_team: self.buildings[target_index].team,
                from_x,
                from_y,
                to_x,
                to_y,
                x: from_x,
                y: from_y,
                rotation,
                speed: driver_block.bullet_speed,
                travel_ticks: time_to_arrive,
                remaining_ticks: time_to_arrive,
                elapsed_ticks: 0.0,
                lifetime_ticks: driver_block.bullet_lifetime,
                expire_ticks: driver_block.bullet_lifetime,
                target_lost: false,
                items: entries,
            });
        self.item_mass_driver_shoot_events
            .push(GameRuntimeItemMassDriverShootEvent {
                from_tile: source_tile,
                to_tile: target_tile,
                x: from_x,
                y: from_y,
                shoot_effect: driver_block.shoot_effect.clone(),
                smoke_effect: driver_block.smoke_effect.clone(),
                shoot_sound: driver_block.shoot_sound.clone(),
                shoot_sound_volume: driver_block.shoot_sound_volume,
                shake: driver_block.shake,
            });
        total_used
    }

    pub fn advance_owned_item_unloaders(
        &mut self,
        content: &ContentLoader,
        delta_seconds: f32,
    ) -> Option<GameRuntimeItemUnloaderFrameReport> {
        let advanced = self.state.advance_game_update_frame(delta_seconds);
        if !advanced.advanced {
            return None;
        }
        Some(self.advance_owned_item_unloaders_ticks(content, advanced.delta_ticks as f32))
    }

    fn advance_owned_item_unloaders_ticks(
        &mut self,
        content: &ContentLoader,
        frame_delta: f32,
    ) -> GameRuntimeItemUnloaderFrameReport {
        self.refresh_owned_storage_core_links(content);
        let mut report = GameRuntimeItemUnloaderFrameReport::default();
        let unloader_indices: Vec<_> = self
            .buildings
            .iter()
            .enumerate()
            .filter_map(|(index, building)| {
                report.visited_buildings += 1;
                match content.block(building.block.id) {
                    Some(BlockDef::Distribution(distribution))
                        if distribution.kind == DistributionBlockKind::Unloader =>
                    {
                        report.unloader_candidates += 1;
                        Some(index)
                    }
                    _ => None,
                }
            })
            .collect();

        for index in unloader_indices {
            let Some(BlockDef::Distribution(unloader_block)) =
                content.block(self.buildings[index].block.id)
            else {
                continue;
            };
            if !self.buildings[index].enabled {
                continue;
            }
            let tile_pos = self.buildings[index].tile_pos;
            let possible_neighbors =
                self.item_unloader_possible_neighbor_indices(content, index, unloader_block);
            let delta = frame_delta * self.buildings[index].time_scale.max(0.0);
            let previous_timer = self
                .item_unloader_timers
                .get(&tile_pos)
                .copied()
                .unwrap_or(0.0);
            let ready_timer = previous_timer + delta;
            if ready_timer < unloader_block.speed || possible_neighbors.len() < 2 {
                self.item_unloader_timers.insert(tile_pos, ready_timer);
                report.updated_unloaders += 1;
                continue;
            }

            let Some(item_id) =
                self.item_unloader_select_item(content, index, unloader_block, &possible_neighbors)
            else {
                let update = unloader_update_timer(
                    previous_timer,
                    delta,
                    unloader_block.speed,
                    possible_neighbors.len(),
                    false,
                );
                self.item_unloader_timers
                    .insert(tile_pos, update.unload_timer);
                report.missing_partners += 1;
                report.updated_unloaders += 1;
                continue;
            };
            report.selected_items += 1;
            self.item_unloader_rotations.insert(tile_pos, item_id);

            report.attempted_trades += 1;
            let traded = self.item_unloader_trade_item(
                content,
                index,
                unloader_block,
                &possible_neighbors,
                item_id,
            );
            if traded {
                report.moved_items += 1;
                report.item_taken_events += 1;
            } else {
                report.blocked_trades += 1;
            }
            let update = unloader_update_timer(
                previous_timer,
                delta,
                unloader_block.speed,
                possible_neighbors.len(),
                traded,
            );
            self.item_unloader_timers
                .insert(tile_pos, update.unload_timer);
            report.updated_unloaders += 1;
        }

        report
    }

    fn item_unloader_sort_item(&self, tile_pos: i32) -> Option<ContentId> {
        match self.distribution_runtime_states.get(&tile_pos) {
            Some(GameRuntimeDistributionBlockState::Unloader(sort_item)) => *sort_item,
            _ => None,
        }
    }

    fn item_unloader_possible_neighbor_indices(
        &self,
        content: &ContentLoader,
        unloader_index: usize,
        unloader_block: &crate::mindustry::content::blocks::DistributionBlockData,
    ) -> Vec<usize> {
        let mut indices = Vec::new();
        for other_ref in &self.buildings[unloader_index].proximity {
            let Some(other_index) = self
                .buildings
                .iter()
                .position(|building| building.tile_pos == other_ref.tile_pos)
            else {
                continue;
            };
            let other = &self.buildings[other_index];
            if other.team != self.buildings[unloader_index].team {
                continue;
            }
            let Some(other_block) = content.block(other.block.id) else {
                continue;
            };
            let can_load = !matches!(other_block, BlockDef::Storage(_));
            let can_unload =
                self.item_unloader_can_unload_from(content, unloader_block, other_index, None);
            if can_load || can_unload {
                indices.push(other_index);
            }
        }
        indices
    }

    fn item_unloader_can_unload_from(
        &self,
        content: &ContentLoader,
        unloader_block: &crate::mindustry::content::blocks::DistributionBlockData,
        source_index: usize,
        item_id: Option<ContentId>,
    ) -> bool {
        if source_index >= self.buildings.len() {
            return false;
        }
        let item_owner_index = self.item_module_owner_index(content, source_index);
        let Some(source_items) = self
            .buildings
            .get(item_owner_index)
            .and_then(|building| building.items.as_ref())
        else {
            return false;
        };
        if let Some(item_id) = item_id {
            if source_items.get(item_id) <= 0 {
                return false;
            }
        } else if source_items.empty() {
            return false;
        }
        let Some(source_block) = content.block(self.buildings[source_index].block.id) else {
            return false;
        };
        if !Self::payload_block_unloadable(source_block) {
            return false;
        }
        match source_block {
            BlockDef::Storage(storage) if storage.kind == StorageBlockKind::Core => {
                unloader_block.allow_core_unload
            }
            BlockDef::Storage(storage)
                if storage.kind == StorageBlockKind::Storage
                    && self
                        .linked_core_index_for_storage(content, source_index)
                        .is_some() =>
            {
                unloader_block.allow_core_unload
            }
            BlockDef::Storage(_) => true,
            _ => true,
        }
    }

    fn item_unloader_select_item(
        &self,
        content: &ContentLoader,
        unloader_index: usize,
        unloader_block: &crate::mindustry::content::blocks::DistributionBlockData,
        possible_neighbors: &[usize],
    ) -> Option<ContentId> {
        let tile_pos = self.buildings[unloader_index].tile_pos;
        if let Some(sort_item) = self.item_unloader_sort_item(tile_pos) {
            return self
                .item_unloader_item_possible(
                    content,
                    unloader_index,
                    unloader_block,
                    possible_neighbors,
                    sort_item,
                )
                .then_some(sort_item);
        }

        let items = content.items();
        if items.is_empty() {
            return None;
        }
        let rotations = self
            .item_unloader_rotations
            .get(&tile_pos)
            .copied()
            .unwrap_or(0) as i32;
        for offset in 0..items.len() {
            let index = (rotations + offset as i32 + 1).rem_euclid(items.len() as i32) as usize;
            let item_id = items[index].base.mappable.base.id;
            if self.item_unloader_item_possible(
                content,
                unloader_index,
                unloader_block,
                possible_neighbors,
                item_id,
            ) {
                return Some(item_id);
            }
        }
        None
    }

    fn item_unloader_item_possible(
        &self,
        content: &ContentLoader,
        unloader_index: usize,
        unloader_block: &crate::mindustry::content::blocks::DistributionBlockData,
        possible_neighbors: &[usize],
        item_id: ContentId,
    ) -> bool {
        let mut stats = Vec::new();
        for &other_index in possible_neighbors {
            stats.push(self.item_unloader_container_stat(
                content,
                unloader_index,
                unloader_block,
                other_index,
                item_id,
                0,
            ));
        }
        unloader_possible_item(&mut stats)
    }

    fn item_unloader_container_stat(
        &self,
        content: &ContentLoader,
        unloader_index: usize,
        unloader_block: &crate::mindustry::content::blocks::DistributionBlockData,
        other_index: usize,
        item_id: ContentId,
        last_used: i32,
    ) -> ContainerStat {
        let other = &self.buildings[other_index];
        let other_block = content.block(other.block.id);
        let not_storage = !matches!(other_block, Some(BlockDef::Storage(_)));
        let can_load = not_storage
            && self.dump_target_accepts_item(content, unloader_index, other_index, item_id);
        let can_unload =
            self.item_unloader_can_unload_from(content, unloader_block, other_index, Some(item_id));
        let max_accepted = self.item_unloader_maximum_accepted(other_index);
        let load_factor = if max_accepted == 0 {
            0.0
        } else {
            other
                .items
                .as_ref()
                .map(|items| items.get(item_id) as f32 / max_accepted as f32)
                .unwrap_or(0.0)
        };
        ContainerStat {
            can_load,
            can_unload,
            not_storage,
            load_factor,
            last_used,
        }
    }

    fn item_unloader_maximum_accepted(&self, building_index: usize) -> i32 {
        let owner_index = self
            .buildings
            .get(building_index)
            .and_then(|building| {
                self.storage_linked_cores
                    .get(&building.tile_pos)
                    .and_then(|core_tile| {
                        self.buildings
                            .iter()
                            .position(|candidate| candidate.tile_pos == *core_tile)
                    })
            })
            .unwrap_or(building_index);
        self.maximum_accepted_for_item_owner(owner_index)
    }

    fn item_unloader_trade_item(
        &mut self,
        content: &ContentLoader,
        unloader_index: usize,
        unloader_block: &crate::mindustry::content::blocks::DistributionBlockData,
        possible_neighbors: &[usize],
        item_id: ContentId,
    ) -> bool {
        let unloader_tile = self.buildings[unloader_index].tile_pos;
        let mut candidates: Vec<(usize, ContainerStat)> = possible_neighbors
            .iter()
            .copied()
            .map(|other_index| {
                let other_tile = self.buildings[other_index].tile_pos;
                let next_last = self
                    .item_unloader_last_used
                    .get(&(unloader_tile, other_tile))
                    .copied()
                    .unwrap_or(0)
                    .saturating_add(1);
                self.item_unloader_last_used
                    .insert((unloader_tile, other_tile), next_last);
                (
                    other_index,
                    self.item_unloader_container_stat(
                        content,
                        unloader_index,
                        unloader_block,
                        other_index,
                        item_id,
                        next_last,
                    ),
                )
            })
            .collect();
        candidates.sort_by_key(|(_, stat)| unloader_sort_key(stat));

        let dumping_to = candidates
            .iter()
            .find_map(|(index, stat)| stat.can_load.then_some((*index, *stat)));
        let dumping_from = candidates
            .iter()
            .rev()
            .find_map(|(index, stat)| stat.can_unload.then_some((*index, *stat)));
        let (Some((to_index, to_stat)), Some((from_index, from_stat))) = (dumping_to, dumping_from)
        else {
            return false;
        };
        if from_index == to_index {
            return false;
        }
        if (from_stat.load_factor - to_stat.load_factor).abs() <= f32::EPSILON && from_stat.can_load
        {
            return false;
        }
        if !self.item_unloader_transfer_item(content, unloader_index, from_index, to_index, item_id)
        {
            return false;
        }

        let to_tile = self.buildings[to_index].tile_pos;
        let from_tile = self.buildings[from_index].tile_pos;
        self.item_unloader_last_used
            .insert((unloader_tile, to_tile), 0);
        self.item_unloader_last_used
            .insert((unloader_tile, from_tile), 0);
        true
    }

    fn item_unloader_transfer_item(
        &mut self,
        content: &ContentLoader,
        unloader_index: usize,
        from_index: usize,
        to_index: usize,
        item_id: ContentId,
    ) -> bool {
        let from_item_owner_index = self.item_module_owner_index(content, from_index);
        if unloader_index >= self.buildings.len()
            || from_index >= self.buildings.len()
            || from_item_owner_index >= self.buildings.len()
            || to_index >= self.buildings.len()
            || !self.buildings[from_item_owner_index]
                .items
                .as_ref()
                .is_some_and(|items| items.get(item_id) > 0)
            || !self.dump_target_accepts_item(content, unloader_index, to_index, item_id)
        {
            return false;
        }

        let Some(unloader_items) = self.buildings[unloader_index].items.as_mut() else {
            return false;
        };
        unloader_items.add(item_id, 1);
        if !self.dump_item_to_target(content, unloader_index, to_index, item_id) {
            if let Some(unloader_items) = self.buildings[unloader_index].items.as_mut() {
                if unloader_items.get(item_id) > 0 {
                    unloader_items.remove(item_id, 1);
                }
            }
            return false;
        }
        if let Some(source_items) = self.buildings[from_item_owner_index].items.as_mut() {
            source_items.remove(item_id, 1);
        }
        self.record_item_taken(content, from_index, item_id);
        true
    }

    pub fn advance_owned_directional_unloaders(
        &mut self,
        content: &ContentLoader,
        delta_seconds: f32,
    ) -> Option<GameRuntimeDirectionalUnloaderFrameReport> {
        let advanced = self.state.advance_game_update_frame(delta_seconds);
        if !advanced.advanced {
            return None;
        }
        Some(self.advance_owned_directional_unloaders_ticks(content, advanced.delta_ticks as f32))
    }

    fn advance_owned_directional_unloaders_ticks(
        &mut self,
        content: &ContentLoader,
        frame_delta: f32,
    ) -> GameRuntimeDirectionalUnloaderFrameReport {
        self.refresh_owned_storage_core_links(content);
        let mut report = GameRuntimeDirectionalUnloaderFrameReport::default();
        let unloader_indices: Vec<_> = self
            .buildings
            .iter()
            .enumerate()
            .filter_map(|(index, building)| {
                report.visited_buildings += 1;
                match content.block(building.block.id) {
                    Some(BlockDef::Distribution(distribution))
                        if distribution.kind == DistributionBlockKind::DirectionalUnloader =>
                    {
                        report.unloader_candidates += 1;
                        Some(index)
                    }
                    _ => None,
                }
            })
            .collect();

        for index in unloader_indices {
            let Some(BlockDef::Distribution(unloader_block)) =
                content.block(self.buildings[index].block.id)
            else {
                continue;
            };
            if !self.buildings[index].enabled {
                continue;
            }

            let tile_pos = self.buildings[index].tile_pos;
            let edelta = frame_delta
                * self.buildings[index].efficiency.max(0.0)
                * self.buildings[index].time_scale.max(0.0);
            let timer = self
                .item_directional_unloader_timers
                .entry(tile_pos)
                .or_insert(0.0);
            *timer += edelta;
            if *timer < unloader_block.speed {
                report.updated_unloaders += 1;
                continue;
            }

            report.attempted_moves += 1;
            let moved = self.directional_unloader_try_move(content, index, unloader_block);
            if moved {
                let timer = self
                    .item_directional_unloader_timers
                    .entry(tile_pos)
                    .or_insert(0.0);
                *timer %= unloader_block.speed.max(0.0001);
                report.moved_items += 1;
                report.item_taken_events += 1;
            } else {
                let timer = self
                    .item_directional_unloader_timers
                    .entry(tile_pos)
                    .or_insert(0.0);
                *timer = (*timer).min(unloader_block.speed);
                if self
                    .directional_unloader_front_back(content, index)
                    .is_some()
                {
                    report.blocked_sources += 1;
                } else {
                    report.missing_targets += 1;
                }
            }
            report.updated_unloaders += 1;
        }

        report
    }

    fn directional_unloader_front_back(
        &self,
        content: &ContentLoader,
        unloader_index: usize,
    ) -> Option<(usize, usize)> {
        let unloader = self.buildings.get(unloader_index)?;
        let Some(BlockDef::Distribution(unloader_block)) = content.block(unloader.block.id) else {
            return None;
        };
        if unloader_block.kind != DistributionBlockKind::DirectionalUnloader {
            return None;
        }
        let front_index = self.neighbor_building_index(unloader_index, unloader.rotation)?;
        let back_index =
            self.neighbor_building_index(unloader_index, (unloader.rotation + 2).rem_euclid(4))?;
        let front = self.buildings.get(front_index)?;
        let back = self.buildings.get(back_index)?;
        let back_block = content.block(back.block.id)?;
        let back_is_core_or_linked_core = matches!(back_block, BlockDef::Storage(storage) if storage.kind == StorageBlockKind::Core)
            || self
                .linked_core_index_for_storage(content, back_index)
                .is_some();

        directional_unloader_can_unload(
            true,
            true,
            front.team == unloader.team && back.team == unloader.team,
            Self::payload_block_unloadable(back_block) && back.items.is_some(),
            back_is_core_or_linked_core,
            unloader_block.allow_core_unload,
        )
        .then_some((front_index, back_index))
    }

    fn directional_unloader_try_move(
        &mut self,
        content: &ContentLoader,
        unloader_index: usize,
        _unloader_block: &crate::mindustry::content::blocks::DistributionBlockData,
    ) -> bool {
        let Some((front_index, back_index)) =
            self.directional_unloader_front_back(content, unloader_index)
        else {
            return false;
        };
        let tile_pos = self.buildings[unloader_index].tile_pos;
        let mut state = match self.distribution_runtime_states.get(&tile_pos) {
            Some(GameRuntimeDistributionBlockState::DirectionalUnloader(state)) => *state,
            Some(_) => return false,
            None => DirectionalUnloaderState {
                unload_item: None,
                offset: 0,
            },
        };

        if let Some(item_id) = state.unload_item {
            return self.directional_unloader_transfer_item(
                content,
                unloader_index,
                back_index,
                front_index,
                item_id,
            );
        }

        let items: Vec<_> = content
            .items()
            .iter()
            .map(|item| item.base.mappable.base.id)
            .collect();
        if items.is_empty() {
            return false;
        }
        let start = state.offset.rem_euclid(items.len() as i32) as usize;
        for attempt in 0..items.len() {
            let item_id = items[(start + attempt) % items.len()];
            if self.directional_unloader_transfer_item(
                content,
                unloader_index,
                back_index,
                front_index,
                item_id,
            ) {
                state.offset = directional_unloader_next_offset(item_id as i32);
                self.distribution_runtime_states.insert(
                    tile_pos,
                    GameRuntimeDistributionBlockState::DirectionalUnloader(state),
                );
                return true;
            }
        }

        self.distribution_runtime_states.entry(tile_pos).or_insert(
            GameRuntimeDistributionBlockState::DirectionalUnloader(state),
        );
        false
    }

    fn directional_unloader_transfer_item(
        &mut self,
        content: &ContentLoader,
        unloader_index: usize,
        back_index: usize,
        front_index: usize,
        item_id: ContentId,
    ) -> bool {
        if unloader_index == back_index
            || unloader_index == front_index
            || back_index >= self.buildings.len()
            || front_index >= self.buildings.len()
            || unloader_index >= self.buildings.len()
        {
            return false;
        }
        let back_item_owner_index = self.item_module_owner_index(content, back_index);
        if back_item_owner_index >= self.buildings.len()
            || !self.buildings[back_item_owner_index]
                .items
                .as_ref()
                .is_some_and(|items| items.get(item_id) > 0)
        {
            return false;
        }
        if !self.dump_target_accepts_item(content, unloader_index, front_index, item_id) {
            return false;
        }

        if let Some(items) = self.buildings[unloader_index].items.as_mut() {
            items.add(item_id, 1);
        } else {
            return false;
        }

        let moved_to_front =
            self.dump_item_to_target(content, unloader_index, front_index, item_id);
        if !moved_to_front {
            if let Some(items) = self.buildings[unloader_index].items.as_mut() {
                if items.get(item_id) > 0 {
                    items.remove(item_id, 1);
                }
            }
            return false;
        }

        if let Some(back_items) = self.buildings[back_item_owner_index].items.as_mut() {
            back_items.remove(item_id, 1);
        }
        self.record_item_taken(content, back_index, item_id);
        true
    }

    pub fn advance_owned_stack_routers(
        &mut self,
        content: &ContentLoader,
        delta_seconds: f32,
    ) -> Option<GameRuntimeStackRouterFrameReport> {
        let advanced = self.state.advance_game_update_frame(delta_seconds);
        if !advanced.advanced {
            return None;
        }
        Some(self.advance_owned_stack_routers_ticks(content, advanced.delta_ticks as f32))
    }

    fn advance_owned_stack_routers_ticks(
        &mut self,
        content: &ContentLoader,
        frame_delta: f32,
    ) -> GameRuntimeStackRouterFrameReport {
        let mut report = GameRuntimeStackRouterFrameReport::default();
        let router_indices: Vec<_> = self
            .buildings
            .iter()
            .enumerate()
            .filter_map(|(index, building)| {
                report.visited_buildings += 1;
                match content.block(building.block.id) {
                    Some(BlockDef::Distribution(distribution))
                        if distribution.kind == DistributionBlockKind::StackRouter =>
                    {
                        report.router_candidates += 1;
                        Some(index)
                    }
                    _ => None,
                }
            })
            .collect();

        for index in router_indices {
            let Some(BlockDef::Distribution(router_block)) =
                content.block(self.buildings[index].block.id)
            else {
                continue;
            };
            let tile_pos = self.buildings[index].tile_pos;
            let Some(current) = self.stack_router_refresh_current_from_items(index) else {
                report.updated_routers += 1;
                continue;
            };

            let items_total = self.buildings[index]
                .items
                .as_ref()
                .map(|items| items.total())
                .unwrap_or(0);
            if items_total <= 0 {
                self.clear_stack_router_current(tile_pos);
                self.item_stack_router_unloading.insert(tile_pos, false);
                self.item_duct_progress_states.insert(tile_pos, 0.0);
                report.updated_routers += 1;
                continue;
            }

            let mut unloading = self
                .item_stack_router_unloading
                .get(&tile_pos)
                .copied()
                .unwrap_or(false);
            if !unloading && items_total >= self.buildings[index].block.item_capacity {
                let speed = router_block.speed.max(0.0001);
                let progress = self
                    .item_duct_progress_states
                    .entry(tile_pos)
                    .or_insert(0.0);
                let (next_progress, next_unloading) = stack_router_progress_step(
                    unloading,
                    Some(current),
                    items_total,
                    self.buildings[index].block.item_capacity,
                    *progress,
                    self.buildings[index].enabled,
                    self.buildings[index].efficiency.max(0.0)
                        * self.buildings[index].time_scale.max(0.0)
                        * frame_delta,
                    router_block.base_efficiency.max(0.0)
                        * self.buildings[index].time_scale.max(0.0)
                        * frame_delta,
                    speed,
                );
                *progress = next_progress;
                if !unloading && next_unloading {
                    unloading = next_unloading;
                    self.item_stack_router_unloading.insert(tile_pos, true);
                    report.started_unloading += 1;
                }
            }

            if unloading {
                while self.buildings[index]
                    .items
                    .as_ref()
                    .is_some_and(|items| items.get(current) > 0)
                {
                    let Some(target_index) = self.stack_router_target(content, index, current)
                    else {
                        report.missing_targets += 1;
                        break;
                    };
                    report.attempted_moves += 1;
                    if self.dump_item_to_target(content, index, target_index, current) {
                        report.moved_items += 1;
                    } else {
                        report.blocked_targets += 1;
                        break;
                    }
                }

                if self.buildings[index]
                    .items
                    .as_ref()
                    .is_none_or(|items| items.get(current) == 0)
                {
                    self.clear_stack_router_current(tile_pos);
                    self.item_stack_router_unloading.insert(tile_pos, false);
                }
            }

            let item_state = self.buildings[index].items.as_ref();
            if item_state.is_none_or(|items| items.empty()) {
                self.clear_stack_router_current(tile_pos);
                self.item_stack_router_unloading.insert(tile_pos, false);
            } else if self
                .stack_router_current(tile_pos)
                .is_none_or(|item| item_state.is_none_or(|items| items.get(item) == 0))
            {
                if let Some(next_item) = item_state.and_then(|items| {
                    items
                        .each()
                        .find_map(|(item, amount)| (amount > 0).then_some(item))
                }) {
                    self.set_stack_router_current(tile_pos, next_item);
                }
            }

            report.updated_routers += 1;
        }

        report
    }

    fn stack_router_refresh_current_from_items(
        &mut self,
        router_index: usize,
    ) -> Option<ContentId> {
        let tile_pos = self.buildings.get(router_index)?.tile_pos;
        if let Some(current) = self.stack_router_current(tile_pos) {
            if self.buildings[router_index]
                .items
                .as_ref()
                .is_some_and(|items| items.get(current) > 0)
            {
                return Some(current);
            }
            self.clear_stack_router_current(tile_pos);
        }

        let next_item = self.buildings[router_index]
            .items
            .as_ref()
            .and_then(|items| {
                items
                    .each()
                    .find_map(|(item, amount)| (amount > 0).then_some(item))
            });
        if let Some(next_item) = next_item {
            self.set_stack_router_current(tile_pos, next_item);
            Some(next_item)
        } else {
            self.item_stack_router_unloading.insert(tile_pos, false);
            self.item_duct_progress_states.insert(tile_pos, 0.0);
            None
        }
    }

    fn stack_router_current(&self, tile_pos: i32) -> Option<ContentId> {
        match self.distribution_runtime_states.get(&tile_pos) {
            Some(GameRuntimeDistributionBlockState::DuctRouter(state)) => state.current,
            _ => None,
        }
    }

    fn stack_router_sort_item(&self, tile_pos: i32) -> Option<ContentId> {
        match self.distribution_runtime_states.get(&tile_pos) {
            Some(GameRuntimeDistributionBlockState::DuctRouter(state)) => state.sort_item,
            _ => None,
        }
    }

    fn set_stack_router_current(&mut self, tile_pos: i32, item_id: ContentId) {
        let entry = self
            .distribution_runtime_states
            .entry(tile_pos)
            .or_insert_with(|| {
                GameRuntimeDistributionBlockState::DuctRouter(DuctRouterState {
                    sort_item: None,
                    current: None,
                })
            });
        match entry {
            GameRuntimeDistributionBlockState::DuctRouter(state) => state.current = Some(item_id),
            _ => {
                *entry = GameRuntimeDistributionBlockState::DuctRouter(DuctRouterState {
                    sort_item: None,
                    current: Some(item_id),
                });
            }
        }
    }

    fn clear_stack_router_current(&mut self, tile_pos: i32) {
        if let Some(GameRuntimeDistributionBlockState::DuctRouter(state)) =
            self.distribution_runtime_states.get_mut(&tile_pos)
        {
            state.current = None;
        }
    }

    fn stack_router_target(
        &mut self,
        content: &ContentLoader,
        router_index: usize,
        item_id: ContentId,
    ) -> Option<usize> {
        let prox_len = self.buildings[router_index].proximity.len();
        if prox_len == 0 {
            return None;
        }
        let tile_pos = self.buildings[router_index].tile_pos;
        let dump = self.buildings[router_index].cdump;
        let sort_item = self.stack_router_sort_item(tile_pos);
        for attempt in 0..prox_len {
            let target_ref = self.buildings[router_index].proximity[(attempt + dump) % prox_len];
            let Some(target_index) = self
                .buildings
                .iter()
                .position(|building| building.tile_pos == target_ref.tile_pos)
            else {
                self.increment_building_dump(router_index, prox_len);
                continue;
            };
            let Some(rel) = self.relative_direction_between_buildings(router_index, target_index)
            else {
                self.increment_building_dump(router_index, prox_len);
                continue;
            };
            let sorted_rejects = sort_item.is_some_and(|sort| {
                (item_id == sort) != (rel == self.buildings[router_index].rotation)
            });
            if !sorted_rejects
                && rel != (self.buildings[router_index].rotation + 2).rem_euclid(4)
                && self.dump_target_accepts_item(content, router_index, target_index, item_id)
            {
                self.increment_building_dump(router_index, prox_len);
                return Some(target_index);
            }
            self.increment_building_dump(router_index, prox_len);
        }
        None
    }

    pub fn advance_owned_item_ducts(
        &mut self,
        content: &ContentLoader,
        delta_seconds: f32,
    ) -> Option<GameRuntimeItemDuctFrameReport> {
        let advanced = self.state.advance_game_update_frame(delta_seconds);
        if !advanced.advanced {
            return None;
        }
        Some(self.advance_owned_item_ducts_ticks(content, advanced.delta_ticks as f32))
    }

    fn advance_owned_item_ducts_ticks(
        &mut self,
        content: &ContentLoader,
        frame_delta: f32,
    ) -> GameRuntimeItemDuctFrameReport {
        self.refresh_owned_storage_core_links(content);
        let mut report = GameRuntimeItemDuctFrameReport::default();
        let duct_indices: Vec<_> = self
            .buildings
            .iter()
            .enumerate()
            .filter_map(|(index, building)| {
                report.visited_buildings += 1;
                match content.block(building.block.id) {
                    Some(BlockDef::Distribution(distribution))
                        if matches!(
                            distribution.kind,
                            DistributionBlockKind::Duct
                                | DistributionBlockKind::DuctRouter
                                | DistributionBlockKind::OverflowDuct
                        ) =>
                    {
                        report.duct_candidates += 1;
                        Some(index)
                    }
                    _ => None,
                }
            })
            .collect();

        for index in duct_indices {
            let Some(BlockDef::Distribution(duct_block)) =
                content.block(self.buildings[index].block.id)
            else {
                continue;
            };
            if !self.buildings[index].enabled {
                continue;
            }
            let tile_pos = self.buildings[index].tile_pos;
            let current = self.item_duct_current(tile_pos);
            if current.is_none() {
                if let Some(item_id) = self.buildings[index]
                    .items
                    .as_ref()
                    .and_then(|items| items.each().map(|(item, _)| item).next())
                {
                    self.set_item_duct_current(tile_pos, duct_block.kind, item_id, None);
                } else {
                    self.item_duct_progress_states.insert(tile_pos, 0.0);
                    continue;
                }
            }

            let Some(item_id) = self.item_duct_current(tile_pos) else {
                continue;
            };
            if !self.buildings[index]
                .items
                .as_ref()
                .is_some_and(|items| items.get(item_id) > 0)
            {
                self.clear_item_duct_current(tile_pos, duct_block.kind);
                self.item_duct_progress_states.insert(tile_pos, 0.0);
                continue;
            }

            let speed = duct_block.speed.max(0.0001);
            let progress = self
                .item_duct_progress_states
                .entry(tile_pos)
                .or_insert(0.0);
            *progress += frame_delta / speed * 2.0;
            if *progress < 1.0 - 1.0 / speed {
                report.updated_ducts += 1;
                continue;
            }

            let Some(target_index) = self.item_duct_target(content, index, duct_block, item_id)
            else {
                report.missing_targets += 1;
                report.updated_ducts += 1;
                continue;
            };
            report.attempted_moves += 1;
            if self.dump_item_to_target(content, index, target_index, item_id) {
                if duct_block.kind == DistributionBlockKind::OverflowDuct {
                    self.buildings[index].cdump =
                        overflow_duct_next_cdump(self.buildings[index].cdump);
                }
                self.clear_item_duct_current(tile_pos, duct_block.kind);
                let threshold = 1.0 - 1.0 / speed;
                let progress = self
                    .item_duct_progress_states
                    .entry(tile_pos)
                    .or_insert(0.0);
                *progress %= threshold;
                report.moved_items += 1;
            }
            report.updated_ducts += 1;
        }

        report
    }

    fn item_duct_current(&self, tile_pos: i32) -> Option<ContentId> {
        match self.distribution_runtime_states.get(&tile_pos) {
            Some(GameRuntimeDistributionBlockState::Duct(state)) => state.current,
            Some(GameRuntimeDistributionBlockState::DuctRouter(state)) => state.current,
            _ => None,
        }
    }

    fn set_item_duct_current(
        &mut self,
        tile_pos: i32,
        kind: DistributionBlockKind,
        item_id: ContentId,
        rec_dir: Option<i32>,
    ) {
        match kind {
            DistributionBlockKind::Duct => {
                let entry = self
                    .distribution_runtime_states
                    .entry(tile_pos)
                    .or_insert_with(|| {
                        GameRuntimeDistributionBlockState::Duct(DuctState::default())
                    });
                if let GameRuntimeDistributionBlockState::Duct(state) = entry {
                    state.current = Some(item_id);
                    if let Some(rec_dir) = rec_dir {
                        state.rec_dir = rec_dir;
                    }
                }
            }
            DistributionBlockKind::DuctRouter
            | DistributionBlockKind::OverflowDuct
            | DistributionBlockKind::StackRouter => {
                let entry = self
                    .distribution_runtime_states
                    .entry(tile_pos)
                    .or_insert_with(|| {
                        GameRuntimeDistributionBlockState::DuctRouter(DuctRouterState {
                            sort_item: None,
                            current: None,
                        })
                    });
                if let GameRuntimeDistributionBlockState::DuctRouter(state) = entry {
                    state.current = Some(item_id);
                }
            }
            _ => {}
        }
    }

    fn clear_item_duct_current(&mut self, tile_pos: i32, kind: DistributionBlockKind) {
        match kind {
            DistributionBlockKind::Duct => {
                if let Some(GameRuntimeDistributionBlockState::Duct(state)) =
                    self.distribution_runtime_states.get_mut(&tile_pos)
                {
                    state.current = None;
                }
            }
            DistributionBlockKind::DuctRouter
            | DistributionBlockKind::OverflowDuct
            | DistributionBlockKind::StackRouter => {
                if let Some(GameRuntimeDistributionBlockState::DuctRouter(state)) =
                    self.distribution_runtime_states.get_mut(&tile_pos)
                {
                    state.current = None;
                }
            }
            _ => {}
        }
    }

    fn item_duct_target(
        &mut self,
        content: &ContentLoader,
        duct_index: usize,
        duct_block: &crate::mindustry::content::blocks::DistributionBlockData,
        item_id: ContentId,
    ) -> Option<usize> {
        match duct_block.kind {
            DistributionBlockKind::Duct => {
                let direction = self.buildings[duct_index].rotation;
                let target_index = self.neighbor_building_index(duct_index, direction)?;
                self.dump_target_accepts_item(content, duct_index, target_index, item_id)
                    .then_some(target_index)
            }
            DistributionBlockKind::DuctRouter => {
                let prox_len = self.buildings[duct_index].proximity.len();
                if prox_len == 0 {
                    return None;
                }
                let dump = self.buildings[duct_index].cdump;
                let sort_item = match self
                    .distribution_runtime_states
                    .get(&self.buildings[duct_index].tile_pos)
                {
                    Some(GameRuntimeDistributionBlockState::DuctRouter(state)) => state.sort_item,
                    _ => None,
                };
                for attempt in 0..prox_len {
                    let target_ref =
                        self.buildings[duct_index].proximity[(attempt + dump) % prox_len];
                    let Some(target_index) = self
                        .buildings
                        .iter()
                        .position(|building| building.tile_pos == target_ref.tile_pos)
                    else {
                        self.increment_building_dump(duct_index, prox_len);
                        continue;
                    };
                    let Some(rel) =
                        self.relative_direction_between_buildings(duct_index, target_index)
                    else {
                        self.increment_building_dump(duct_index, prox_len);
                        continue;
                    };
                    let sorted_rejects = sort_item.is_some_and(|sort| {
                        (item_id == sort) != (rel == self.buildings[duct_index].rotation)
                    });
                    if !sorted_rejects
                        && rel != (self.buildings[duct_index].rotation + 2).rem_euclid(4)
                        && self.dump_target_accepts_item(content, duct_index, target_index, item_id)
                    {
                        self.increment_building_dump(duct_index, prox_len);
                        return Some(target_index);
                    }
                    self.increment_building_dump(duct_index, prox_len);
                }
                None
            }
            DistributionBlockKind::OverflowDuct => {
                self.overflow_duct_target(content, duct_index, duct_block, item_id)
            }
            _ => None,
        }
    }

    fn overflow_duct_target(
        &self,
        content: &ContentLoader,
        duct_index: usize,
        duct_block: &crate::mindustry::content::blocks::DistributionBlockData,
        item_id: ContentId,
    ) -> Option<usize> {
        let rotation = self.buildings[duct_index].rotation;
        let side_order = overflow_duct_side_order(rotation, self.buildings[duct_index].cdump);
        if duct_block.invert {
            for dir in side_order {
                if let Some(target_index) = self.neighbor_building_index(duct_index, dir) {
                    if self.dump_target_accepts_item(content, duct_index, target_index, item_id) {
                        return Some(target_index);
                    }
                }
            }
        }
        let front = self.neighbor_building_index(duct_index, rotation);
        if let Some(front) = front {
            if self.dump_target_accepts_item(content, duct_index, front, item_id) {
                return Some(front);
            }
        }
        if duct_block.invert {
            return None;
        }
        for dir in side_order {
            if let Some(target_index) = self.neighbor_building_index(duct_index, dir) {
                if self.dump_target_accepts_item(content, duct_index, target_index, item_id) {
                    return Some(target_index);
                }
            }
        }
        None
    }

    fn dump_item_to_item_bridge(
        &mut self,
        content: &ContentLoader,
        source_index: usize,
        target_index: usize,
        item_id: ContentId,
    ) -> bool {
        if !self.dump_target_accepts_item(content, source_index, target_index, item_id) {
            return false;
        }

        let target_tile_pos = self.buildings[target_index].tile_pos;
        let Some(target_kind) = content
            .block(self.buildings[target_index].block.id)
            .and_then(|block| match block {
                BlockDef::Distribution(distribution) => Some(distribution.kind),
                _ => None,
            })
        else {
            return false;
        };

        {
            let (source, target) = if source_index < target_index {
                let (left, right) = self.buildings.split_at_mut(target_index);
                (&mut left[source_index], &mut right[0])
            } else {
                let (left, right) = self.buildings.split_at_mut(source_index);
                (&mut right[0], &mut left[target_index])
            };

            let Some(source_items) = source.items.as_mut() else {
                return false;
            };
            if source_items.get(item_id) <= 0 {
                return false;
            }

            let Some(target_items) = target.items.as_mut() else {
                return false;
            };
            if target_items.total() >= target.block.item_capacity {
                return false;
            }

            source_items.remove(item_id, 1);
            target_items.add(item_id, 1);
        }

        self.ensure_item_bridge_state(target_tile_pos, target_kind);
        true
    }

    fn dump_item_to_junction(
        &mut self,
        content: &ContentLoader,
        source_index: usize,
        target_index: usize,
        item_id: ContentId,
    ) -> bool {
        if !self.dump_target_accepts_item(content, source_index, target_index, item_id) {
            return false;
        }
        let Some(relative) = self.relative_direction_between_buildings(source_index, target_index)
        else {
            return false;
        };
        let side = relative as usize;
        let target_tile_pos = self.buildings[target_index].tile_pos;
        let now = self
            .item_junction_time_counters
            .get(&target_tile_pos)
            .copied()
            .unwrap_or(0.0);

        {
            let Some(source_items) = self.buildings[source_index].items.as_mut() else {
                return false;
            };
            if source_items.get(item_id) <= 0 {
                return false;
            }
            source_items.remove(item_id, 1);
        }

        let state = self.ensure_duct_junction_state(target_tile_pos);
        state.buffer.accept(side, item_id, now)
    }

    fn dump_item_to_duct_bridge(
        &mut self,
        content: &ContentLoader,
        source_index: usize,
        target_index: usize,
        item_id: ContentId,
    ) -> bool {
        if !self.dump_target_accepts_item(content, source_index, target_index, item_id) {
            return false;
        }
        let target_tile_pos = self.buildings[target_index].tile_pos;

        {
            let (source, target) = if source_index < target_index {
                let (left, right) = self.buildings.split_at_mut(target_index);
                (&mut left[source_index], &mut right[0])
            } else {
                let (left, right) = self.buildings.split_at_mut(source_index);
                (&mut right[0], &mut left[target_index])
            };

            let Some(source_items) = source.items.as_mut() else {
                return false;
            };
            if source_items.get(item_id) <= 0 {
                return false;
            }
            let Some(target_items) = target.items.as_mut() else {
                return false;
            };
            if target_items.total() >= target.block.item_capacity {
                return false;
            }

            source_items.remove(item_id, 1);
            target_items.add(item_id, 1);
        }

        self.ensure_duct_bridge_state(target_tile_pos);
        true
    }

    fn dump_item_to_stack_conveyor(
        &mut self,
        content: &ContentLoader,
        source_index: usize,
        target_index: usize,
        item_id: ContentId,
    ) -> bool {
        if !self.dump_target_accepts_item(content, source_index, target_index, item_id) {
            return false;
        }
        let target_tile_pos = self.buildings[target_index].tile_pos;
        let was_empty = self.buildings[target_index]
            .items
            .as_ref()
            .is_none_or(|items| items.empty());

        {
            let (source, target) = if source_index < target_index {
                let (left, right) = self.buildings.split_at_mut(target_index);
                (&mut left[source_index], &mut right[0])
            } else {
                let (left, right) = self.buildings.split_at_mut(source_index);
                (&mut right[0], &mut left[target_index])
            };

            let Some(source_items) = source.items.as_mut() else {
                return false;
            };
            if source_items.get(item_id) <= 0 {
                return false;
            }
            let Some(target_items) = target.items.as_mut() else {
                return false;
            };
            if target_items.total() >= target.block.item_capacity
                || (target_items.any() && target_items.get(item_id) <= 0)
            {
                return false;
            }

            source_items.remove(item_id, 1);
            target_items.add(item_id, 1);
        }

        let state = self.ensure_stack_conveyor_state(target_tile_pos);
        if was_empty {
            state.link = target_tile_pos;
            state.cooldown = 0.0;
        }
        state.last_item = Some(item_id);
        true
    }

    fn dump_item_to_duct(
        &mut self,
        content: &ContentLoader,
        source_index: usize,
        target_index: usize,
        item_id: ContentId,
    ) -> bool {
        if !self.dump_target_accepts_item(content, source_index, target_index, item_id) {
            return false;
        }

        let Some(relative) = self.relative_direction_between_buildings(source_index, target_index)
        else {
            return false;
        };
        let target_tile_pos = self.buildings[target_index].tile_pos;
        let Some(target_kind) = content
            .block(self.buildings[target_index].block.id)
            .and_then(|block| match block {
                BlockDef::Distribution(distribution) => Some(distribution.kind),
                _ => None,
            })
        else {
            return false;
        };

        {
            let (source, target) = if source_index < target_index {
                let (left, right) = self.buildings.split_at_mut(target_index);
                (&mut left[source_index], &mut right[0])
            } else {
                let (left, right) = self.buildings.split_at_mut(source_index);
                (&mut right[0], &mut left[target_index])
            };

            let Some(source_items) = source.items.as_mut() else {
                return false;
            };
            if source_items.get(item_id) <= 0 {
                return false;
            }

            let Some(target_items) = target.items.as_mut() else {
                return false;
            };
            if target_items.total() >= target.block.item_capacity {
                return false;
            }

            source_items.remove(item_id, 1);
            target_items.add(item_id, 1);
        }

        match target_kind {
            DistributionBlockKind::Duct => {
                let entry = self
                    .distribution_runtime_states
                    .entry(target_tile_pos)
                    .or_insert_with(|| {
                        GameRuntimeDistributionBlockState::Duct(DuctState::default())
                    });
                let GameRuntimeDistributionBlockState::Duct(state) = entry else {
                    return false;
                };
                state.current = Some(item_id);
                state.rec_dir = relative;
                self.item_duct_progress_states.insert(target_tile_pos, -1.0);
                true
            }
            DistributionBlockKind::DuctRouter
            | DistributionBlockKind::OverflowDuct
            | DistributionBlockKind::StackRouter => {
                let entry = self
                    .distribution_runtime_states
                    .entry(target_tile_pos)
                    .or_insert_with(|| {
                        GameRuntimeDistributionBlockState::DuctRouter(DuctRouterState {
                            sort_item: None,
                            current: None,
                        })
                    });
                let GameRuntimeDistributionBlockState::DuctRouter(state) = entry else {
                    return false;
                };
                state.current = Some(item_id);
                self.item_duct_progress_states.insert(target_tile_pos, -1.0);
                true
            }
            _ => false,
        }
    }

    fn dump_item_to_conveyor(
        &mut self,
        content: &ContentLoader,
        source_index: usize,
        target_index: usize,
        item_id: ContentId,
    ) -> bool {
        if !self.dump_target_accepts_item(content, source_index, target_index, item_id) {
            return false;
        }

        let Some((insert_x, insert_y, insert_at)) =
            self.conveyor_dump_insert_plan(source_index, target_index)
        else {
            return false;
        };
        let target_tile_pos = self.buildings[target_index].tile_pos;

        {
            let (source, target) = if source_index < target_index {
                let (left, right) = self.buildings.split_at_mut(target_index);
                (&mut left[source_index], &mut right[0])
            } else {
                let (left, right) = self.buildings.split_at_mut(source_index);
                (&mut right[0], &mut left[target_index])
            };

            let Some(source_items) = source.items.as_mut() else {
                return false;
            };
            if source_items.get(item_id) <= 0 {
                return false;
            }

            let Some(target_items) = target.items.as_mut() else {
                return false;
            };
            if target_items.total() >= target.block.item_capacity {
                return false;
            }

            source_items.remove(item_id, 1);
            target_items.add(item_id, 1);
        }

        let entry = self
            .distribution_runtime_states
            .entry(target_tile_pos)
            .or_insert_with(|| {
                GameRuntimeDistributionBlockState::Conveyor(ConveyorState { items: Vec::new() })
            });
        let GameRuntimeDistributionBlockState::Conveyor(conveyor) = entry else {
            return false;
        };
        if conveyor.items.len() >= CONVEYOR_CAPACITY {
            return false;
        }
        let insert_at = insert_at.min(conveyor.items.len());
        conveyor.items.insert(
            insert_at,
            ConveyorItemState {
                item: item_id,
                x: insert_x,
                y: insert_y,
            },
        );
        true
    }

    fn conveyor_dump_insert_plan(
        &self,
        source_index: usize,
        target_index: usize,
    ) -> Option<(f32, f32, usize)> {
        let target = self.buildings.get(target_index)?;
        let relative = self.relative_direction_between_buildings(source_index, target_index)?;
        let angle = relative - target.rotation;
        let x = if angle == -1 || angle == 3 {
            1.0
        } else if angle == 1 || angle == -3 {
            -1.0
        } else {
            0.0
        };
        if (relative - target.rotation).abs() == 0 {
            Some((x, 0.0, 0))
        } else {
            Some((x, 0.5, usize::MAX))
        }
    }

    fn dump_liquid_to_target(
        &mut self,
        content: &ContentLoader,
        source_index: usize,
        target_index: usize,
        liquid_id: ContentId,
    ) -> bool {
        let Some(target_index) =
            self.liquid_destination_index(content, source_index, target_index, liquid_id)
        else {
            return false;
        };

        if source_index == target_index
            || source_index >= self.buildings.len()
            || target_index >= self.buildings.len()
            || !self.dump_liquid_target_accepts(content, source_index, target_index, liquid_id)
        {
            return false;
        }

        let (source, target) = if source_index < target_index {
            let (left, right) = self.buildings.split_at_mut(target_index);
            (&mut left[source_index], &mut right[0])
        } else {
            let (left, right) = self.buildings.split_at_mut(source_index);
            (&mut right[0], &mut left[target_index])
        };

        let source_capacity = source.block.liquid_capacity;
        let target_capacity = target.block.liquid_capacity;
        let Some(source_liquids) = source.liquids.as_mut() else {
            return false;
        };
        let Some(target_liquids) = target.liquids.as_mut() else {
            return false;
        };
        if !accept_same_or_low_amount(
            target_liquids.current(),
            liquid_id,
            target_liquids.current_amount(),
        ) {
            return false;
        }

        let flow = calc_dump_transfer(
            source_liquids.get(liquid_id),
            source_capacity,
            target_liquids.get(liquid_id),
            target_capacity,
            2.0,
        );
        if flow <= 0.0 {
            return false;
        }

        target_liquids.add(liquid_id, flow);
        source_liquids.remove(liquid_id, flow);
        true
    }

    fn liquid_destination_index(
        &self,
        content: &ContentLoader,
        source_index: usize,
        target_index: usize,
        liquid_id: ContentId,
    ) -> Option<usize> {
        if source_index >= self.buildings.len() || target_index >= self.buildings.len() {
            return None;
        }

        let mut from_index = source_index;
        let mut current_index = target_index;
        for _ in 0..=self.buildings.len() {
            if !matches!(
                content.block(self.buildings[current_index].block.id),
                Some(BlockDef::Liquid(liquid)) if liquid.kind == LiquidBlockKind::LiquidJunction
            ) {
                return Some(current_index);
            }

            if !self.buildings[current_index].enabled {
                return None;
            }

            let dir = self.relative_direction_between_buildings(from_index, current_index)?;
            let (dx, dy) = autotiler_direction(dir);
            let next_tile_pos = self
                .state
                .world
                .build(
                    self.buildings[current_index].tile_x() + dx,
                    self.buildings[current_index].tile_y() + dy,
                )
                .map(|target| target.tile_pos)?;
            let next_index = self
                .buildings
                .iter()
                .position(|building| building.tile_pos == next_tile_pos)?;

            if !matches!(
                content.block(self.buildings[next_index].block.id),
                Some(BlockDef::Liquid(liquid)) if liquid.kind == LiquidBlockKind::LiquidJunction
            ) && !self.dump_liquid_target_accepts(content, source_index, next_index, liquid_id)
            {
                return None;
            }

            from_index = current_index;
            current_index = next_index;
        }

        None
    }

    fn relative_direction_between_buildings(
        &self,
        from_index: usize,
        to_index: usize,
    ) -> Option<i32> {
        let (Some(from), Some(to)) = (self.buildings.get(from_index), self.buildings.get(to_index))
        else {
            return None;
        };

        if (from.x - to.x).abs() > (from.y - to.y).abs() {
            if from.x <= to.x - 1.0 {
                Some(0)
            } else if from.x >= to.x + 1.0 {
                Some(2)
            } else {
                None
            }
        } else if from.y <= to.y - 1.0 {
            Some(1)
        } else if from.y >= to.y + 1.0 {
            Some(3)
        } else {
            None
        }
    }

    fn dump_target_accepts_item(
        &self,
        content: &ContentLoader,
        source_index: usize,
        target_index: usize,
        item_id: ContentId,
    ) -> bool {
        let (Some(source), Some(target)) = (
            self.buildings.get(source_index),
            self.buildings.get(target_index),
        ) else {
            return false;
        };
        if source.team != target.team {
            return false;
        }

        match content.block(target.block.id) {
            Some(BlockDef::Sandbox(sandbox)) if sandbox.kind == SandboxBlockKind::ItemVoid => {
                item_void_accept_item(target.enabled)
            }
            Some(BlockDef::Crafting(crafting))
                if crafting.kind == CraftingBlockKind::ItemIncinerator =>
            {
                target.enabled && item_incinerator_accept_item(target.efficiency)
            }
            Some(BlockDef::Distribution(distribution))
                if matches!(
                    distribution.kind,
                    DistributionBlockKind::Conveyor | DistributionBlockKind::ArmoredConveyor
                ) =>
            {
                let Some(items) = target.items.as_ref() else {
                    return false;
                };
                if items.total() >= target.block.item_capacity {
                    return false;
                }
                let len = match self.distribution_runtime_states.get(&target.tile_pos) {
                    Some(GameRuntimeDistributionBlockState::Conveyor(conveyor)) => {
                        conveyor.items.len()
                    }
                    Some(_) => return false,
                    None => 0,
                };
                conveyor_accept_item(
                    len,
                    1.0,
                    self.relative_direction_between_buildings(source_index, target_index),
                    target.rotation,
                    false,
                )
            }
            Some(BlockDef::Distribution(distribution))
                if distribution.kind == DistributionBlockKind::Router =>
            {
                let Some(items) = target.items.as_ref() else {
                    return false;
                };
                items.total() == 0 && target.block.item_capacity > 0
            }
            Some(BlockDef::Distribution(distribution))
                if matches!(
                    distribution.kind,
                    DistributionBlockKind::ItemBridge | DistributionBlockKind::BufferedItemBridge
                ) =>
            {
                let Some(items) = target.items.as_ref() else {
                    return false;
                };
                items.total() < target.block.item_capacity
                    && self.item_bridge_accepts_item(content, source_index, target_index)
            }
            Some(BlockDef::Distribution(distribution))
                if distribution.kind == DistributionBlockKind::Junction =>
            {
                let Some(relative) =
                    self.relative_direction_between_buildings(source_index, target_index)
                else {
                    return false;
                };
                let side = relative as usize;
                if side >= 4 {
                    return false;
                }
                let side_accepts = match self.distribution_runtime_states.get(&target.tile_pos) {
                    Some(GameRuntimeDistributionBlockState::DuctJunction(state)) => {
                        state.buffer.accepts(side)
                    }
                    Some(_) => return false,
                    None => true,
                };
                let target_exists_and_same_team = self
                    .neighbor_building_index(target_index, relative)
                    .and_then(|next_index| self.buildings.get(next_index))
                    .is_some_and(|next| next.team == target.team);
                duct_junction_accept_item(Some(side), side_accepts, target_exists_and_same_team)
            }
            Some(BlockDef::Distribution(distribution))
                if distribution.kind == DistributionBlockKind::DuctBridge =>
            {
                self.duct_bridge_accepts_item(content, source_index, target_index)
            }
            Some(BlockDef::Distribution(distribution))
                if distribution.kind == DistributionBlockKind::StackConveyor =>
            {
                let Some(items) = target.items.as_ref() else {
                    return false;
                };
                let item_total = items.total();
                let items_empty_or_same = items.empty() || items.get(item_id) > 0;
                let state = self.stack_conveyor_state(target.tile_pos);
                let state_kind = self.stack_conveyor_state_kind(content, target_index);
                let source_is_front = self.neighbor_building_index(target_index, target.rotation)
                    == Some(source_index);
                stack_conveyor_accept_item(
                    source_index == target_index,
                    item_total,
                    target.block.item_capacity,
                    items_empty_or_same,
                    state.cooldown,
                    distribution.recharge,
                    state_kind,
                    target.block.item_capacity,
                    source_is_front,
                )
            }
            Some(BlockDef::Distribution(distribution))
                if distribution.kind == DistributionBlockKind::MassDriver =>
            {
                let Some(items) = target.items.as_ref() else {
                    return false;
                };
                items.total() < target.block.item_capacity
                    && self
                        .distribution_runtime_states
                        .get(&target.tile_pos)
                        .and_then(|state| match state {
                            GameRuntimeDistributionBlockState::MassDriver(state) => {
                                Some(state.link)
                            }
                            _ => None,
                        })
                        .and_then(|link| {
                            self.item_mass_driver_link_target_index(content, target_index, link)
                        })
                        .is_some()
            }
            Some(BlockDef::Distribution(distribution))
                if distribution.kind == DistributionBlockKind::UnitCargoLoader =>
            {
                let Some(items) = target.items.as_ref() else {
                    return false;
                };
                unit_cargo_loader_accept_item(items.total(), target.block.item_capacity)
            }
            Some(BlockDef::Distribution(distribution))
                if distribution.kind == DistributionBlockKind::Duct =>
            {
                let Some(items) = target.items.as_ref() else {
                    return false;
                };
                let current = match self.distribution_runtime_states.get(&target.tile_pos) {
                    Some(GameRuntimeDistributionBlockState::Duct(state)) => state.current,
                    Some(_) => return false,
                    None => None,
                };
                let (source_is_duct, source_front_points_to_target) = content
                    .block(source.block.id)
                    .map_or((false, false), |block| {
                        let BlockDef::Distribution(distribution) = block else {
                            return (false, false);
                        };
                        (
                            distribution.is_duct,
                            distribution.is_duct
                                && distribution.rotate
                                && distribution.base.has_items
                                && self.neighbor_building_index(source_index, source.rotation)
                                    == Some(target_index),
                        )
                    });
                duct_accept_item(
                    current.is_some(),
                    items.total() == 0,
                    self.relative_direction_between_buildings(source_index, target_index),
                    target.rotation,
                    distribution.armored,
                    source_is_duct,
                    source_front_points_to_target,
                )
            }
            Some(BlockDef::Distribution(distribution))
                if distribution.kind == DistributionBlockKind::StackRouter =>
            {
                let Some(items) = target.items.as_ref() else {
                    return false;
                };
                let current = match self.distribution_runtime_states.get(&target.tile_pos) {
                    Some(GameRuntimeDistributionBlockState::DuctRouter(state)) => state.current,
                    Some(_) => return false,
                    None => None,
                };
                let unloading = self
                    .item_stack_router_unloading
                    .get(&target.tile_pos)
                    .copied()
                    .unwrap_or(false);
                stack_router_accept_item(
                    unloading,
                    current,
                    item_id,
                    items.total(),
                    target.block.item_capacity,
                    self.relative_direction_between_buildings(source_index, target_index),
                    target.rotation,
                )
            }
            Some(BlockDef::Distribution(distribution))
                if matches!(
                    distribution.kind,
                    DistributionBlockKind::DuctRouter | DistributionBlockKind::OverflowDuct
                ) =>
            {
                let Some(items) = target.items.as_ref() else {
                    return false;
                };
                let current = match self.distribution_runtime_states.get(&target.tile_pos) {
                    Some(GameRuntimeDistributionBlockState::DuctRouter(state)) => state.current,
                    Some(_) => return false,
                    None => None,
                };
                duct_router_accept_item(
                    current.is_some(),
                    items.total() == 0,
                    self.relative_direction_between_buildings(source_index, target_index),
                    target.rotation,
                )
            }
            Some(BlockDef::Distribution(distribution))
                if matches!(
                    distribution.kind,
                    DistributionBlockKind::Sorter | DistributionBlockKind::OverflowGate
                ) =>
            {
                self.instant_transfer_item_destination(
                    content,
                    source_index,
                    target_index,
                    item_id,
                    false,
                )
                .is_some()
            }
            Some(BlockDef::UnitFactory(factory_block)) => {
                let Some(items) = target.items.as_ref() else {
                    return false;
                };
                let current_plan = self
                    .unit_runtime_states
                    .get(&target.tile_pos)
                    .and_then(|state| match state {
                        GameRuntimeUnitBlockState::Factory { factory, .. } => {
                            Some(factory.current_plan)
                        }
                        _ => None,
                    })
                    .or_else(|| match target.config_value() {
                        type_io::TypeValue::Int(plan) => Some(plan),
                        _ => None,
                    })
                    .unwrap_or(-1);
                let plan_contains_item = (current_plan >= 0)
                    .then(|| factory_block.plans.get(current_plan as usize))
                    .flatten()
                    .is_some_and(|plan| {
                        plan.requirements
                            .iter()
                            .any(|requirement| requirement.item == item_id)
                    });
                let base_capacity = factory_block
                    .capacities
                    .iter()
                    .find(|capacity| capacity.item == item_id)
                    .map(|capacity| capacity.amount)
                    .unwrap_or(0);
                let maximum_accepted = unit_factory_maximum_accepted(
                    base_capacity,
                    self.state.rules.unit_cost(target.team.0 as usize),
                );
                unit_factory_accept_item(
                    current_plan,
                    items.get(item_id),
                    maximum_accepted,
                    plan_contains_item,
                )
            }
            Some(BlockDef::UnitReconstructor(reconstructor_block)) => {
                let Some(items) = target.items.as_ref() else {
                    return false;
                };
                let base_capacity = reconstructor_block
                    .capacities
                    .iter()
                    .find(|capacity| capacity.item == item_id)
                    .map(|capacity| capacity.amount)
                    .unwrap_or(0);
                let maximum_accepted = reconstructor_maximum_accepted(
                    base_capacity,
                    self.state.rules.unit_cost(target.team.0 as usize),
                );
                reconstructor_accept_item(items.get(item_id), maximum_accepted)
            }
            Some(BlockDef::Storage(storage)) => {
                let target_owner_index = self.item_module_owner_index(content, target_index);
                let Some(items) = self
                    .buildings
                    .get(target_owner_index)
                    .and_then(|building| building.items.as_ref())
                else {
                    return false;
                };
                let stored = items.get(item_id);
                let maximum_accepted = self.maximum_accepted_for_item_owner(target_owner_index);
                match storage.kind {
                    StorageBlockKind::Storage => storage_accept_item(
                        target_owner_index != target_index,
                        core_accept_item(
                            self.state.rules.core_incinerates,
                            stored,
                            maximum_accepted,
                        ),
                        stored,
                        target.block.item_capacity,
                    ),
                    StorageBlockKind::Core => core_accept_item(
                        self.state.rules.core_incinerates,
                        stored,
                        maximum_accepted,
                    ),
                }
            }
            _ => false,
        }
    }

    fn dump_liquid_target_accepts(
        &self,
        content: &ContentLoader,
        source_index: usize,
        target_index: usize,
        liquid_id: ContentId,
    ) -> bool {
        let (Some(source), Some(target)) = (
            self.buildings.get(source_index),
            self.buildings.get(target_index),
        ) else {
            return false;
        };
        if source.team != target.team || !target.block.has_liquids {
            return false;
        }
        if !matches!(content.block(target.block.id), Some(BlockDef::Liquid(_))) {
            return false;
        }
        let Some(liquids) = target.liquids.as_ref() else {
            return false;
        };
        target.block.liquid_capacity > 0.0
            && liquids.get(liquid_id) < target.block.liquid_capacity
            && accept_same_or_low_amount(liquids.current(), liquid_id, liquids.current_amount())
    }

    fn payload_loader_load_inner_building(
        content: &ContentLoader,
        loader_def: &PayloadLoaderBlockData,
        outer: &mut BuildingComp,
        common: &mut PayloadBlockBuildState,
        loader: &mut PayloadLoaderState,
        edelta: f32,
        efficiency: f32,
        report: &mut GameRuntimePayloadLoaderFrameReport,
    ) {
        let Some(payload) = common.payload.as_mut() else {
            Self::refresh_payload_loader_state_from_common(content, outer, common, loader);
            return;
        };
        let Some((mut payload_building, tail)) =
            Self::payload_ref_building_with_tail(content, payload)
        else {
            report.invalid_payloads += 1;
            Self::refresh_payload_loader_state_from_common(content, outer, common, loader);
            return;
        };

        let mut changed = false;

        if payload_building.block.has_items && outer.items.as_ref().is_some_and(|items| items.any())
        {
            if payload_loader_timer_ready(
                &mut loader.load_timer,
                loader_def.load_time,
                efficiency,
                edelta,
            ) {
                let before_loaded = report.loaded_items;
                for _ in 0..loader_def.items_loaded.max(0) {
                    let Some(item_id) = outer
                        .items
                        .as_ref()
                        .and_then(|items| items.each().map(|(id, _)| id).next())
                    else {
                        break;
                    };
                    let Some(payload_items) = payload_building.items.as_mut() else {
                        loader.exporting = true;
                        break;
                    };
                    let payload_block_def = content.block(payload_building.block.id);
                    let separate_item_capacity =
                        Self::payload_block_separate_item_capacity(payload_block_def);
                    let item_capacity_reached = if separate_item_capacity {
                        payload_items.get(item_id) >= payload_building.block.item_capacity
                    } else {
                        payload_items.total() >= payload_building.block.item_capacity
                    };
                    if item_capacity_reached {
                        if separate_item_capacity
                            || Self::payload_block_consumes_item(payload_block_def, item_id)
                        {
                            loader.exporting = true;
                        }
                        break;
                    }
                    payload_items.add(item_id, 1);
                    if let Some(items) = outer.items.as_mut() {
                        items.remove(item_id, 1);
                    }
                    report.loaded_items += 1;
                    changed = true;
                }
                if report.loaded_items == before_loaded {
                    loader.exporting = true;
                }
            }
        }

        if payload_building.block.has_liquids {
            let liquid = outer
                .liquids
                .as_ref()
                .and_then(|liquids| liquids.current())
                .filter(|_| {
                    outer
                        .liquids
                        .as_ref()
                        .map(|liquids| liquids.current_amount() >= 0.001)
                        .unwrap_or(false)
                });
            if let Some(liquid) = liquid {
                let outer_amount = outer
                    .liquids
                    .as_ref()
                    .map(|liquids| liquids.current_amount())
                    .unwrap_or(0.0);
                let Some(payload_liquids) = payload_building.liquids.as_mut() else {
                    loader.exporting = true;
                    Self::refresh_payload_loader_state_from_common(content, outer, common, loader);
                    return;
                };
                let accepts_liquid = payload_liquids.current() == Some(liquid)
                    || payload_liquids.current_amount() < 0.2;
                if accepts_liquid {
                    let flow = payload_loader_liquid_flow(
                        loader_def.liquids_loaded,
                        edelta,
                        payload_building.block.liquid_capacity,
                        payload_liquids.get(liquid),
                        outer_amount,
                    );
                    if flow > 0.0 {
                        payload_liquids.add(liquid, flow);
                        if let Some(liquids) = outer.liquids.as_mut() {
                            liquids.remove(liquid, flow);
                        }
                        report.loaded_liquid_events += 1;
                        changed = true;
                    }
                } else {
                    loader.exporting = true;
                }
            }
        }

        if let Some(capacity) =
            Self::payload_block_buffered_power_capacity(content, payload_building.block.id)
        {
            if capacity > 0.0 {
                if let (Some(outer_power), Some(payload_power)) =
                    (outer.power.as_ref(), payload_building.power.as_mut())
                {
                    let base_power_use = if loader_def.base_power_use > 0.0 {
                        loader_def.base_power_use
                    } else {
                        loader_def.consume_power
                    };
                    let step = payload_loader_charge_battery(
                        payload_power.status,
                        outer_power.status,
                        base_power_use,
                        loader_def.max_power_consumption,
                        capacity,
                        edelta,
                    );
                    payload_power.status = step.payload_power_status;
                    if step.available_input > 0.0 {
                        report.charged_batteries += 1;
                        changed = true;
                    }
                    if step.exporting {
                        loader.exporting = true;
                    }
                }
            }
        }

        if changed {
            Self::write_payload_ref_building_with_tail(payload, &payload_building, &tail);
        }
        Self::refresh_payload_loader_state_from_common(content, outer, common, loader);
    }

    fn payload_unloader_unload_inner_building(
        content: &ContentLoader,
        loader_def: &PayloadLoaderBlockData,
        outer: &mut BuildingComp,
        common: &mut PayloadBlockBuildState,
        loader: &mut PayloadLoaderState,
        edelta: f32,
        efficiency: f32,
        report: &mut GameRuntimePayloadLoaderFrameReport,
    ) {
        let Some(payload) = common.payload.as_mut() else {
            Self::refresh_payload_loader_state_from_common(content, outer, common, loader);
            return;
        };
        let Some((mut payload_building, tail)) =
            Self::payload_ref_building_with_tail(content, payload)
        else {
            report.invalid_payloads += 1;
            Self::refresh_payload_loader_state_from_common(content, outer, common, loader);
            return;
        };

        let mut changed = false;

        if payload_building.block.has_items
            && !payload_unloader_full(
                outer.items.as_ref().map(|items| items.total()).unwrap_or(0),
                outer.block.item_capacity,
            )
            && payload_loader_timer_ready(
                &mut loader.load_timer,
                loader_def.load_time,
                efficiency,
                edelta,
            )
        {
            for _ in 0..loader_def.items_loaded.max(0) {
                if payload_unloader_full(
                    outer.items.as_ref().map(|items| items.total()).unwrap_or(0),
                    outer.block.item_capacity,
                ) {
                    break;
                }
                let Some(item_id) = payload_building
                    .items
                    .as_ref()
                    .and_then(|items| items.each().map(|(id, _)| id).next())
                else {
                    break;
                };
                if let Some(payload_items) = payload_building.items.as_mut() {
                    payload_items.remove(item_id, 1);
                }
                if let Some(items) = outer.items.as_mut() {
                    items.add(item_id, 1);
                }
                report.unloaded_items += 1;
                changed = true;
            }
        }

        if payload_building.block.has_liquids {
            let payload_current = payload_building
                .liquids
                .as_ref()
                .and_then(|liquids| liquids.current());
            let payload_amount = payload_building
                .liquids
                .as_ref()
                .map(|liquids| liquids.current_amount())
                .unwrap_or(0.0);
            if let Some(liquid) = payload_current.filter(|_| payload_amount >= 0.01) {
                let outer_current = outer.liquids.as_ref().and_then(|liquids| liquids.current());
                let outer_amount = outer
                    .liquids
                    .as_ref()
                    .map(|liquids| liquids.current_amount())
                    .unwrap_or(0.0);
                if outer_current == Some(liquid) || outer_amount <= 0.2 {
                    let flow = payload_unloader_liquid_flow(
                        loader_def.liquids_loaded,
                        edelta,
                        outer.block.liquid_capacity,
                        outer_amount,
                        payload_amount,
                    );
                    if flow > 0.0 {
                        if let Some(liquids) = outer.liquids.as_mut() {
                            liquids.add(liquid, flow);
                        }
                        if let Some(payload_liquids) = payload_building.liquids.as_mut() {
                            payload_liquids.remove(liquid, flow);
                        }
                        report.unloaded_liquid_events += 1;
                        changed = true;
                    }
                }
            }
        }

        if let Some(capacity) =
            Self::payload_block_buffered_power_capacity(content, payload_building.block.id)
        {
            if capacity > 0.0 {
                if let Some(payload_power) = payload_building.power.as_mut() {
                    let step = payload_unloader_drain_battery(
                        payload_power.status,
                        capacity,
                        loader_def.max_power_unload,
                        edelta,
                    );
                    payload_power.status = step.payload_power_status.max(0.0);
                    loader.last_output_power = step.last_output_power;
                    if step.last_output_power > 0.0 {
                        report.drained_batteries += 1;
                        changed = true;
                    }
                }
            }
        }

        if changed {
            Self::write_payload_ref_building_with_tail(payload, &payload_building, &tail);
        }
        Self::refresh_payload_loader_state_from_common(content, outer, common, loader);
    }

    fn refresh_payload_loader_state_from_common(
        content: &ContentLoader,
        outer: &BuildingComp,
        common: &PayloadBlockBuildState,
        loader: &mut PayloadLoaderState,
    ) {
        let exporting = common
            .payload
            .as_ref()
            .map(|_| loader.exporting)
            .unwrap_or(false);
        let load_timer = common
            .payload
            .as_ref()
            .map(|_| loader.load_timer)
            .unwrap_or(0.0);
        let last_output_power = loader.last_output_power;
        let mut next = PayloadLoaderState {
            exporting,
            load_timer,
            last_output_power,
            has_payload: common.payload.is_some(),
            loader_liquid_amount: outer
                .liquids
                .as_ref()
                .map(|liquids| liquids.current_amount())
                .unwrap_or(0.0),
            ..PayloadLoaderState::default()
        };

        if let Some(payload) = common.payload.as_ref() {
            if let Some((payload_building, _tail)) =
                Self::payload_ref_building_with_tail(content, payload)
            {
                next.payload_has_items = payload_building.block.has_items;
                next.payload_items_total = payload_building
                    .items
                    .as_ref()
                    .map(|items| items.total())
                    .unwrap_or(0);
                next.payload_item_capacity = payload_building.block.item_capacity;
                let payload_block_def = content.block(payload_building.block.id);
                if Self::payload_block_separate_item_capacity(payload_block_def) {
                    next.payload_item_capacity_blocked = outer
                        .items
                        .as_ref()
                        .zip(payload_building.items.as_ref())
                        .map(|(outer_items, payload_items)| {
                            outer_items.each().any(|(item_id, _)| {
                                payload_items.get(item_id) >= payload_building.block.item_capacity
                            })
                        })
                        .unwrap_or(false);
                }
                next.payload_has_liquids = payload_building.block.has_liquids;
                next.payload_liquid_amount = payload_building
                    .liquids
                    .as_ref()
                    .map(|liquids| liquids.current_amount())
                    .unwrap_or(0.0);
                next.payload_liquid_capacity = payload_building.block.liquid_capacity;
                next.has_battery =
                    Self::payload_block_buffered_power_capacity(content, payload_building.block.id)
                        .is_some();
                next.payload_power_status = payload_building
                    .power
                    .as_ref()
                    .map(|power| power.status)
                    .unwrap_or(0.0);
            }
        }

        *loader = next;
    }

    fn payload_ref_building_with_tail(
        content: &ContentLoader,
        payload: &PayloadRef,
    ) -> Option<(BuildingComp, Vec<u8>)> {
        let PayloadRef::Block {
            block, build_bytes, ..
        } = payload
        else {
            return None;
        };
        let block_def = content.block(*block)?;
        let mut building = BuildingComp::new(
            crate::mindustry::world::point2_pack(0, 0),
            block_def.base().clone(),
            TeamId(0),
        );
        let mut cursor = Cursor::new(build_bytes.as_slice());
        building.read_base(&mut cursor).ok()?;
        let consumed = cursor.position() as usize;
        let tail = build_bytes.get(consumed..)?.to_vec();
        Some((building, tail))
    }

    fn write_payload_ref_building_with_tail(
        payload: &mut PayloadRef,
        building: &BuildingComp,
        tail: &[u8],
    ) -> bool {
        let PayloadRef::Block { build_bytes, .. } = payload else {
            return false;
        };
        let mut next = Vec::new();
        if building.write_base(&mut next, false).is_err() {
            return false;
        }
        next.extend_from_slice(tail);
        *build_bytes = next;
        true
    }

    fn payload_ref_deconstruction_plan(
        content: &ContentLoader,
        payload: &PayloadRef,
    ) -> Option<GameRuntimePayloadDeconstructionPlan> {
        match payload {
            PayloadRef::Block { block, .. } => {
                let block_def = content.block(*block)?;
                let requirements: Vec<_> = block_def
                    .requirements()
                    .iter()
                    .filter(|requirement| requirement.amount > 0)
                    .collect();
                if requirements.is_empty() {
                    return None;
                }
                let build_time = block_def.effective_build_time(content.items());
                if !build_time.is_finite() || build_time <= 0.0 {
                    return None;
                }
                Some(GameRuntimePayloadDeconstructionPlan {
                    item_ids: requirements
                        .iter()
                        .map(|requirement| requirement.item)
                        .collect(),
                    amounts: requirements
                        .iter()
                        .map(|requirement| requirement.amount)
                        .collect(),
                    payload_size: block_def.base().size as f32,
                    build_time,
                })
            }
            PayloadRef::Unit { .. } => None,
        }
    }

    fn payload_deconstructor_accepts_payload_ref(
        content: &ContentLoader,
        max_payload_size: f32,
        common: &PayloadBlockBuildState,
        deconstructor: &PayloadDeconstructorState,
        payload: &PayloadRef,
    ) -> bool {
        let Some(plan) = Self::payload_ref_deconstruction_plan(content, payload) else {
            return false;
        };
        let state = PayloadDeconstructorState {
            has_payload: common.payload.is_some(),
            has_deconstructing: deconstructor.deconstructing.is_some(),
            ..PayloadDeconstructorState::default()
        };
        payload_deconstructor_accept_payload(
            &state,
            plan.amounts.len(),
            plan.payload_size,
            max_payload_size,
        )
    }

    fn payload_ref_unit_type<'a>(
        content: &'a ContentLoader,
        payload: &PayloadRef,
    ) -> Option<&'a crate::mindustry::r#type::UnitType> {
        payload_ref_sort_key(payload)
            .filter(|key| key.content_type == ContentType::Unit.ordinal() as i8)
            .and_then(|key| content.unit(key.id))
    }

    fn reconstructor_upgrade_for_payload<'a>(
        content: &'a ContentLoader,
        reconstructor: &'a crate::mindustry::content::blocks::UnitReconstructorBlockData,
        payload: &PayloadRef,
    ) -> Option<(
        &'a crate::mindustry::r#type::UnitType,
        &'a crate::mindustry::r#type::UnitType,
    )> {
        let from = Self::payload_ref_unit_type(content, payload)?;
        let upgrade = reconstructor
            .upgrades
            .iter()
            .find(|upgrade| upgrade.from == from.name())?;
        let to = content.unit_by_name(&upgrade.to)?;
        Some((from, to))
    }

    fn reconstructor_upgrade_unlocked_now(
        rules: &crate::mindustry::game::Rules,
        unit: &crate::mindustry::r#type::UnitType,
    ) -> bool {
        Self::unit_unlocked_now(rules, unit)
    }

    fn unit_unlocked_now(
        rules: &crate::mindustry::game::Rules,
        unit: &crate::mindustry::r#type::UnitType,
    ) -> bool {
        unit.base.unlocked()
            || rules.researched.contains(unit.name())
            || rules.editor
            || rules.infinite_resources
            // Until the campaign/host research mirror is fully migrated, an empty
            // rules.researched set means "unknown", not "everything locked".
            || rules.researched.is_empty()
    }

    fn unit_default_command_id(
        content: &ContentLoader,
        unit: &crate::mindustry::r#type::UnitType,
    ) -> Option<ContentId> {
        let command = unit.default_command.as_deref()?;
        content
            .unit_command_by_name(command)
            .or_else(|| {
                command
                    .strip_suffix("Command")
                    .and_then(|name| content.unit_command_by_name(name))
            })
            .map(|command| command.base.base.id)
    }

    fn unit_payload_controller_bounds(class_id: u8, unit_bytes: &[u8]) -> Option<(usize, usize)> {
        let mut read = unit_bytes;
        let revision = type_io::read_i16(&mut read).ok()?;
        let schema = Self::unit_payload_schema(class_id, revision)?;

        type_io::skip_abilities(&mut read).ok()?;
        if matches!(schema, GameRuntimeUnitPayloadSchema::Ammo) {
            type_io::read_f32(&mut read).ok()?;
        } else {
            type_io::read_f32(&mut read).ok()?;
            type_io::read_f32(&mut read).ok()?;
        }
        if matches!(schema, GameRuntimeUnitPayloadSchema::BaseRotation) {
            type_io::read_f32(&mut read).ok()?;
        }
        if matches!(schema, GameRuntimeUnitPayloadSchema::BuildingPayloads) {
            type_io::read_building_ref(&mut read).ok()?;
        }

        let start = unit_bytes.len().checked_sub(read.len())?;
        type_io::read_controller(&mut read).ok()?;
        let end = unit_bytes.len().checked_sub(read.len())?;
        (start <= end).then_some((start, end))
    }

    fn payload_ref_patch_unit_controller(
        payload: &mut PayloadRef,
        controller: &type_io::ControllerWire,
    ) -> bool {
        let PayloadRef::Unit {
            class_id,
            unit_bytes,
        } = payload
        else {
            return false;
        };
        let Some((start, end)) = Self::unit_payload_controller_bounds(*class_id, unit_bytes) else {
            return false;
        };
        let mut controller_bytes = Vec::new();
        if type_io::write_controller(&mut controller_bytes, controller).is_err() {
            return false;
        }
        unit_bytes.splice(start..end, controller_bytes);
        true
    }

    fn reconstructor_accepts_payload_ref_with_rules(
        content: &ContentLoader,
        rules: &crate::mindustry::game::Rules,
        reconstructor_block: &crate::mindustry::content::blocks::UnitReconstructorBlockData,
        _team: TeamId,
        payload_empty: bool,
        enabled_or_self_source: bool,
        source_not_output_side: bool,
        payload: &PayloadRef,
    ) -> bool {
        let Some((_from, upgrade)) =
            Self::reconstructor_upgrade_for_payload(content, reconstructor_block, payload)
        else {
            return false;
        };
        reconstructor_accept_payload(
            payload_empty,
            enabled_or_self_source,
            source_not_output_side,
            true,
            Self::reconstructor_upgrade_unlocked_now(rules, upgrade),
            rules.is_unit_banned(upgrade.name()),
        )
    }

    fn payload_deconstructor_pay_rotation_step(current: f32, delta: f32) -> f32 {
        let target = 90.0_f32;
        let mut angle_delta = (target - current).rem_euclid(360.0);
        if angle_delta > 180.0 {
            angle_delta -= 360.0;
        }
        if angle_delta.abs() <= delta {
            target.rem_euclid(360.0)
        } else {
            (current + angle_delta.signum() * delta).rem_euclid(360.0)
        }
    }

    fn payload_block_unloadable(block: &BlockDef) -> bool {
        match block {
            BlockDef::Distribution(distribution) => distribution.unloadable,
            _ => true,
        }
    }

    fn payload_block_separate_item_capacity(block: Option<&BlockDef>) -> bool {
        matches!(block, Some(BlockDef::Storage(storage)) if storage.separate_item_capacity)
    }

    fn payload_block_consumes_item(block: Option<&BlockDef>, item_id: ContentId) -> bool {
        let consumes = |items: &[crate::mindustry::content::blocks::ItemAmount]| {
            items.iter().any(|stack| stack.item == item_id)
        };
        match block {
            Some(BlockDef::Production(production)) => consumes(&production.consume_items),
            Some(BlockDef::Effect(effect)) => {
                consumes(&effect.consume_items) || consumes(&effect.boost_items)
            }
            Some(BlockDef::Power(power)) => consumes(&power.consume_items),
            Some(BlockDef::Crafting(crafting)) => consumes(&crafting.consume_items),
            Some(BlockDef::UnitReconstructor(reconstructor)) => {
                consumes(&reconstructor.consume_items)
            }
            Some(BlockDef::Campaign(campaign)) => consumes(&campaign.consume_items),
            _ => false,
        }
    }

    fn payload_block_buffered_power_capacity(
        content: &ContentLoader,
        block_id: ContentId,
    ) -> Option<f32> {
        match content.block(block_id) {
            Some(BlockDef::Power(power)) if power.buffered_power > 0.0 => {
                Some(power.buffered_power)
            }
            _ => None,
        }
    }

    fn payload_ref_block_instant_deconstruct(
        content: &ContentLoader,
        payload: Option<&PayloadRef>,
    ) -> bool {
        match payload {
            Some(PayloadRef::Block { block, .. }) => content
                .block(*block)
                .map(|block| block.base().instant_deconstruct)
                .unwrap_or(false),
            _ => false,
        }
    }

    fn payload_loader_accepts_payload_ref(
        content: &ContentLoader,
        max_block_size: i32,
        base_accepts: bool,
        payload: &PayloadRef,
    ) -> bool {
        let PayloadRef::Block { block, .. } = payload else {
            return false;
        };
        let Some(block_def) = content.block(*block) else {
            return false;
        };
        let base = block_def.base();
        payload_loader_accept_payload(
            base_accepts,
            base.size as f32 <= max_block_size as f32,
            true,
            base.has_items,
            Self::payload_block_unloadable(block_def),
            base.item_capacity,
            base.size,
            max_block_size,
            base.has_liquids,
            base.liquid_capacity,
            Self::payload_block_buffered_power_capacity(content, base.id).is_some(),
        )
    }

    fn payload_router_candidate_accepts(
        &mut self,
        content: &ContentLoader,
        source_index: usize,
        payload_block: &crate::mindustry::content::blocks::PayloadBlockData,
        payload: &PayloadRef,
        rotation: i32,
        tick: f32,
    ) -> bool {
        let source = &self.buildings[source_index];
        let trns = payload_block.base.size / 2 + 1;
        let (dx, dy) = autotiler_direction(rotation);
        let Some(target_tile_pos) = self
            .state
            .world
            .build(source.tile_x() + dx * trns, source.tile_y() + dy * trns)
            .map(|target| target.tile_pos)
        else {
            return false;
        };
        if target_tile_pos == source.tile_pos {
            return false;
        }
        let Some(target_index) = self
            .buildings
            .iter()
            .position(|building| building.tile_pos == target_tile_pos)
        else {
            return false;
        };
        let source_team = self.buildings[source_index].team;
        let target_team = self.buildings[target_index].team;
        let target_enabled = self.buildings[target_index].enabled;
        if source_team != target_team {
            return false;
        }

        if matches!(
            content.block(self.buildings[target_index].block.id),
            Some(BlockDef::Payload(target_payload))
                if target_payload.kind == PayloadBlockKind::PayloadConveyor
        ) {
            self.pre_advance_plain_payload_conveyor_target(content, target_tile_pos, tick);
        }

        match (
            content.block(self.buildings[target_index].block.id),
            self.payload_runtime_states.get(&target_tile_pos),
        ) {
            (
                Some(BlockDef::Sandbox(target_sandbox)),
                Some(GameRuntimePayloadBlockState::Void(common)),
            ) if target_sandbox.kind == SandboxBlockKind::PayloadVoid => common.payload.is_none(),
            (
                Some(BlockDef::Payload(target_payload)),
                Some(GameRuntimePayloadBlockState::Conveyor(conveyor)),
            ) if matches!(
                target_payload.kind,
                PayloadBlockKind::PayloadConveyor | PayloadBlockKind::PayloadRouter
            ) =>
            {
                payload_conveyor_accept_payload(
                    conveyor.item.is_some(),
                    Self::payload_ref_fits_payload_limit(
                        content,
                        payload,
                        target_payload.payload_limit,
                    ),
                    true,
                    target_enabled,
                    conveyor.progress,
                )
            }
            (
                Some(BlockDef::Payload(target_payload)),
                Some(GameRuntimePayloadBlockState::Router { conveyor, .. }),
            ) if matches!(
                target_payload.kind,
                PayloadBlockKind::PayloadConveyor | PayloadBlockKind::PayloadRouter
            ) =>
            {
                payload_conveyor_accept_payload(
                    conveyor.item.is_some(),
                    Self::payload_ref_fits_payload_limit(
                        content,
                        payload,
                        target_payload.payload_limit,
                    ),
                    true,
                    target_enabled,
                    conveyor.progress,
                )
            }
            (
                Some(BlockDef::PayloadLoader(loader_block)),
                Some(GameRuntimePayloadBlockState::Loader { common, .. }),
            ) if loader_block.accepts_payload => Self::payload_loader_accepts_payload_ref(
                content,
                loader_block.max_block_size,
                common.payload.is_none(),
                payload,
            ),
            (
                Some(BlockDef::PayloadDeconstructor(deconstructor_block)),
                Some(GameRuntimePayloadBlockState::Deconstructor {
                    common,
                    deconstructor,
                }),
            ) if deconstructor_block.accepts_payload => {
                Self::payload_deconstructor_accepts_payload_ref(
                    content,
                    deconstructor_block.max_payload_size,
                    common,
                    deconstructor,
                    payload,
                )
            }
            _ => false,
        }
    }

    fn pick_owned_payload_router_next_rotation(
        &mut self,
        content: &ContentLoader,
        source_index: usize,
        payload_block: &crate::mindustry::content::blocks::PayloadBlockData,
        tick: f32,
    ) -> bool {
        let tile_pos = self.buildings[source_index].tile_pos;
        let (payload, sorted, rec_dir, control_time) = {
            let Some(GameRuntimePayloadBlockState::Router {
                conveyor,
                sorted,
                rec_dir,
                control_time,
                ..
            }) = self.payload_runtime_states.get(&tile_pos)
            else {
                return false;
            };
            let Some(payload) = conveyor.item.clone() else {
                return false;
            };
            (payload, *sorted, *rec_dir, *control_time)
        };
        if control_time > 0.0 {
            return false;
        }
        let payload_key = payload_ref_sort_key(&payload);
        let matches = payload_router_check_match(sorted, payload_key, payload_block.invert);
        let rec_dir = rec_dir.rem_euclid(4);
        let current_rotation = self.buildings[source_index].rotation.rem_euclid(4);
        let mut candidate_accepts = [false; 4];
        if !matches {
            for rotation in 0..4 {
                candidate_accepts[rotation as usize] = self.payload_router_candidate_accepts(
                    content,
                    source_index,
                    payload_block,
                    &payload,
                    rotation,
                    tick,
                );
            }
        }
        let next_rotation = payload_router_pick_next_rotation(
            current_rotation,
            rec_dir,
            matches,
            sorted.is_some(),
            candidate_accepts,
        );

        if let Some(GameRuntimePayloadBlockState::Router {
            matches: state_matches,
            ..
        }) = self.payload_runtime_states.get_mut(&tile_pos)
        {
            *state_matches = matches;
        }

        if next_rotation != current_rotation {
            self.buildings[source_index].set_rotation(next_rotation);
            true
        } else {
            false
        }
    }

    fn payload_ref_size_tiles(content: &ContentLoader, payload: &PayloadRef) -> Option<f32> {
        match payload {
            PayloadRef::Block { block, .. } => {
                content.block(*block).map(|block| block.base().size as f32)
            }
            PayloadRef::Unit { .. } => payload_ref_sort_key(payload)
                .filter(|key| key.content_type == ContentType::Unit.ordinal() as i8)
                .and_then(|key| content.unit(key.id))
                .map(|unit| unit.hit_size / TILE_SIZE as f32),
        }
    }

    fn payload_mass_driver_payload_fits(
        content: &ContentLoader,
        driver: &PayloadMassDriverBlockData,
        payload: &PayloadRef,
    ) -> bool {
        Self::payload_ref_size_tiles(content, payload)
            .map(|size| size <= driver.max_payload_size)
            .unwrap_or(false)
    }

    fn payload_mass_driver_link_index(
        &self,
        source_index: usize,
        link: i32,
        driver: &PayloadMassDriverBlockData,
    ) -> Option<usize> {
        if link == -1 {
            return None;
        }
        let source = &self.buildings[source_index];
        let target_index = self
            .buildings
            .iter()
            .position(|building| building.tile_pos == link)?;
        let target = &self.buildings[target_index];
        if target.team != source.team || target.block.id != source.block.id {
            return None;
        }
        let dx = target.x - source.x;
        let dy = target.y - source.y;
        let dst = (dx * dx + dy * dy).sqrt();
        (dst <= driver.range).then_some(target_index)
    }

    fn payload_mass_driver_waiting_shooter_valid(
        &self,
        content: &ContentLoader,
        receiver_tile_pos: i32,
        shooter_tile_pos: i32,
    ) -> bool {
        let Some(shooter_index) = self
            .buildings
            .iter()
            .position(|building| building.tile_pos == shooter_tile_pos)
        else {
            return false;
        };
        let Some(BlockDef::PayloadMassDriver(shooter_def)) =
            content.block(self.buildings[shooter_index].block.id)
        else {
            return false;
        };
        let Some(GameRuntimePayloadBlockState::MassDriver { driver, .. }) =
            self.payload_runtime_states.get(&shooter_tile_pos)
        else {
            return false;
        };
        self.payload_mass_driver_link_index(shooter_index, driver.link, shooter_def)
            .map(|target_index| self.buildings[target_index].tile_pos == receiver_tile_pos)
            .unwrap_or(false)
    }

    fn payload_mass_driver_angle_between_buildings(
        &self,
        source_index: usize,
        target_index: usize,
    ) -> f32 {
        Self::payload_angle_between(
            PayloadVec2 {
                x: self.buildings[source_index].x,
                y: self.buildings[source_index].y,
            },
            PayloadVec2 {
                x: self.buildings[target_index].x,
                y: self.buildings[target_index].y,
            },
        )
    }

    fn transfer_payload_output_to_front(
        &mut self,
        content: &ContentLoader,
        source_tile_pos: i32,
        target_tile_pos: i32,
    ) -> bool {
        #[derive(Debug, Clone, Copy)]
        enum TargetKind {
            Void,
            Conveyor {
                payload_limit: f32,
                move_time: f32,
                target_enabled: bool,
                target_rotdeg: f32,
                invert: bool,
            },
            Loader {
                max_block_size: i32,
            },
            Deconstructor {
                max_payload_size: f32,
            },
            Reconstructor,
            Assembler,
        }

        if source_tile_pos == target_tile_pos {
            return false;
        }

        let Some(source_index) = self
            .buildings
            .iter()
            .position(|building| building.tile_pos == source_tile_pos)
        else {
            return false;
        };
        let Some(target_index) = self
            .buildings
            .iter()
            .position(|building| building.tile_pos == target_tile_pos)
        else {
            return false;
        };

        if self.buildings[source_index].team != self.buildings[target_index].team {
            return false;
        }

        let target_kind = match content.block(self.buildings[target_index].block.id) {
            Some(BlockDef::Sandbox(target_sandbox))
                if target_sandbox.kind == SandboxBlockKind::PayloadVoid =>
            {
                TargetKind::Void
            }
            Some(BlockDef::Payload(payload_block))
                if matches!(
                    payload_block.kind,
                    PayloadBlockKind::PayloadConveyor | PayloadBlockKind::PayloadRouter
                ) =>
            {
                TargetKind::Conveyor {
                    payload_limit: payload_block.payload_limit,
                    move_time: payload_block.move_time,
                    target_enabled: self.buildings[target_index].enabled,
                    target_rotdeg: self.buildings[target_index].rotdeg(),
                    invert: payload_block.invert,
                }
            }
            Some(BlockDef::PayloadLoader(loader_block)) if loader_block.accepts_payload => {
                TargetKind::Loader {
                    max_block_size: loader_block.max_block_size,
                }
            }
            Some(BlockDef::PayloadDeconstructor(deconstructor_block))
                if deconstructor_block.accepts_payload =>
            {
                TargetKind::Deconstructor {
                    max_payload_size: deconstructor_block.max_payload_size,
                }
            }
            Some(BlockDef::UnitReconstructor(_)) => TargetKind::Reconstructor,
            Some(BlockDef::UnitAssembler(_)) => TargetKind::Assembler,
            _ => return false,
        };

        if matches!(
            target_kind,
            TargetKind::Reconstructor | TargetKind::Assembler
        ) {
            let target_building = self.buildings[target_index].clone();
            if !self.ensure_unit_state_for_building(content, &target_building) {
                return false;
            }
        }

        let source_payload = match self.payload_runtime_states.get(&source_tile_pos) {
            Some(GameRuntimePayloadBlockState::Source { common, .. })
            | Some(GameRuntimePayloadBlockState::Constructor { common, .. }) => {
                common.payload.as_ref()
            }
            Some(GameRuntimePayloadBlockState::Loader { common, .. }) => common.payload.as_ref(),
            Some(GameRuntimePayloadBlockState::Conveyor(conveyor)) => conveyor.item.as_ref(),
            Some(GameRuntimePayloadBlockState::Router { conveyor, .. }) => conveyor.item.as_ref(),
            _ => match self.unit_runtime_states.get(&source_tile_pos) {
                Some(GameRuntimeUnitBlockState::Factory { common, .. }) => common.payload.as_ref(),
                Some(GameRuntimeUnitBlockState::Reconstructor { common, .. }) => {
                    common.payload.as_ref()
                }
                Some(GameRuntimeUnitBlockState::AssemblerModule(common)) => common.payload.as_ref(),
                _ => None,
            },
        };
        let Some(source_payload) = source_payload else {
            return false;
        };

        let target_accepts = match (
            target_kind,
            self.payload_runtime_states.get(&target_tile_pos),
        ) {
            (TargetKind::Void, Some(GameRuntimePayloadBlockState::Void(common))) => {
                common.payload.is_none()
            }
            (
                TargetKind::Conveyor {
                    payload_limit,
                    target_enabled,
                    ..
                },
                Some(GameRuntimePayloadBlockState::Conveyor(conveyor)),
            ) => payload_conveyor_accept_payload(
                conveyor.item.is_some(),
                Self::payload_ref_fits_payload_limit(content, source_payload, payload_limit),
                false,
                target_enabled,
                conveyor.progress,
            ),
            (
                TargetKind::Conveyor {
                    payload_limit,
                    target_enabled,
                    ..
                },
                Some(GameRuntimePayloadBlockState::Router { conveyor, .. }),
            ) => payload_conveyor_accept_payload(
                conveyor.item.is_some(),
                Self::payload_ref_fits_payload_limit(content, source_payload, payload_limit),
                false,
                target_enabled,
                conveyor.progress,
            ),
            (
                TargetKind::Loader { max_block_size },
                Some(GameRuntimePayloadBlockState::Loader { common, .. }),
            ) => Self::payload_loader_accepts_payload_ref(
                content,
                max_block_size,
                common.payload.is_none(),
                source_payload,
            ),
            (
                TargetKind::Deconstructor { max_payload_size },
                Some(GameRuntimePayloadBlockState::Deconstructor {
                    common,
                    deconstructor,
                }),
            ) => Self::payload_deconstructor_accepts_payload_ref(
                content,
                max_payload_size,
                common,
                deconstructor,
                source_payload,
            ),
            (TargetKind::Reconstructor, _) => {
                let Some(BlockDef::UnitReconstructor(reconstructor_block)) =
                    content.block(self.buildings[target_index].block.id)
                else {
                    return false;
                };
                let source_not_output_side = Self::building_source_not_output_side(
                    &self.buildings[target_index],
                    &self.buildings[source_index],
                );
                match self.unit_runtime_states.get(&target_tile_pos) {
                    Some(GameRuntimeUnitBlockState::Reconstructor { common, .. }) => {
                        Self::reconstructor_accepts_payload_ref_with_rules(
                            content,
                            &self.state.rules,
                            reconstructor_block,
                            self.buildings[target_index].team,
                            common.payload.is_none(),
                            self.buildings[target_index].enabled,
                            source_not_output_side,
                            source_payload,
                        )
                    }
                    _ => false,
                }
            }
            (TargetKind::Assembler, _) => {
                let Some(BlockDef::UnitAssembler(assembler_block)) =
                    content.block(self.buildings[target_index].block.id)
                else {
                    return false;
                };
                let source_is_module = matches!(
                    content.block(self.buildings[source_index].block.id),
                    Some(BlockDef::UnitAssemblerModule(_))
                );
                let Some(source_key) =
                    payload_ref_sort_key(source_payload).and_then(Self::payload_key_from_sort_key)
                else {
                    return false;
                };
                let unit_cost = self
                    .state
                    .rules
                    .unit_cost(self.buildings[target_index].team.0 as usize);
                match self.unit_runtime_states.get(&target_tile_pos) {
                    Some(GameRuntimeUnitBlockState::Assembler { common, assembler }) => {
                        let current_tier = if source_is_module {
                            unit_assembler_current_tier(self.linked_module_tiers_for_assembler(
                                content,
                                target_index,
                                assembler_block,
                            ))
                        } else {
                            assembler.current_tier
                        }
                        .max(0) as usize;
                        let Some(plan) = assembler_block
                            .plans
                            .get(current_tier.min(assembler_block.plans.len().saturating_sub(1)))
                        else {
                            return false;
                        };
                        let Some(payload_requirements) =
                            Self::assembler_payload_requirements(content, plan, unit_cost)
                        else {
                            return false;
                        };
                        let Some((_, required_amount)) = payload_requirements
                            .iter()
                            .find(|(key, _)| *key == source_key)
                        else {
                            return false;
                        };
                        let same_payload_already_held_from_module = source_is_module
                            && common
                                .payload
                                .as_ref()
                                .and_then(payload_ref_sort_key)
                                .and_then(Self::payload_key_from_sort_key)
                                == Some(source_key);
                        unit_assembler_accept_payload(
                            common.payload.is_none(),
                            source_is_module,
                            *required_amount,
                            assembler.blocks.get(source_key),
                            unit_cost,
                            same_payload_already_held_from_module,
                        )
                    }
                    _ => false,
                }
            }
            _ => false,
        };
        if !target_accepts {
            return false;
        }

        let source_pos = PayloadVec2 {
            x: self.buildings[source_index].x,
            y: self.buildings[source_index].y,
        };
        let target_pos = PayloadVec2 {
            x: self.buildings[target_index].x,
            y: self.buildings[target_index].y,
        };
        let target_size = self.buildings[target_index].block.size;
        let source_rotdeg = self.buildings[source_index].rotdeg();
        let source_angle_to_target = Self::payload_angle_between(source_pos, target_pos);

        let source_payload_take = self
            .payload_runtime_states
            .get_mut(&source_tile_pos)
            .and_then(|state| match state {
                GameRuntimePayloadBlockState::Source { common, source } => {
                    let payload = common.payload.take()?;
                    source.has_payload = false;
                    Some((payload, common.pay_rotation))
                }
                GameRuntimePayloadBlockState::Constructor {
                    common, producer, ..
                } => {
                    let payload = common.payload.take()?;
                    producer.has_payload = false;
                    Some((payload, common.pay_rotation))
                }
                GameRuntimePayloadBlockState::Loader { common, loader } => {
                    let payload = common.payload.take()?;
                    loader.has_payload = false;
                    loader.exporting = false;
                    Some((payload, common.pay_rotation))
                }
                GameRuntimePayloadBlockState::Conveyor(conveyor) => {
                    let payload = conveyor.item.take()?;
                    Some((payload, source_rotdeg))
                }
                GameRuntimePayloadBlockState::Router { conveyor, .. } => {
                    let payload = conveyor.item.take()?;
                    Some((payload, source_rotdeg))
                }
                _ => None,
            })
            .or_else(|| {
                self.unit_runtime_states
                    .get_mut(&source_tile_pos)
                    .and_then(|state| match state {
                        GameRuntimeUnitBlockState::Factory { common, factory } => {
                            let payload = common.payload.take()?;
                            factory.base.has_payload = false;
                            Some((payload, common.pay_rotation))
                        }
                        GameRuntimeUnitBlockState::Reconstructor {
                            common,
                            reconstructor,
                        } => {
                            let payload = common.payload.take()?;
                            reconstructor.base.has_payload = false;
                            reconstructor.constructing = false;
                            Some((payload, common.pay_rotation))
                        }
                        GameRuntimeUnitBlockState::AssemblerModule(common) => {
                            let payload = common.payload.take()?;
                            Some((payload, common.pay_rotation))
                        }
                        _ => None,
                    })
            });

        let Some((payload, payload_rotation)) = source_payload_take else {
            return false;
        };

        let mut payload = Some(payload);
        let transferred = match (
            target_kind,
            self.payload_runtime_states.get_mut(&target_tile_pos),
        ) {
            (TargetKind::Void, Some(GameRuntimePayloadBlockState::Void(common)))
                if common.payload.is_none() =>
            {
                payload_block_handle_payload(
                    common,
                    payload.take().expect("payload should be present"),
                    target_pos,
                    source_pos,
                    payload_rotation,
                    target_size,
                    TILE_SIZE as f32,
                );
                true
            }
            (
                TargetKind::Loader { max_block_size },
                Some(GameRuntimePayloadBlockState::Loader { common, loader }),
            ) if common.payload.is_none()
                && payload
                    .as_ref()
                    .map(|payload| {
                        Self::payload_loader_accepts_payload_ref(
                            content,
                            max_block_size,
                            true,
                            payload,
                        )
                    })
                    .unwrap_or(false) =>
            {
                payload_block_handle_payload(
                    common,
                    payload.take().expect("payload should be present"),
                    target_pos,
                    source_pos,
                    payload_rotation,
                    target_size,
                    TILE_SIZE as f32,
                );
                loader.exporting = false;
                loader.has_payload = true;
                true
            }
            (
                TargetKind::Deconstructor { max_payload_size },
                Some(GameRuntimePayloadBlockState::Deconstructor {
                    common,
                    deconstructor,
                }),
            ) if common.payload.is_none()
                && payload
                    .as_ref()
                    .map(|payload| {
                        Self::payload_deconstructor_accepts_payload_ref(
                            content,
                            max_payload_size,
                            common,
                            deconstructor,
                            payload,
                        )
                    })
                    .unwrap_or(false) =>
            {
                payload_block_handle_payload(
                    common,
                    payload.take().expect("payload should be present"),
                    target_pos,
                    source_pos,
                    payload_rotation,
                    target_size,
                    TILE_SIZE as f32,
                );
                deconstructor.accum = None;
                deconstructor.has_payload = true;
                deconstructor.has_deconstructing = deconstructor.deconstructing.is_some();
                true
            }
            (
                TargetKind::Conveyor {
                    payload_limit,
                    move_time,
                    target_enabled,
                    target_rotdeg,
                    invert: _,
                },
                Some(GameRuntimePayloadBlockState::Conveyor(conveyor)),
            ) if payload_conveyor_accept_payload(
                conveyor.item.is_some(),
                payload
                    .as_ref()
                    .map(|payload| {
                        Self::payload_ref_fits_payload_limit(content, payload, payload_limit)
                    })
                    .unwrap_or(false),
                false,
                target_enabled,
                conveyor.progress,
            ) =>
            {
                let cur_step = payload_conveyor_cur_step(self.state.tick as f32, move_time);
                payload_conveyor_handle_payload(
                    conveyor,
                    payload.take().expect("payload should be present"),
                    cur_step,
                    false,
                    target_rotdeg,
                    source_angle_to_target,
                );
                true
            }
            (
                TargetKind::Conveyor {
                    payload_limit,
                    move_time,
                    target_enabled,
                    target_rotdeg,
                    invert,
                },
                Some(GameRuntimePayloadBlockState::Router {
                    conveyor,
                    sorted,
                    rec_dir,
                    matches,
                    smooth_rot,
                    control_time,
                }),
            ) if payload_conveyor_accept_payload(
                conveyor.item.is_some(),
                payload
                    .as_ref()
                    .map(|payload| {
                        Self::payload_ref_fits_payload_limit(content, payload, payload_limit)
                    })
                    .unwrap_or(false),
                false,
                target_enabled,
                conveyor.progress,
            ) =>
            {
                let cur_step = payload_conveyor_cur_step(self.state.tick as f32, move_time);
                payload_conveyor_handle_payload(
                    conveyor,
                    payload.take().expect("payload should be present"),
                    cur_step,
                    false,
                    target_rotdeg,
                    source_angle_to_target,
                );
                *matches = conveyor
                    .item
                    .as_ref()
                    .and_then(|payload_ref| payload_ref_sort_key(payload_ref))
                    .map(|payload_key| {
                        payload_router_check_match(*sorted, Some(payload_key), invert)
                    })
                    .unwrap_or_else(|| payload_router_check_match(*sorted, None, invert));
                if *control_time < 0.0 {
                    let source_building = &self.buildings[source_index];
                    let target_building = &self.buildings[target_index];
                    let dx = source_building.x - target_building.x;
                    let dy = source_building.y - target_building.y;
                    *rec_dir = if dx.abs() > dy.abs() {
                        if source_building.x <= target_building.x - 1.0 {
                            0
                        } else if source_building.x >= target_building.x + 1.0 {
                            2
                        } else {
                            *rec_dir
                        }
                    } else if source_building.y <= target_building.y - 1.0 {
                        1
                    } else if source_building.y >= target_building.y + 1.0 {
                        3
                    } else {
                        *rec_dir
                    };
                }
                *smooth_rot = target_rotdeg;
                true
            }
            (TargetKind::Reconstructor, _) => {
                let Some(BlockDef::UnitReconstructor(reconstructor_block)) =
                    content.block(self.buildings[target_index].block.id)
                else {
                    return false;
                };
                let source_not_output_side = Self::building_source_not_output_side(
                    &self.buildings[target_index],
                    &self.buildings[source_index],
                );
                let target_team = self.buildings[target_index].team;
                let target_enabled = self.buildings[target_index].enabled;
                let reconstructor_accepts = payload
                    .as_ref()
                    .map(|payload| {
                        Self::reconstructor_accepts_payload_ref_with_rules(
                            content,
                            &self.state.rules,
                            reconstructor_block,
                            target_team,
                            true,
                            target_enabled,
                            source_not_output_side,
                            payload,
                        )
                    })
                    .unwrap_or(false);
                let Some(GameRuntimeUnitBlockState::Reconstructor {
                    common,
                    reconstructor,
                }) = self.unit_runtime_states.get_mut(&target_tile_pos)
                else {
                    return false;
                };
                if common.payload.is_none() && reconstructor_accepts {
                    payload_block_handle_payload(
                        common,
                        payload.take().expect("payload should be present"),
                        target_pos,
                        source_pos,
                        payload_rotation,
                        target_size,
                        TILE_SIZE as f32,
                    );
                    reconstructor.base.has_payload = true;
                    reconstructor.constructing = true;
                    true
                } else {
                    false
                }
            }
            (TargetKind::Assembler, _) => {
                let Some(GameRuntimeUnitBlockState::Assembler { common, .. }) =
                    self.unit_runtime_states.get_mut(&target_tile_pos)
                else {
                    return false;
                };
                if common.payload.is_none() {
                    payload_block_handle_payload(
                        common,
                        payload.take().expect("payload should be present"),
                        target_pos,
                        source_pos,
                        payload_rotation,
                        target_size,
                        TILE_SIZE as f32,
                    );
                    true
                } else {
                    false
                }
            }
            _ => false,
        };

        if !transferred {
            if let Some(payload) = payload {
                match self.payload_runtime_states.get_mut(&source_tile_pos) {
                    Some(GameRuntimePayloadBlockState::Source { common, source }) => {
                        if common.payload.is_none() {
                            common.payload = Some(payload);
                            source.has_payload = true;
                        }
                    }
                    Some(GameRuntimePayloadBlockState::Constructor {
                        common, producer, ..
                    }) => {
                        if common.payload.is_none() {
                            common.payload = Some(payload);
                            producer.has_payload = true;
                        }
                    }
                    Some(GameRuntimePayloadBlockState::Loader { common, loader }) => {
                        if common.payload.is_none() {
                            common.payload = Some(payload);
                            loader.has_payload = true;
                        }
                    }
                    Some(GameRuntimePayloadBlockState::Deconstructor {
                        common,
                        deconstructor,
                    }) => {
                        if common.payload.is_none() {
                            common.payload = Some(payload);
                            deconstructor.has_payload = true;
                        }
                    }
                    Some(GameRuntimePayloadBlockState::Conveyor(conveyor)) => {
                        if conveyor.item.is_none() {
                            conveyor.item = Some(payload);
                        }
                    }
                    Some(GameRuntimePayloadBlockState::Router { conveyor, .. }) => {
                        if conveyor.item.is_none() {
                            conveyor.item = Some(payload);
                        }
                    }
                    _ => {
                        if let Some(state) = self.unit_runtime_states.get_mut(&source_tile_pos) {
                            match state {
                                GameRuntimeUnitBlockState::Factory { common, factory } => {
                                    if common.payload.is_none() {
                                        common.payload = Some(payload);
                                        factory.base.has_payload = true;
                                    }
                                }
                                GameRuntimeUnitBlockState::Reconstructor {
                                    common,
                                    reconstructor,
                                } => {
                                    if common.payload.is_none() {
                                        common.payload = Some(payload);
                                        reconstructor.base.has_payload = true;
                                    }
                                }
                                GameRuntimeUnitBlockState::AssemblerModule(common) => {
                                    if common.payload.is_none() {
                                        common.payload = Some(payload);
                                    }
                                }
                                _ => {}
                            }
                        }
                    }
                }
            }
        }

        transferred
    }

    fn payload_ref_fits_payload_limit(
        content: &ContentLoader,
        payload: &PayloadRef,
        payload_limit: f32,
    ) -> bool {
        match payload {
            PayloadRef::Block { block, .. } => content
                .block(*block)
                .map(|block| block.base().size as f32 <= payload_limit)
                .unwrap_or(false),
            PayloadRef::Unit { .. } => payload_ref_sort_key(payload)
                .filter(|key| key.content_type == ContentType::Unit.ordinal() as i8)
                .and_then(|key| content.unit(key.id))
                .map(|unit| unit.hit_size / TILE_SIZE as f32 <= payload_limit)
                .unwrap_or(false),
        }
    }

    fn building_source_not_output_side(target: &BuildingComp, source: &BuildingComp) -> bool {
        if target.tile_pos == source.tile_pos {
            return true;
        }
        let dx = source.tile_x() - target.tile_x();
        let dy = source.tile_y() - target.tile_y();
        let source_side = if dx.abs() >= dy.abs() && dx != 0 {
            if dx > 0 {
                0
            } else {
                2
            }
        } else if dy != 0 {
            if dy > 0 {
                1
            } else {
                3
            }
        } else {
            return true;
        };
        source_side != target.rotation.rem_euclid(4)
    }

    fn payload_angle_between(from: PayloadVec2, to: PayloadVec2) -> f32 {
        let mut angle = (to.y - from.y).atan2(to.x - from.x).to_degrees();
        if angle < 0.0 {
            angle += 360.0;
        }
        angle
    }

    fn payload_router_smooth_rot_step(current: f32, target: f32, delta_ticks: f32) -> f32 {
        let delta = ((target - current + 540.0).rem_euclid(360.0)) - 180.0;
        let alpha = 1.0 - (1.0_f32 - 0.2_f32).powf(delta_ticks.max(0.0));
        (current + delta * alpha.clamp(0.0, 1.0)).rem_euclid(360.0)
    }

    fn pre_advance_plain_payload_conveyor_target(
        &mut self,
        content: &ContentLoader,
        tile_pos: i32,
        tick: f32,
    ) -> bool {
        let Some(index) = self
            .buildings
            .iter()
            .position(|building| building.tile_pos == tile_pos)
        else {
            return false;
        };
        if !self.buildings[index].enabled {
            return false;
        }

        let Some(BlockDef::Payload(payload_block)) = content.block(self.buildings[index].block.id)
        else {
            return false;
        };
        if payload_block.kind != PayloadBlockKind::PayloadConveyor {
            return false;
        }

        let rotation = self.buildings[index].rotation;
        let trns = payload_block.base.size / 2 + 1;
        let (dx, dy) = autotiler_direction(rotation);
        let target_tile_pos = self
            .state
            .world
            .build(
                point2_x(tile_pos) as i32 + dx * trns,
                point2_y(tile_pos) as i32 + dy * trns,
            )
            .map(|target| target.tile_pos);

        let Some(GameRuntimePayloadBlockState::Conveyor(conveyor)) =
            self.payload_runtime_states.get_mut(&tile_pos)
        else {
            return false;
        };
        let progress = tick % payload_block.move_time;
        let interp_progress = (progress / payload_block.move_time).clamp(0.0, 1.0);
        payload_conveyor_update_timing(conveyor, tick, payload_block.move_time, interp_progress);
        let cur_step = payload_conveyor_cur_step(tick, payload_block.move_time);
        if !payload_conveyor_should_attempt_move(conveyor, cur_step) {
            return false;
        }

        target_tile_pos
            .map(|target_tile_pos| {
                self.transfer_payload_output_to_front(content, tile_pos, target_tile_pos)
            })
            .unwrap_or(false)
    }

    pub fn advance_owned_payload_conveyors(
        &mut self,
        content: &ContentLoader,
        delta_seconds: f32,
    ) -> Option<GameRuntimePayloadConveyorFrameReport> {
        self.consume_world_load_events_and_reset_sidecars();

        let advanced = self.state.advance_game_update_frame(delta_seconds);
        if !advanced.advanced {
            return None;
        }

        self.refresh_owned_building_update_permissions(content);

        let frame_delta = advanced.delta_ticks as f32;
        let tick = advanced.tick as f32;
        for building in self.buildings.iter_mut() {
            let can_overdrive = content
                .block(building.block.id)
                .map(BlockDef::can_overdrive)
                .unwrap_or(false);
            building.advance_update_timing(frame_delta, can_overdrive);
        }

        Some(self.advance_owned_payload_conveyors_ticks(content, frame_delta, tick))
    }

    fn advance_owned_payload_conveyors_ticks(
        &mut self,
        content: &ContentLoader,
        frame_delta: f32,
        tick: f32,
    ) -> GameRuntimePayloadConveyorFrameReport {
        let mut report = GameRuntimePayloadConveyorFrameReport::default();
        let mut pending_payload_moves = Vec::new();

        for index in 0..self.buildings.len() {
            let (tile_pos, block_id, enabled) = {
                let building = &self.buildings[index];
                report.visited_buildings += 1;
                (building.tile_pos, building.block.id, building.enabled)
            };

            if !enabled {
                continue;
            }

            let Some(BlockDef::Payload(payload_block)) = content.block(block_id) else {
                continue;
            };
            if !matches!(
                payload_block.kind,
                PayloadBlockKind::PayloadConveyor | PayloadBlockKind::PayloadRouter
            ) {
                continue;
            }
            report.conveyor_candidates += 1;

            if payload_block.kind == PayloadBlockKind::PayloadRouter {
                self.pick_owned_payload_router_next_rotation(content, index, payload_block, tick);
            }

            let rotation = self.buildings[index].rotation;
            let trns = payload_block.base.size / 2 + 1;
            let (dx, dy) = autotiler_direction(rotation);
            let target_tile_pos = self
                .state
                .world
                .build(
                    point2_x(tile_pos) as i32 + dx * trns,
                    point2_y(tile_pos) as i32 + dy * trns,
                )
                .map(|target| target.tile_pos);

            let Some(state) = self.payload_runtime_states.get_mut(&tile_pos) else {
                report.missing_runtime_states += 1;
                continue;
            };

            let progress_time = tick;
            let progress = progress_time % payload_block.move_time;
            let interp_progress = (progress / payload_block.move_time).clamp(0.0, 1.0);
            let should_attempt_move = match state {
                GameRuntimePayloadBlockState::Conveyor(conveyor) => {
                    payload_conveyor_update_timing(
                        conveyor,
                        progress_time,
                        payload_block.move_time,
                        interp_progress,
                    );
                    let cur_step =
                        payload_conveyor_cur_step(progress_time, payload_block.move_time);
                    payload_conveyor_should_attempt_move(conveyor, cur_step)
                }
                GameRuntimePayloadBlockState::Router {
                    conveyor,
                    control_time,
                    smooth_rot,
                    ..
                } => {
                    payload_conveyor_update_timing(
                        conveyor,
                        progress_time,
                        payload_block.move_time,
                        interp_progress,
                    );
                    *control_time -= frame_delta;
                    *smooth_rot = Self::payload_router_smooth_rot_step(
                        *smooth_rot,
                        rotation as f32 * 90.0,
                        frame_delta,
                    );
                    let cur_step =
                        payload_conveyor_cur_step(progress_time, payload_block.move_time);
                    payload_conveyor_should_attempt_move(conveyor, cur_step)
                }
                _ => {
                    report.missing_runtime_states += 1;
                    continue;
                }
            };
            report.updated_conveyors += 1;

            if should_attempt_move {
                report.attempted_moves += 1;
                if let Some(target_tile_pos) = target_tile_pos {
                    pending_payload_moves.push((tile_pos, target_tile_pos));
                } else if payload_block.kind == PayloadBlockKind::PayloadRouter {
                    self.pick_owned_payload_router_next_rotation(
                        content,
                        index,
                        payload_block,
                        tick,
                    );
                }
            }
        }

        for (source_tile_pos, target_tile_pos) in pending_payload_moves {
            if self.pre_advance_plain_payload_conveyor_target(content, target_tile_pos, tick) {
                report.transferred_payloads += 1;
            }
            if self.transfer_payload_output_to_front(content, source_tile_pos, target_tile_pos) {
                report.transferred_payloads += 1;
            } else if let Some(source_index) = self
                .buildings
                .iter()
                .position(|building| building.tile_pos == source_tile_pos)
            {
                if let Some(BlockDef::Payload(payload_block)) =
                    content.block(self.buildings[source_index].block.id)
                {
                    if payload_block.kind == PayloadBlockKind::PayloadRouter {
                        self.pick_owned_payload_router_next_rotation(
                            content,
                            source_index,
                            payload_block,
                            tick,
                        );
                    }
                }
            }
        }

        report
    }

    fn create_common_unit_payload_ref(
        content: &ContentLoader,
        unit: &crate::mindustry::r#type::UnitType,
        unit_id: ContentId,
        team: crate::mindustry::io::TeamId,
        x: f32,
        y: f32,
        rotation: f32,
        command_pos: Option<PayloadVec2>,
    ) -> io::Result<PayloadRef> {
        const UNIT_ENTITY_CLASS_ID: u8 = 3;
        const UNIT_ENTITY_REVISION: i16 = 9;

        let controller = match command_pos {
            Some(pos) => type_io::ControllerWire::Command(type_io::CommandWire {
                target_pos: Some(type_io::Vec2 { x: pos.x, y: pos.y }),
                ..type_io::CommandWire::new()
            }),
            None => type_io::ControllerWire::Ground,
        };
        let mut unit_bytes = Vec::new();
        type_io::write_i16(&mut unit_bytes, UNIT_ENTITY_REVISION)?;
        type_io::write_abilities(&mut unit_bytes, &[])?;
        type_io::write_f32(&mut unit_bytes, x)?;
        type_io::write_f32(&mut unit_bytes, y)?;
        type_io::write_controller(&mut unit_bytes, &controller)?;
        type_io::write_f32(&mut unit_bytes, if unit.flying { 1.0 } else { 0.0 })?;
        type_io::write_u64(&mut unit_bytes, 0.0f64.to_bits())?;
        type_io::write_f32(&mut unit_bytes, unit.health)?;
        type_io::write_bool(&mut unit_bytes, false)?;
        type_io::write_tile_pos(&mut unit_bytes, None)?;
        type_io::write_mounts(&mut unit_bytes, &[])?;
        type_io::write_plans_queue_net(&mut unit_bytes, content, Some(&[]))?;
        type_io::write_f32(&mut unit_bytes, rotation)?;
        type_io::write_f32(&mut unit_bytes, 0.0)?;
        type_io::write_bool(&mut unit_bytes, false)?;
        type_io::write_items(
            &mut unit_bytes,
            content,
            &crate::mindustry::r#type::ItemStack::new("", 0),
        )?;
        type_io::write_statuses(&mut unit_bytes, &[])?;
        type_io::write_team(&mut unit_bytes, Some(team))?;
        type_io::write_i16(&mut unit_bytes, unit_id)?;
        type_io::write_bool(&mut unit_bytes, false)?;
        type_io::write_vec2(&mut unit_bytes, type_io::Vec2 { x: 0.0, y: 0.0 })?;
        type_io::write_f32(&mut unit_bytes, x)?;
        type_io::write_f32(&mut unit_bytes, y)?;
        Ok(PayloadRef::Unit {
            class_id: UNIT_ENTITY_CLASS_ID,
            unit_bytes,
        })
    }

    pub fn advance_owned_unit_factories(
        &mut self,
        content: &ContentLoader,
        delta_seconds: f32,
    ) -> Option<GameRuntimeUnitFactoryFrameReport> {
        self.consume_world_load_events_and_reset_sidecars();

        let advanced = self.state.advance_game_update_frame(delta_seconds);
        if !advanced.advanced {
            return None;
        }

        self.refresh_owned_building_update_permissions(content);

        let frame_delta = advanced.delta_ticks as f32;
        for building in self.buildings.iter_mut() {
            let can_overdrive = content
                .block(building.block.id)
                .map(BlockDef::can_overdrive)
                .unwrap_or(false);
            building.advance_update_timing(frame_delta, can_overdrive);
        }

        Some(self.advance_owned_unit_factories_ticks(content, frame_delta))
    }

    fn advance_owned_unit_factories_ticks(
        &mut self,
        content: &ContentLoader,
        frame_delta: f32,
    ) -> GameRuntimeUnitFactoryFrameReport {
        let mut report = GameRuntimeUnitFactoryFrameReport::default();

        for index in 0..self.buildings.len() {
            let (tile_pos, block_id, enabled, efficiency, time_scale, rotation, rotdeg, team, x, y) = {
                let building = &self.buildings[index];
                report.visited_buildings += 1;
                (
                    building.tile_pos,
                    building.block.id,
                    building.enabled,
                    building.efficiency,
                    building.time_scale,
                    building.rotation,
                    building.rotdeg(),
                    building.team,
                    building.x,
                    building.y,
                )
            };

            let Some(BlockDef::UnitFactory(factory_block)) = content.block(block_id) else {
                continue;
            };
            report.factory_candidates += 1;

            if !enabled {
                continue;
            }

            if !self.unit_runtime_states.contains_key(&tile_pos) {
                let building = self.buildings[index].clone();
                if !self.ensure_unit_state_for_building(content, &building) {
                    report.missing_runtime_states += 1;
                    continue;
                }
            }

            let trns = factory_block.base.size / 2 + 1;
            let (dx, dy) = autotiler_direction(rotation);
            let target_tile_pos = self
                .state
                .world
                .build(
                    point2_x(tile_pos) as i32 + dx * trns,
                    point2_y(tile_pos) as i32 + dy * trns,
                )
                .map(|target| target.tile_pos);

            let unit_cost = self.state.rules.unit_cost(team.0 as usize);
            let unit_build_speed = self.state.rules.unit_build_speed(team.0 as usize);
            let team_activates_factories = self
                .state
                .rules
                .unit_factory_active(team.0 as usize, self.state.tick);

            let current_plan = self
                .unit_runtime_states
                .get(&tile_pos)
                .and_then(|state| match state {
                    GameRuntimeUnitBlockState::Factory { factory, .. } => {
                        Some(factory.current_plan)
                    }
                    _ => None,
                })
                .unwrap_or(-1);
            let plan = (current_plan >= 0)
                .then(|| factory_block.plans.get(current_plan as usize))
                .flatten();
            let plan_unit = plan.and_then(|plan| content.unit_by_name(&plan.unit));
            let plan_requirements = plan
                .map(|plan| scaled_item_requirements(&plan.requirements, unit_cost))
                .unwrap_or_default();
            let has_required_items = building_has_items(&self.buildings[index], &plan_requirements);
            let plan_time = plan.map(|plan| plan.time).unwrap_or(0.0);
            let plan_banned = plan_unit
                .map(|unit| self.state.rules.is_unit_banned(unit.name()))
                .unwrap_or(false);

            let mut consume_items = false;
            let mut arrived_output = false;
            let mut created_unit_name = None;
            {
                let Some(GameRuntimeUnitBlockState::Factory { common, factory }) =
                    self.unit_runtime_states.get_mut(&tile_pos)
                else {
                    report.missing_runtime_states += 1;
                    continue;
                };

                factory.base.has_payload = common.payload.is_some();
                if common.payload.is_some() {
                    report.moved_out_payloads += 1;
                    let arrived = payload_block_move_out_step(
                        common,
                        rotdeg,
                        factory_block.base.size,
                        TILE_SIZE as f32,
                        DEFAULT_PAYLOAD_SPEED,
                        DEFAULT_PAYLOAD_ROTATE_SPEED,
                        frame_delta * time_scale,
                    );
                    if arrived {
                        report.arrived_output_payloads += 1;
                        arrived_output = true;
                    }
                }
            }

            if arrived_output {
                if let Some(target_tile_pos) = target_tile_pos {
                    if self.transfer_payload_output_to_front(content, tile_pos, target_tile_pos) {
                        report.transferred_payloads += 1;
                        report.spawned_tiles.push(tile_pos);
                    }
                }
            }

            {
                let Some(GameRuntimeUnitBlockState::Factory { common, factory }) =
                    self.unit_runtime_states.get_mut(&tile_pos)
                else {
                    report.missing_runtime_states += 1;
                    continue;
                };

                factory.base.has_payload = common.payload.is_some();

                if !team_activates_factories {
                    report.inactive_factories += 1;
                }
                let effective_efficiency =
                    if team_activates_factories && common.payload.is_none() && has_required_items {
                        efficiency
                    } else {
                        0.0
                    };
                let update = unit_factory_update(
                    factory,
                    factory_block.configurable,
                    factory_block.plans.len(),
                    effective_efficiency,
                    frame_delta * time_scale * effective_efficiency,
                    unit_build_speed,
                    plan_time,
                    plan_banned,
                );
                report.updated_factories += 1;
                if update.current_plan == -1 && current_plan != -1 {
                    report.invalid_plans += 1;
                }

                if update.created_unit {
                    let Some(unit_type) = plan_unit else {
                        factory.base.has_payload = common.payload.is_some();
                        report.invalid_plans += 1;
                        continue;
                    };
                    let mut unit = UnitComp::new(0, unit_type.clone(), team);
                    unit.set_pos(x, y);
                    unit.set_rotation(rotdeg);
                    if let Some(mut payload) = Self::unit_payload_ref_from_unit(content, &unit) {
                        let command_id = factory
                            .command_id
                            .map(|id| id as ContentId)
                            .or_else(|| Self::unit_default_command_id(content, unit_type));
                        if command_id.is_some() || factory.command_pos.is_some() {
                            let _ = Self::payload_ref_patch_unit_controller(
                                &mut payload,
                                &type_io::ControllerWire::Command(type_io::CommandWire {
                                    target_pos: factory.command_pos,
                                    command_id,
                                    ..type_io::CommandWire::new()
                                }),
                            );
                        }
                        common.payload = Some(payload);
                        common.pay_vector = PayloadVec2::ZERO;
                        common.pay_rotation = rotdeg;
                        factory.base.has_payload = true;
                        consume_items = !plan_requirements.is_empty();
                        report.produced_unit_payloads += 1;
                        created_unit_name = Some(unit_type.name().to_string());
                    } else {
                        factory.base.has_payload = common.payload.is_some();
                        report.invalid_plans += 1;
                    }
                }
            }

            if consume_items {
                consume_building_items(&mut self.buildings[index], &plan_requirements);
                report.consumed_item_batches += 1;
            }
            if let Some(unit_name) = created_unit_name {
                self.note_unit_create_event(None, unit_name, team, Some(tile_pos), None);
            }
        }

        report
    }

    fn assembler_payload_requirements(
        content: &ContentLoader,
        plan: &crate::mindustry::content::blocks::AssemblerUnitPlanSpec,
        unit_cost: f32,
    ) -> Option<Vec<(PayloadKey, i32)>> {
        let unit_cost = if unit_cost.is_finite() {
            unit_cost.max(0.0)
        } else {
            0.0
        };
        plan.payload_requirements
            .iter()
            .map(|stack| {
                let key = match &stack.content {
                    crate::mindustry::content::blocks::PayloadContentSpec::Unit(name) => content
                        .unit_by_name(name)
                        .map(|unit| PayloadKey::new(ContentType::Unit, unit.base.mappable.base.id)),
                    crate::mindustry::content::blocks::PayloadContentSpec::Block(name) => content
                        .block_by_name(name)
                        .map(|block| PayloadKey::new(ContentType::Block, block.base().id)),
                }?;
                let amount = ((stack.amount as f32) * unit_cost).ceil() as i32;
                Some((key, amount.max(0)))
            })
            .collect()
    }

    fn payload_key_from_sort_key(sort_key: PayloadSortKey) -> Option<PayloadKey> {
        if sort_key.content_type == ContentType::Unit.ordinal() as i8 {
            Some(PayloadKey::new(ContentType::Unit, sort_key.id))
        } else if sort_key.content_type == ContentType::Block.ordinal() as i8 {
            Some(PayloadKey::new(ContentType::Block, sort_key.id))
        } else {
            None
        }
    }

    fn payload_seq_contains_requirements(
        payloads: &PayloadSeq,
        requirements: &[(PayloadKey, i32)],
    ) -> bool {
        requirements
            .iter()
            .all(|(key, amount)| *amount <= 0 || payloads.contains(*key, *amount))
    }

    fn relative_direction(from_x: f32, from_y: f32, to_x: f32, to_y: f32) -> i32 {
        let dx = to_x - from_x;
        let dy = to_y - from_y;
        if dx.abs() >= dy.abs() && dx.abs() > f32::EPSILON {
            if dx > 0.0 {
                0
            } else {
                2
            }
        } else if dy.abs() > f32::EPSILON {
            if dy > 0.0 {
                1
            } else {
                3
            }
        } else {
            0
        }
    }

    fn assembler_module_fits(
        assembler_building: &BuildingComp,
        assembler_block: &crate::mindustry::content::blocks::UnitAssemblerBlockData,
        module_building: &BuildingComp,
    ) -> bool {
        let tile_size = TILE_SIZE as f32;
        let (adx, ady) = autotiler_direction(assembler_building.rotation);
        let spawn_x = assembler_building.x
            + adx as f32
                * tile_size
                * (assembler_block.area_size + assembler_block.base.size) as f32
                / 2.0;
        let spawn_y = assembler_building.y
            + ady as f32
                * tile_size
                * (assembler_block.area_size + assembler_block.base.size) as f32
                / 2.0;

        if Self::relative_direction(module_building.x, module_building.y, spawn_x, spawn_y)
            != module_building.rotation.rem_euclid(4)
        {
            return false;
        }

        let (mdx, mdy) = autotiler_direction(module_building.rotation);
        let module_probe_x = module_building.x
            + mdx as f32 * (module_building.block.size as f32 / 2.0 + 0.5) * tile_size;
        let module_probe_y = module_building.y
            + mdy as f32 * (module_building.block.size as f32 / 2.0 + 0.5) * tile_size;
        let dst = (module_probe_x - spawn_x)
            .abs()
            .max((module_probe_y - spawn_y).abs());
        let expected = tile_size * assembler_block.area_size as f32 / 2.0 - tile_size / 2.0;
        (dst - expected).abs() <= tile_size / 2.0
    }

    fn find_owned_unit_assembler_link_for_module(
        &self,
        content: &ContentLoader,
        module_index: usize,
    ) -> Option<usize> {
        let module = &self.buildings[module_index];
        self.buildings
            .iter()
            .enumerate()
            .find_map(|(index, building)| {
                if index == module_index || building.team != module.team {
                    return None;
                }
                let Some(BlockDef::UnitAssembler(assembler_block)) =
                    content.block(building.block.id)
                else {
                    return None;
                };
                Self::assembler_module_fits(building, assembler_block, module).then_some(index)
            })
    }

    fn linked_module_tiers_for_assembler(
        &self,
        content: &ContentLoader,
        assembler_index: usize,
        assembler_block: &crate::mindustry::content::blocks::UnitAssemblerBlockData,
    ) -> Vec<i32> {
        let assembler = &self.buildings[assembler_index];
        self.buildings
            .iter()
            .enumerate()
            .filter_map(|(index, building)| {
                if index == assembler_index || building.team != assembler.team {
                    return None;
                }
                let Some(BlockDef::UnitAssemblerModule(module_block)) =
                    content.block(building.block.id)
                else {
                    return None;
                };
                Self::assembler_module_fits(assembler, assembler_block, building)
                    .then_some(module_block.tier)
            })
            .collect()
    }

    fn advance_owned_unit_assembler_modules_ticks(
        &mut self,
        content: &ContentLoader,
        frame_delta: f32,
    ) -> GameRuntimeUnitAssemblerModuleFrameReport {
        let mut report = GameRuntimeUnitAssemblerModuleFrameReport::default();
        let mut pending_transfers = Vec::new();

        for index in 0..self.buildings.len() {
            let (tile_pos, block_id, enabled, efficiency, time_scale, rotdeg) = {
                let building = &self.buildings[index];
                report.visited_buildings += 1;
                (
                    building.tile_pos,
                    building.block.id,
                    building.enabled,
                    building.efficiency,
                    building.time_scale,
                    building.rotdeg(),
                )
            };

            let Some(BlockDef::UnitAssemblerModule(module_block)) = content.block(block_id) else {
                continue;
            };
            report.module_candidates += 1;

            if !self.unit_runtime_states.contains_key(&tile_pos) {
                let building = self.buildings[index].clone();
                if !self.ensure_unit_state_for_building(content, &building) {
                    report.missing_runtime_states += 1;
                    continue;
                }
            }

            let Some(link_index) = self.find_owned_unit_assembler_link_for_module(content, index)
            else {
                report.missing_links += 1;
                continue;
            };
            report.linked_modules += 1;
            let link_tile_pos = self.buildings[link_index].tile_pos;
            let link_was_occupied = self
                .unit_runtime_states
                .get(&link_tile_pos)
                .and_then(|state| match state {
                    GameRuntimeUnitBlockState::Assembler { assembler, .. } => {
                        Some(assembler.was_occupied)
                    }
                    _ => None,
                })
                .unwrap_or(false);

            let moved_in = {
                let Some(GameRuntimeUnitBlockState::AssemblerModule(common)) =
                    self.unit_runtime_states.get_mut(&tile_pos)
                else {
                    report.missing_runtime_states += 1;
                    continue;
                };
                payload_block_move_in(
                    common,
                    true,
                    module_block.rotate,
                    rotdeg,
                    module_block.payload_speed,
                    module_block.payload_rotate_speed,
                    frame_delta * time_scale,
                )
            };
            if moved_in {
                report.moved_in_payloads += 1;
            }
            if assembler_module_transfer_payload(
                moved_in,
                true,
                true,
                link_was_occupied,
                true,
                if enabled { efficiency } else { 0.0 },
            ) {
                pending_transfers.push((tile_pos, link_tile_pos));
            }
        }

        for (source_tile_pos, target_tile_pos) in pending_transfers {
            if self.transfer_payload_output_to_front(content, source_tile_pos, target_tile_pos) {
                report.transferred_payloads += 1;
            }
        }

        report
    }

    fn advance_owned_unit_assemblers_ticks(
        &mut self,
        content: &ContentLoader,
        frame_delta: f32,
    ) -> GameRuntimeUnitAssemblerFrameReport {
        let mut report = GameRuntimeUnitAssemblerFrameReport::default();

        for index in 0..self.buildings.len() {
            let (
                tile_pos,
                block_id,
                enabled,
                efficiency,
                time_scale,
                rotdeg,
                rotation,
                building_x,
                building_y,
                team,
                power_status,
            ) = {
                let building = &self.buildings[index];
                report.visited_buildings += 1;
                (
                    building.tile_pos,
                    building.block.id,
                    building.enabled,
                    building.efficiency,
                    building.time_scale,
                    building.rotdeg(),
                    building.rotation,
                    building.x,
                    building.y,
                    building.team,
                    building
                        .power
                        .as_ref()
                        .map(|power| power.status)
                        .unwrap_or(1.0),
                )
            };

            let Some(BlockDef::UnitAssembler(assembler_block)) = content.block(block_id) else {
                continue;
            };
            report.assembler_candidates += 1;

            if !self.unit_runtime_states.contains_key(&tile_pos) {
                let building = self.buildings[index].clone();
                if !self.ensure_unit_state_for_building(content, &building) {
                    report.missing_runtime_states += 1;
                    continue;
                }
            }

            let linked_tier = unit_assembler_current_tier(self.linked_module_tiers_for_assembler(
                content,
                index,
                assembler_block,
            ));
            if let Some(GameRuntimeUnitBlockState::Assembler { assembler, .. }) =
                self.unit_runtime_states.get_mut(&tile_pos)
            {
                if assembler.current_tier != linked_tier {
                    assembler.current_tier = linked_tier;
                    report.tier_updates += 1;
                }
            }

            let current_tier = self
                .unit_runtime_states
                .get(&tile_pos)
                .and_then(|state| match state {
                    GameRuntimeUnitBlockState::Assembler { assembler, .. } => {
                        Some(assembler.current_tier)
                    }
                    _ => None,
                })
                .unwrap_or(0)
                .max(0) as usize;
            let Some(plan) = assembler_block
                .plans
                .get(current_tier.min(assembler_block.plans.len().saturating_sub(1)))
            else {
                report.invalid_plans += 1;
                continue;
            };
            let created_unit_name = plan.unit.clone();

            let plan_unit = content.unit_by_name(&plan.unit);
            let can_create = plan_unit
                .map(|unit| !self.state.rules.is_unit_banned(unit.name()))
                .unwrap_or(false);
            let unit_cost = self.state.rules.unit_cost(team.0 as usize);
            let unit_build_speed = self.state.rules.unit_build_speed(team.0 as usize);
            let team_activates_factories = self
                .state
                .rules
                .unit_factory_active(team.0 as usize, self.state.tick);
            let Some(payload_requirements) =
                Self::assembler_payload_requirements(content, plan, unit_cost)
            else {
                report.invalid_plans += 1;
                continue;
            };
            let item_requirements = scaled_item_requirements(&plan.item_requirements, unit_cost);
            let liquid_requirements =
                scaled_liquid_requirements(&plan.liquid_requirements, unit_cost);
            let has_required_items = building_has_items(&self.buildings[index], &item_requirements);
            let has_required_liquids =
                building_has_liquids(&self.buildings[index], &liquid_requirements);
            if !can_create {
                report.invalid_plans += 1;
            }
            let drones_created = assembler_block.drones_created.max(0) as usize;
            let drone_ids = self
                .unit_runtime_states
                .get(&tile_pos)
                .and_then(|state| match state {
                    GameRuntimeUnitBlockState::Assembler { assembler, .. } => {
                        Some(assembler.read_unit_ids.clone())
                    }
                    _ => None,
                })
                .unwrap_or_default();
            let mut seen_drone_ids = BTreeSet::new();
            let unique_drone_ids: Vec<i32> = drone_ids
                .iter()
                .copied()
                .filter(|id| *id >= 0 && seen_drone_ids.insert(*id))
                .take(drones_created)
                .collect();
            let tracked_drones = unique_drone_ids
                .iter()
                .filter(|id| {
                    self.client_unit_snapshot_entities
                        .get(id)
                        .is_some_and(|unit| {
                            matches!(unit.controller, UnitControllerState::Assembler)
                                && unit.team_id() == team
                        })
                })
                .count();
            let (dir_x, dir_y) = autotiler_direction(rotation);
            let spawn_len = TILE_SIZE as f32
                * (assembler_block.area_size + assembler_block.base.size) as f32
                / 2.0;
            let spawn_x = building_x + dir_x as f32 * spawn_len;
            let spawn_y = building_y + dir_y as f32 * spawn_len;
            let drones_in_position = unique_drone_ids
                .iter()
                .enumerate()
                .filter(|(slot_index, id)| {
                    let target = unit_assembler_drone_target(
                        spawn_x,
                        spawn_y,
                        assembler_block.area_size,
                        TILE_SIZE as f32,
                        *slot_index,
                    );
                    self.client_unit_snapshot_entities
                        .get(id)
                        .is_some_and(|unit| {
                            matches!(unit.controller, UnitControllerState::Assembler)
                                && unit.team_id() == team
                                && unit_assembler_drone_in_position(
                                    unit.x(),
                                    unit.y(),
                                    unit.rotation(),
                                    target,
                                )
                        })
                })
                .count();

            let mut completed_unit = false;
            let mut consumed_payloads = false;
            {
                let Some(GameRuntimeUnitBlockState::Assembler { common, assembler }) =
                    self.unit_runtime_states.get_mut(&tile_pos)
                else {
                    report.missing_runtime_states += 1;
                    continue;
                };

                common.pay_rotation = rotdeg;
                if common.payload.is_some() {
                    let moved_in = payload_block_move_in(
                        common,
                        true,
                        assembler_block.rotate,
                        rotdeg,
                        assembler_block.payload_speed,
                        assembler_block.payload_rotate_speed,
                        frame_delta * time_scale,
                    );
                    if moved_in && !assembler.was_occupied {
                        if let Some(payload) = common.payload.take() {
                            if let Some(key) = payload_ref_sort_key(&payload)
                                .and_then(Self::payload_key_from_sort_key)
                            {
                                assembler.blocks.add_one(key);
                                report.moved_in_payloads += 1;
                            } else {
                                common.payload = Some(payload);
                            }
                        }
                    }
                }

                let has_required_payloads = Self::payload_seq_contains_requirements(
                    &assembler.blocks,
                    &payload_requirements,
                );
                let requirements_met =
                    has_required_payloads && has_required_items && has_required_liquids;
                if !requirements_met {
                    report.missing_requirements += 1;
                }
                if !team_activates_factories {
                    report.inactive_assemblers += 1;
                }
                let effective_efficiency = if team_activates_factories {
                    efficiency
                } else {
                    0.0
                };

                let drone_spawned = unit_assembler_update_progress(
                    assembler,
                    enabled,
                    power_status,
                    tracked_drones,
                    drones_created,
                    effective_efficiency,
                    can_create,
                    requirements_met,
                    drones_in_position,
                    frame_delta * time_scale,
                    frame_delta * time_scale * effective_efficiency,
                    unit_build_speed,
                    assembler_block.drone_construct_time,
                    plan.time,
                );
                if drone_spawned {
                    report.spawned_drone_tiles.push(tile_pos);
                }
                report.drones_in_position += drones_in_position;
                report.updated_assemblers += 1;

                if assembler.progress >= 1.0 && requirements_met && can_create {
                    consumed_payloads = !payload_requirements.is_empty();
                    unit_assembler_spawned(assembler);
                    completed_unit = true;
                }
            }

            if completed_unit {
                self.note_unit_create_event(None, created_unit_name, team, Some(tile_pos), None);
                report.completed_units += 1;
                report.spawned_tiles.push(tile_pos);
                if consumed_payloads {
                    report.consumed_payload_batches += 1;
                }
                if !item_requirements.is_empty() {
                    consume_building_items(&mut self.buildings[index], &item_requirements);
                    report.consumed_item_batches += 1;
                }
                if !liquid_requirements.is_empty() {
                    consume_building_liquids(&mut self.buildings[index], &liquid_requirements);
                    report.consumed_liquid_batches += 1;
                }
            }
        }

        report
    }

    pub fn advance_owned_unit_reconstructors(
        &mut self,
        content: &ContentLoader,
        delta_seconds: f32,
    ) -> Option<GameRuntimeUnitReconstructorFrameReport> {
        self.consume_world_load_events_and_reset_sidecars();

        let advanced = self.state.advance_game_update_frame(delta_seconds);
        if !advanced.advanced {
            return None;
        }

        self.refresh_owned_building_update_permissions(content);

        let frame_delta = advanced.delta_ticks as f32;
        for building in self.buildings.iter_mut() {
            let can_overdrive = content
                .block(building.block.id)
                .map(BlockDef::can_overdrive)
                .unwrap_or(false);
            building.advance_update_timing(frame_delta, can_overdrive);
        }

        Some(self.advance_owned_unit_reconstructors_ticks(content, frame_delta))
    }

    fn advance_owned_unit_reconstructors_ticks(
        &mut self,
        content: &ContentLoader,
        frame_delta: f32,
    ) -> GameRuntimeUnitReconstructorFrameReport {
        let mut report = GameRuntimeUnitReconstructorFrameReport::default();
        let mut pending_payload_moves = Vec::new();

        for index in 0..self.buildings.len() {
            let (tile_pos, block_id, enabled, efficiency, time_scale, rotation, rotdeg, team) = {
                let building = &self.buildings[index];
                report.visited_buildings += 1;
                (
                    building.tile_pos,
                    building.block.id,
                    building.enabled,
                    building.efficiency,
                    building.time_scale,
                    building.rotation,
                    building.rotdeg(),
                    building.team,
                )
            };

            let Some(BlockDef::UnitReconstructor(reconstructor_block)) = content.block(block_id)
            else {
                continue;
            };
            report.reconstructor_candidates += 1;

            if !enabled {
                continue;
            }

            if !self.unit_runtime_states.contains_key(&tile_pos) {
                let building = self.buildings[index].clone();
                if !self.ensure_unit_state_for_building(content, &building) {
                    report.missing_runtime_states += 1;
                    continue;
                }
            }

            let trns = reconstructor_block.base.size / 2 + 1;
            let (dx, dy) = autotiler_direction(rotation);
            let target_tile_pos = self
                .state
                .world
                .build(
                    point2_x(tile_pos) as i32 + dx * trns,
                    point2_y(tile_pos) as i32 + dy * trns,
                )
                .map(|target| target.tile_pos);

            let unit_cost = self.state.rules.unit_cost(team.0 as usize);
            let item_requirements =
                scaled_item_requirements(&reconstructor_block.consume_items, unit_cost);
            let has_required_items = building_has_items(&self.buildings[index], &item_requirements);
            let unit_build_speed = self.state.rules.unit_build_speed(team.0 as usize);
            let team_activates_factories = self
                .state
                .rules
                .unit_factory_active(team.0 as usize, self.state.tick);

            let target_upgrade = self
                .unit_runtime_states
                .get(&tile_pos)
                .and_then(|state| match state {
                    GameRuntimeUnitBlockState::Reconstructor {
                        common,
                        reconstructor,
                    } => common
                        .payload
                        .as_ref()
                        .map(|payload| (payload, reconstructor)),
                    _ => None,
                })
                .and_then(|(payload, reconstructor)| {
                    Self::reconstructor_upgrade_for_payload(content, reconstructor_block, payload)
                        .and_then(|(_from, to)| {
                            if Self::reconstructor_upgrade_unlocked_now(&self.state.rules, to)
                                && !self.state.rules.is_unit_banned(to.name())
                            {
                                Some((
                                    to.base.mappable.base.id,
                                    to.name().to_string(),
                                    reconstructor
                                        .command_id
                                        .map(|id| id as ContentId)
                                        .or_else(|| Self::unit_default_command_id(content, to)),
                                    reconstructor.command_pos,
                                ))
                            } else {
                                None
                            }
                        })
                });

            let mut consume_items = false;
            let mut upgraded_unit_name = None;
            {
                let Some(GameRuntimeUnitBlockState::Reconstructor {
                    common,
                    reconstructor,
                }) = self.unit_runtime_states.get_mut(&tile_pos)
                else {
                    report.missing_runtime_states += 1;
                    continue;
                };

                let has_payload = common.payload.is_some();
                reconstructor.base.has_payload = has_payload;

                if !has_payload {
                    reconstructor.constructing = false;
                    report.updated_reconstructors += 1;
                    continue;
                }

                if target_upgrade.is_none() {
                    reconstructor.constructing = false;
                    report.moved_out_payloads += 1;
                    let arrived = payload_block_move_out_step(
                        common,
                        rotdeg,
                        reconstructor_block.base.size,
                        TILE_SIZE as f32,
                        DEFAULT_PAYLOAD_SPEED,
                        DEFAULT_PAYLOAD_ROTATE_SPEED,
                        frame_delta * time_scale,
                    );
                    if arrived {
                        report.arrived_output_payloads += 1;
                        if let Some(target_tile_pos) = target_tile_pos {
                            pending_payload_moves.push((tile_pos, target_tile_pos));
                        }
                    }
                    report.updated_reconstructors += 1;
                    continue;
                }

                let moved_in = payload_block_move_in(
                    common,
                    true,
                    reconstructor_block.rotate,
                    rotdeg,
                    DEFAULT_PAYLOAD_SPEED,
                    DEFAULT_PAYLOAD_ROTATE_SPEED,
                    frame_delta * time_scale,
                );
                if moved_in {
                    report.moved_in_payloads += 1;
                }

                if !team_activates_factories {
                    report.inactive_reconstructors += 1;
                }
                let effective_efficiency = if has_required_items && team_activates_factories {
                    efficiency
                } else {
                    0.0
                };
                let upgraded = reconstructor_update(
                    reconstructor,
                    true,
                    true,
                    moved_in,
                    effective_efficiency,
                    frame_delta * time_scale * effective_efficiency,
                    unit_build_speed,
                    reconstructor_block.construct_time,
                );
                report.updated_reconstructors += 1;

                if upgraded {
                    let patched = common
                        .payload
                        .as_mut()
                        .zip(target_upgrade.as_ref())
                        .map(|(payload, (unit_id, unit_name, command_id, command_pos))| {
                            let type_patched = payload_ref_patch_unit_type(payload, *unit_id);
                            let controller_patched =
                                if command_id.is_some() || command_pos.is_some() {
                                    Self::payload_ref_patch_unit_controller(
                                        payload,
                                        &type_io::ControllerWire::Command(type_io::CommandWire {
                                            target_pos: *command_pos,
                                            command_id: *command_id,
                                            ..type_io::CommandWire::new()
                                        }),
                                    )
                                } else {
                                    true
                                };
                            (type_patched && controller_patched, unit_name.clone())
                        })
                        .unwrap_or((false, String::new()));
                    let (patched, unit_name) = patched;
                    if patched {
                        upgraded_unit_name = Some(unit_name);
                        report.upgraded_payloads += 1;
                        consume_items = !item_requirements.is_empty();
                    } else {
                        report.invalid_payloads += 1;
                    }
                }

                reconstructor.base.has_payload = common.payload.is_some();
            }

            if consume_items {
                consume_building_items(&mut self.buildings[index], &item_requirements);
                report.consumed_item_batches += 1;
            }
            if let Some(unit_name) = upgraded_unit_name {
                self.note_unit_create_event(None, unit_name, team, Some(tile_pos), None);
            }
        }

        for (source_tile_pos, target_tile_pos) in pending_payload_moves {
            if self.transfer_payload_output_to_front(content, source_tile_pos, target_tile_pos) {
                report.transferred_payloads += 1;
                report.spawned_tiles.push(source_tile_pos);
            }
        }

        report
    }

    pub fn advance_owned_payload_voids(
        &mut self,
        content: &ContentLoader,
        delta_seconds: f32,
    ) -> Option<GameRuntimePayloadVoidFrameReport> {
        self.consume_world_load_events_and_reset_sidecars();

        let advanced = self.state.advance_game_update_frame(delta_seconds);
        if !advanced.advanced {
            return None;
        }

        self.refresh_owned_building_update_permissions(content);

        let frame_delta = advanced.delta_ticks as f32;
        for building in self.buildings.iter_mut() {
            let can_overdrive = content
                .block(building.block.id)
                .map(BlockDef::can_overdrive)
                .unwrap_or(false);
            building.advance_update_timing(frame_delta, can_overdrive);
        }

        Some(self.advance_owned_payload_voids_ticks(content, frame_delta))
    }

    fn advance_owned_payload_voids_ticks(
        &mut self,
        content: &ContentLoader,
        frame_delta: f32,
    ) -> GameRuntimePayloadVoidFrameReport {
        let mut report = GameRuntimePayloadVoidFrameReport::default();

        for index in 0..self.buildings.len() {
            let (tile_pos, block_id, enabled, efficiency, time_scale, rotdeg) = {
                let building = &self.buildings[index];
                report.visited_buildings += 1;
                (
                    building.tile_pos,
                    building.block.id,
                    building.enabled,
                    building.efficiency,
                    building.time_scale,
                    building.rotdeg(),
                )
            };

            if !enabled {
                continue;
            }

            let Some(BlockDef::Sandbox(sandbox)) = content.block(block_id) else {
                continue;
            };
            if sandbox.kind != SandboxBlockKind::PayloadVoid {
                continue;
            }
            report.void_candidates += 1;

            let Some(GameRuntimePayloadBlockState::Void(common)) =
                self.payload_runtime_states.get_mut(&tile_pos)
            else {
                report.missing_runtime_states += 1;
                continue;
            };

            let arrived = payload_block_move_in(
                common,
                false,
                sandbox.rotate,
                rotdeg,
                sandbox.payload_speed,
                sandbox.payload_rotate_speed,
                frame_delta * time_scale,
            );
            report.updated_voids += 1;

            if payload_void_update(arrived, efficiency, common.payload.is_some()) {
                common.payload = None;
                common.pay_vector = PayloadVec2::ZERO;
                report.incinerated_payloads += 1;
            }
        }

        report
    }

    pub fn advance_and_dispatch_effect_blocks<'a, 'b>(
        &'a mut self,
        content: &ContentLoader,
        delta_seconds: f32,
        resources: GameRuntimeEffectResources<'a, 'b>,
    ) -> Option<EffectBlockFrameBatchReport> {
        self.consume_world_load_events_and_reset_sidecars();

        let advanced = self.state.advance_game_update_frame(delta_seconds);
        let frame = effect_block_frame_input_from_game_update(
            advanced,
            TILE_SIZE as f32,
            self.state.rules.fog,
            self.state.rules.static_fog,
        )?;

        for building in resources.buildings.iter_mut() {
            let can_overdrive = content
                .block(building.block.id)
                .map(BlockDef::can_overdrive)
                .unwrap_or(false);
            building.advance_update_timing(frame.delta, can_overdrive);
        }

        let mut batch_resources = EffectBlockFrameBatchResources {
            fog_control: Some(&mut self.state.fog_control),
            bullets: resources.bullets,
            bullet_type: resources.bullet_type,
            units: resources.units,
            suppressed: resources.suppressed,
            force_coolant: resources.force_coolant,
            spark_random: resources.spark_random,
        };

        Some(effect_block_update_building_slice_with_stores(
            &mut self.effect_runtime_store,
            &mut self.effect_timer_store,
            content,
            resources.buildings,
            frame,
            &mut batch_resources,
        ))
    }

