    #[test]
    fn game_runtime_applies_client_liquid_and_laser_turret_snapshots_preserving_rotation_reload_with_content(
    ) {
        fn assert_generic_turret_snapshot_preserves(
            content: &ContentLoader,
            block_name: &str,
            tile_pos: i32,
            health: f32,
            building_rotation: i32,
            existing_turret: TurretState,
            incoming_turret: TurretState,
        ) {
            let turret = content
                .block_by_name(block_name)
                .unwrap_or_else(|| panic!("base content should include {block_name}"))
                .base()
                .clone();
            let mut runtime = GameRuntime::default();
            runtime.state.world.resize(8, 8);
            runtime.add_building(BuildingComp::new(tile_pos, turret.clone(), TeamId(6)));
            runtime.turret_runtime_states.insert(
                tile_pos,
                GameRuntimeTurretBlockState::Generic(existing_turret.clone()),
            );

            let mut synced_building = BuildingComp::new(tile_pos, turret.clone(), TeamId(6));
            synced_building.health = health;
            synced_building.set_rotation(building_rotation);
            let mut sync_bytes = Vec::new();
            synced_building.write_base(&mut sync_bytes, false).unwrap();
            turret_write_child(&mut sync_bytes, &incoming_turret).unwrap();

            let report = runtime.apply_client_block_snapshot_record_with_content(
                content, tile_pos, turret.id, sync_bytes,
            );
            assert_eq!(report.block_records_applied, 1);
            assert_eq!(report.block_base_records_applied, 1);
            assert_eq!(report.block_child_records_applied, 1);
            assert_eq!(report.block_remaining_sync_bytes, 0);
            let building = runtime
                .buildings()
                .iter()
                .find(|building| building.tile_pos == tile_pos)
                .unwrap();
            assert_eq!(building.health, health);
            assert_eq!(building.rotation, building_rotation);

            let mut expected_turret = incoming_turret;
            expected_turret.rotation = existing_turret.rotation;
            expected_turret.reload_counter = existing_turret.reload_counter;
            assert_eq!(
                runtime.turret_runtime_states.get(&tile_pos),
                Some(&GameRuntimeTurretBlockState::Generic(expected_turret))
            );
        }

        let content = ContentLoader::create_base_content().unwrap();
        assert_generic_turret_snapshot_preserves(
            &content,
            "wave",
            point2_pack(6, 2),
            33.0,
            2,
            TurretState {
                reload_counter: 6.0,
                rotation: 115.0,
                ..TurretState::default()
            },
            TurretState {
                reload_counter: 14.0,
                rotation: 240.0,
                ..TurretState::default()
            },
        );
        assert_generic_turret_snapshot_preserves(
            &content,
            "meltdown",
            point2_pack(7, 2),
            35.0,
            3,
            TurretState {
                reload_counter: 7.0,
                rotation: 135.0,
                ..TurretState::default()
            },
            TurretState {
                reload_counter: 15.0,
                rotation: 270.0,
                ..TurretState::default()
            },
        );
    }

    #[test]
    fn game_runtime_preserves_payload_ammo_turret_snapshot_rotation_reload_after_reading_payloads()
    {
        let content = ContentLoader::create_base_content().unwrap();
        let router = content.block_by_name("router").unwrap();
        let valid_key = PayloadKey::new(ContentType::Block, router.base().id);
        let mut turret_block = TurretBlockData::new(
            902,
            "payload-ammo-client-test",
            TurretBlockKind::PayloadAmmoTurret,
        );
        turret_block.payload_ammo.push(PayloadTurretAmmo {
            content: valid_key,
            bullet: BulletSpec::new(BulletKind::Basic, 1.0, 1.0),
        });
        let block = BlockDef::Turret(turret_block);
        let tile_pos = point2_pack(5, 2);
        let mut runtime = GameRuntime::default();
        let existing_turret = TurretState {
            reload_counter: 5.0,
            rotation: 105.0,
            ..TurretState::default()
        };
        runtime.turret_runtime_states.insert(
            tile_pos,
            GameRuntimeTurretBlockState::PayloadAmmo {
                turret: existing_turret.clone(),
                payloads: PayloadSeq::new(),
            },
        );

        let incoming_turret = TurretState {
            reload_counter: 12.0,
            rotation: 180.0,
            ..TurretState::default()
        };
        let mut incoming_payloads = PayloadSeq::new();
        incoming_payloads.add(valid_key, 3);
        let mut building_payload = Vec::new();
        turret_write_child(&mut building_payload, &incoming_turret).unwrap();
        payload_ammo_turret_write_payloads(&mut building_payload, &incoming_payloads).unwrap();

        let mut payload_slice = building_payload.as_slice();
        let mut state = runtime
            .read_turret_runtime_state_from_building_payload(&block, 1, &mut payload_slice)
            .unwrap()
            .expect("payload ammo turret child tail should be readable");
        assert!(payload_slice.is_empty());
        runtime.preserve_client_turret_sync_fields(tile_pos, &mut state);

        let mut expected_turret = incoming_turret;
        expected_turret.rotation = existing_turret.rotation;
        expected_turret.reload_counter = existing_turret.reload_counter;
        expected_turret.total_ammo = 3;
        assert_eq!(
            state,
            GameRuntimeTurretBlockState::PayloadAmmo {
                turret: expected_turret,
                payloads: incoming_payloads,
            }
        );
    }

    #[test]
    fn game_runtime_applies_client_entity_and_hidden_snapshot_sidecars() {
        let mut runtime = GameRuntime::default();

        let report = runtime.apply_client_entity_snapshot_record(1001, 2, vec![4, 5, 6]);
        assert_eq!(report.entity_records_seen, 1);
        assert_eq!(report.entity_records_applied, 1);
        assert_eq!(report.entity_opaque_bytes, 3);
        let entity = runtime
            .client_entity_snapshot_records
            .get(&1001)
            .expect("entity snapshot should create a runtime mirror record");
        assert_eq!(entity.entity_id, 1001);
        assert_eq!(entity.type_id, 2);
        assert_eq!(entity.sync_bytes, vec![4, 5, 6]);
        assert!(!entity.hidden);

        let hidden = runtime.apply_client_hidden_snapshot_ids(&[1001, 2002]);
        assert_eq!(hidden.hidden_ids_seen, 2);
        assert_eq!(hidden.hidden_existing_entities, 1);
        assert_eq!(hidden.hidden_missing_entities, 1);
        assert!(
            runtime
                .client_entity_snapshot_records
                .get(&1001)
                .unwrap()
                .hidden
        );
        assert!(runtime.client_hidden_entity_ids.contains(&1001));
        assert!(runtime.client_hidden_entity_ids.contains(&2002));
    }

    #[test]
    fn game_runtime_applies_client_fire_entity_snapshot_to_typed_runtime() {
        let sync = type_io::FireSyncWire {
            lifetime: 120.0,
            tile_pos: Some(point2_pack(4, 5)),
            time: 33.0,
            x: 32.0,
            y: 40.0,
        };
        let mut sync_bytes = Vec::new();
        type_io::write_fire_sync(&mut sync_bytes, &sync).unwrap();

        let mut runtime = GameRuntime::default();
        let report =
            runtime.apply_client_entity_snapshot_record(7001, FIRE_CLASS_ID, sync_bytes.clone());
        assert_eq!(report.entity_records_applied, 1);
        assert!(runtime.apply_client_fire_sync_wire(7001, &sync));

        let raw = runtime
            .client_entity_snapshot_records
            .get(&7001)
            .expect("fire snapshot should preserve raw sidecar");
        assert_eq!(raw.type_id, FIRE_CLASS_ID);
        assert_eq!(raw.sync_bytes, sync_bytes);

        let fire = runtime
            .client_fire_snapshot_entities
            .get(&7001)
            .expect("fire sync should materialize typed runtime fire");
        assert_eq!(fire.lifetime, 120.0);
        assert_eq!(fire.time, 33.0);
        assert_eq!(fire.x, 32.0);
        assert_eq!(fire.y, 40.0);
        assert_eq!(fire.tile.unwrap().x, 4);
        assert_eq!(fire.tile.unwrap().y, 5);
        assert!(fire.registered);

        let hidden = runtime.apply_client_hidden_snapshot_ids(&[7001]);
        assert_eq!(hidden.hidden_existing_entities, 1);
    }

    #[test]
