    #[test]
    fn game_runtime_unit_factory_produces_configured_unit_payload() {
        let content = ContentLoader::create_base_content().unwrap();
        let factory_def = content.block_by_name("air-factory").unwrap();
        let flare = content.unit_by_name("flare").unwrap();
        let BlockDef::UnitFactory(factory_block) = factory_def else {
            panic!("air-factory should be a unit factory");
        };
        let plan = &factory_block.plans[0];
        let tile_pos = point2_pack(6, 14);
        let mut runtime = GameRuntime::default();
        runtime.state.set(GameStateState::Playing);
        runtime.state.world.resize(24, 24);
        runtime.add_building(BuildingComp::new(
            tile_pos,
            factory_def.base().clone(),
            TeamId(2),
        ));
        if let Some(items) = runtime.buildings[0].items.as_mut() {
            for requirement in &plan.requirements {
                items.set(requirement.item, requirement.amount);
            }
        }
        runtime.unit_runtime_states.insert(
            tile_pos,
            GameRuntimeUnitBlockState::Factory {
                common: PayloadBlockBuildState::default(),
                factory: UnitFactoryState {
                    current_plan: 0,
                    base: UnitBlockState {
                        progress: plan.time - 1.0,
                        ..UnitBlockState::default()
                    },
                    ..UnitFactoryState::default()
                },
            },
        );

        let mut bullets = Vec::new();
        let mut units = Vec::new();
        let mut bullet_type = |_: ContentId| -> Option<&BulletType> { None };
        let mut suppressed = |_: &BuildingComp| false;
        let mut force_coolant = |_: &BuildingComp| (0.0, 0.0);
        let mut spark_random = |_: &UnitComp| 1.0;
        let report = runtime
            .advance_owned_runtime_blocks(
                &content,
                1.0,
                owned_noop_resources(
                    &mut bullets,
                    &mut units,
                    &mut bullet_type,
                    &mut suppressed,
                    &mut force_coolant,
                    &mut spark_random,
                ),
            )
            .unwrap()
            .unit
            .factory;

        assert_eq!(report.factory_candidates, 1);
        assert_eq!(report.produced_unit_payloads, 1);
        assert_eq!(report.consumed_item_batches, 1);
        let Some(GameRuntimeUnitBlockState::Factory { common, factory }) =
            runtime.unit_runtime_states.get(&tile_pos)
        else {
            panic!("unit factory sidecar should remain present");
        };
        assert!(factory.base.has_payload);
        assert_eq!(
            payload_ref_sort_key(common.payload.as_ref().unwrap())
                .unwrap()
                .id,
            flare.id()
        );
    }

    #[test]
    fn game_runtime_unit_factory_respects_team_activation_delay_like_java() {
        let content = ContentLoader::create_base_content().unwrap();
        let factory_def = content.block_by_name("air-factory").unwrap();
        let BlockDef::UnitFactory(factory_block) = factory_def else {
            panic!("air-factory should be a unit factory");
        };
        let plan = &factory_block.plans[0];
        let tile_pos = point2_pack(7, 14);
        let mut runtime = GameRuntime::default();
        runtime.state.set(GameStateState::Playing);
        runtime.state.world.resize(24, 24);
        runtime
            .state
            .rules
            .teams
            .get_or_insert(2)
            .unit_factory_activation_delay = 120.0;
        runtime.add_building(BuildingComp::new(
            tile_pos,
            factory_def.base().clone(),
            TeamId(2),
        ));
        if let Some(items) = runtime.buildings[0].items.as_mut() {
            for requirement in &plan.requirements {
                items.set(requirement.item, requirement.amount);
            }
        }
        runtime.unit_runtime_states.insert(
            tile_pos,
            GameRuntimeUnitBlockState::Factory {
                common: PayloadBlockBuildState::default(),
                factory: UnitFactoryState {
                    current_plan: 0,
                    ..UnitFactoryState::default()
                },
            },
        );

        let inactive_report = runtime
            .advance_owned_unit_factories(&content, 1.0)
            .expect("playing runtime should advance one factory frame");
        assert_eq!(runtime.state.tick, 60.0);
        assert_eq!(inactive_report.factory_candidates, 1);
        assert_eq!(inactive_report.updated_factories, 1);
        assert_eq!(inactive_report.inactive_factories, 1);
        assert_eq!(inactive_report.produced_unit_payloads, 0);
        let Some(GameRuntimeUnitBlockState::Factory { common, factory }) =
            runtime.unit_runtime_states.get(&tile_pos)
        else {
            panic!("unit factory sidecar should remain present while inactive");
        };
        assert!(common.payload.is_none());
        assert_eq!(factory.base.progress, 0.0);

        let active_report = runtime
            .advance_owned_unit_factories(&content, 1.0)
            .expect("playing runtime should advance second factory frame");
        assert_eq!(runtime.state.tick, 120.0);
        assert_eq!(active_report.inactive_factories, 0);
        let Some(GameRuntimeUnitBlockState::Factory { factory, .. }) =
            runtime.unit_runtime_states.get(&tile_pos)
        else {
            panic!("unit factory sidecar should remain present after activation");
        };
        assert!(factory.base.progress > 0.0);
    }

    #[test]
    fn game_runtime_unit_factory_accepts_only_current_plan_items_like_java() {
        let content = ContentLoader::create_base_content().unwrap();
        let factory_def = content.block_by_name("air-factory").unwrap();
        let source_def = content.block_by_name("router").unwrap();
        let silicon = content.item_by_name("silicon").unwrap();
        let lead = content.item_by_name("lead").unwrap();
        let silicon_id = silicon.base.mappable.base.id;
        let lead_id = lead.base.mappable.base.id;
        let BlockDef::UnitFactory(factory_block) = factory_def else {
            panic!("air-factory should be a unit factory");
        };
        let tile_pos = point2_pack(9, 14);
        let source_pos = point2_pack(8, 14);
        let mut runtime = GameRuntime::default();
        runtime.state.rules.unit_cost_multiplier = 1.5;
        runtime.add_building(BuildingComp::new(
            source_pos,
            source_def.base().clone(),
            TeamId(2),
        ));
        let mut factory_building =
            BuildingComp::new(tile_pos, factory_def.base().clone(), TeamId(2));
        factory_building.config = Some(TypeValue::Int(0));
        runtime.add_building(factory_building);

        let base_capacity = factory_block
            .capacities
            .iter()
            .find(|capacity| capacity.item == silicon_id)
            .map(|capacity| capacity.amount)
            .expect("air factory should have silicon capacity");
        let maximum_accepted = unit_factory_maximum_accepted(base_capacity, 1.5);
        let factory_items = runtime.buildings[1]
            .items
            .as_mut()
            .expect("unit factory should own item storage");
        factory_items.set(silicon_id, maximum_accepted - 1);

        assert!(runtime.dump_target_accepts_item(&content, 0, 1, silicon_id));
        assert!(!runtime.dump_target_accepts_item(&content, 0, 1, lead_id));

        runtime.buildings[1]
            .items
            .as_mut()
            .unwrap()
            .set(silicon_id, maximum_accepted);
        assert!(!runtime.dump_target_accepts_item(&content, 0, 1, silicon_id));

        runtime.unit_runtime_states.insert(
            tile_pos,
            GameRuntimeUnitBlockState::Factory {
                common: PayloadBlockBuildState::default(),
                factory: UnitFactoryState {
                    current_plan: -1,
                    ..UnitFactoryState::default()
                },
            },
        );
        runtime.buildings[1]
            .items
            .as_mut()
            .unwrap()
            .set(silicon_id, 0);
        assert!(!runtime.dump_target_accepts_item(&content, 0, 1, silicon_id));
    }

