    #[test]
    fn game_runtime_unit_factory_configuration_plan_hides_enter_payload_only_standard_commands_like_java(
    ) {
        let mut content = ContentLoader::create_base_content().unwrap();
        let factory_def = content.block_by_name("air-factory").unwrap().base().clone();
        for unit in &mut content.catalog_mut().units {
            match unit.name() {
                "flare" => {
                    unit.commands = vec!["move".into(), "enterPayload".into()];
                    unit.default_command = Some("move".into());
                    unit.allow_change_commands = true;
                }
                "mono" => {
                    unit.commands = vec!["move".into(), "enterPayload".into(), "mine".into()];
                    unit.default_command = Some("mine".into());
                    unit.allow_change_commands = false;
                }
                _ => {}
            }
        }
        let tile_pos = point2_pack(22, 15);
        let mut runtime = GameRuntime::default();
        runtime.state.rules.researched.insert("flare".into());
        runtime.add_building(BuildingComp::new(tile_pos, factory_def, TeamId(2)));
        runtime.unit_runtime_states.insert(
            tile_pos,
            GameRuntimeUnitBlockState::Factory {
                common: PayloadBlockBuildState::default(),
                factory: UnitFactoryState {
                    current_plan: 0,
                    ..UnitFactoryState::default()
                },
            },
        );

        let flare_plan = runtime
            .unit_factory_configuration_plan(&content, tile_pos)
            .expect("air factory should expose flare configuration plan");
        assert!(flare_plan.command_options.is_empty());
        assert!(!GameRuntime::unit_factory_can_set_command(
            content.unit_by_name("flare").unwrap()
        ));

        let GameRuntimeUnitBlockState::Factory { factory, .. } =
            runtime.unit_runtime_states.get_mut(&tile_pos).unwrap()
        else {
            panic!("unit factory sidecar should stay a factory");
        };
        factory.current_plan = 1;
        runtime.state.rules.researched.insert("mono".into());
        let mono_plan = runtime
            .unit_factory_configuration_plan(&content, tile_pos)
            .expect("air factory should expose mono configuration plan");
        assert!(mono_plan.command_options.is_empty());
        assert!(!GameRuntime::unit_factory_can_set_command(
            content.unit_by_name("mono").unwrap()
        ));
    }

    #[test]
    fn game_runtime_senses_unit_factory_progress_and_item_capacity_like_java() {
        let content = ContentLoader::create_base_content().unwrap();
        let factory_def = content.block_by_name("air-factory").unwrap();
        let BlockDef::UnitFactory(factory_block) = factory_def else {
            panic!("air-factory should be a unit factory");
        };
        let plan = &factory_block.plans[0];
        let tile_pos = point2_pack(20, 14);
        let mut runtime = GameRuntime::default();
        runtime.state.rules.unit_cost_multiplier = 1.5;
        runtime.add_building(BuildingComp::new(
            tile_pos,
            factory_def.base().clone(),
            TeamId(2),
        ));
        runtime.unit_runtime_states.insert(
            tile_pos,
            GameRuntimeUnitBlockState::Factory {
                common: PayloadBlockBuildState::default(),
                factory: UnitFactoryState {
                    current_plan: 0,
                    base: UnitBlockState {
                        progress: plan.time * 0.25,
                        ..UnitBlockState::default()
                    },
                    ..UnitFactoryState::default()
                },
            },
        );

        assert_eq!(
            runtime.sense_owned_building_number(&content, tile_pos, LAccess::Progress),
            Some(0.25)
        );
        assert_eq!(
            runtime.sense_owned_building_number(&content, tile_pos, LAccess::ItemCapacity),
            Some(
                (factory_block.base.item_capacity as f32 * runtime.state.rules.unit_cost(2)).round()
                    as f64
            )
        );

        {
            let Some(GameRuntimeUnitBlockState::Factory { factory, .. }) =
                runtime.unit_runtime_states.get_mut(&tile_pos)
            else {
                panic!("unit factory sidecar should stay present for sense numeric test");
            };
            factory.base.progress = plan.time * 2.0;
        }
        assert_eq!(
            runtime.sense_owned_building_number(&content, tile_pos, LAccess::Progress),
            Some(1.0)
        );
        {
            let Some(GameRuntimeUnitBlockState::Factory { factory, .. }) =
                runtime.unit_runtime_states.get_mut(&tile_pos)
            else {
                panic!("unit factory sidecar should stay present for sense numeric clear test");
            };
            factory.current_plan = -1;
        }
        assert_eq!(
            runtime.sense_owned_building_number(&content, tile_pos, LAccess::Progress),
            Some(0.0)
        );
    }

    #[test]
    fn game_runtime_commands_unit_factory_position_and_payload_controller_like_java() {
        let content = ContentLoader::create_base_content().unwrap();
        let factory_def = content.block_by_name("air-factory").unwrap();
        let router_def = content.block_by_name("router").unwrap();
        let flare = content.unit_by_name("flare").unwrap();
        let BlockDef::UnitFactory(factory_block) = factory_def else {
            panic!("air-factory should be a unit factory");
        };
        let plan = &factory_block.plans[0];
        let factory_tile = point2_pack(21, 14);
        let enemy_factory_tile = point2_pack(25, 14);
        let router_tile = point2_pack(29, 14);
        let target = IoVec2::new(64.0, 96.0);
        let mut runtime = GameRuntime::default();
        runtime.state.set(GameStateState::Playing);
        runtime.state.world.resize(40, 24);
        runtime.add_building(BuildingComp::new(
            factory_tile,
            factory_def.base().clone(),
            TeamId(2),
        ));
        runtime.add_building(BuildingComp::new(
            enemy_factory_tile,
            factory_def.base().clone(),
            TeamId(3),
        ));
        runtime.add_building(BuildingComp::new(
            router_tile,
            router_def.base().clone(),
            TeamId(2),
        ));
        if let Some(items) = runtime.buildings[0].items.as_mut() {
            for requirement in &plan.requirements {
                items.set(requirement.item, requirement.amount);
            }
        }
        runtime.unit_runtime_states.insert(
            factory_tile,
            GameRuntimeUnitBlockState::Factory {
                common: PayloadBlockBuildState::default(),
                factory: UnitFactoryState {
                    current_plan: 0,
                    base: UnitBlockState {
                        progress: plan.time - 1.0,
                        ..UnitBlockState::default()
                    },
                    ..UnitFactoryState::default()
                },
            },
        );

        let report = runtime.command_owned_building_positions(
            &content,
            TeamId(2),
            &[
                factory_tile,
                enemy_factory_tile,
                router_tile,
                point2_pack(31, 14),
            ],
            target,
            Some("[#AABBCCDD]builder".into()),
        );

        assert_eq!(report.commanded_positions, vec![factory_tile]);
        assert_eq!(report.team_mismatches, 1);
        assert_eq!(report.uncommandable_buildings, 1);
        assert_eq!(report.missing_buildings, 1);
        assert!(report.changed());
        assert_eq!(runtime.buildings[0].last_accessed, "[#AABBCCDD]builder");
        let Some(GameRuntimeUnitBlockState::Factory { factory, .. }) =
            runtime.unit_runtime_states.get(&factory_tile)
        else {
            panic!("factory sidecar should remain present after command");
        };
        assert_eq!(factory.command_pos, Some(target));

        let report = runtime.advance_owned_unit_factories(&content, 1.0).unwrap();

        assert_eq!(report.produced_unit_payloads, 1);
        let Some(GameRuntimeUnitBlockState::Factory { common, .. }) =
            runtime.unit_runtime_states.get(&factory_tile)
        else {
            panic!("factory sidecar should remain present after production");
        };
        assert_eq!(
            payload_ref_sort_key(common.payload.as_ref().unwrap())
                .unwrap()
                .id,
            flare.id()
        );
        let Some(PayloadRef::Unit {
            class_id,
            unit_bytes,
        }) = common.payload.as_ref()
        else {
            panic!("factory output should be a unit payload");
        };
        let (start, end) =
            GameRuntime::unit_payload_controller_bounds(*class_id, unit_bytes).unwrap();
        let mut controller_bytes = &unit_bytes[start..end];
        let controller = type_io::read_controller(&mut controller_bytes).unwrap();
        assert_eq!(controller_bytes.len(), 0);
        let type_io::ControllerWire::Command(command) = controller else {
            panic!("commanded factory payload should get Command controller");
        };
        assert_eq!(command.target_pos, Some(target));
    }

    #[test]
    fn game_runtime_commands_other_commandable_building_positions_like_java() {
        let content = ContentLoader::create_base_content().unwrap();
        let reconstructor_def = content.block_by_name("additive-reconstructor").unwrap();
        let assembler_def = content.block_by_name("tank-assembler").unwrap();
        let payload_source_def = content.block_by_name("payload-source").unwrap();
        let core_def = content.block_by_name("core-shard").unwrap();
        let reconstructor_tile = point2_pack(8, 20);
        let assembler_tile = point2_pack(20, 20);
        let payload_source_tile = point2_pack(36, 20);
        let core_tile = point2_pack(52, 20);
        let target = IoVec2::new(112.0, 144.0);
        let mut runtime = GameRuntime::default();
        runtime.state.world.resize(80, 40);
        for (tile_pos, block) in [
            (reconstructor_tile, reconstructor_def.base().clone()),
            (assembler_tile, assembler_def.base().clone()),
            (payload_source_tile, payload_source_def.base().clone()),
            (core_tile, core_def.base().clone()),
        ] {
            runtime.add_building(BuildingComp::new(tile_pos, block, TeamId(2)));
        }

        let report = runtime.command_owned_building_positions(
            &content,
            TeamId(2),
            &[
                reconstructor_tile,
                assembler_tile,
                payload_source_tile,
                core_tile,
            ],
            target,
            Some("[#01020304]commander".into()),
        );

        assert_eq!(
            report.commanded_positions,
            vec![
                reconstructor_tile,
                assembler_tile,
                payload_source_tile,
                core_tile
            ]
        );
        assert!(report.changed());
        assert!(runtime
            .buildings()
            .iter()
            .filter(|building| [
                reconstructor_tile,
                assembler_tile,
                payload_source_tile,
                core_tile
            ]
            .contains(&building.tile_pos))
            .all(|building| building.last_accessed == "[#01020304]commander"));

        let Some(GameRuntimeUnitBlockState::Reconstructor { reconstructor, .. }) =
            runtime.unit_runtime_states.get(&reconstructor_tile)
        else {
            panic!("reconstructor sidecar should be commandable");
        };
        assert_eq!(reconstructor.command_pos, Some(target));

        let Some(GameRuntimeUnitBlockState::Assembler { assembler, .. }) =
            runtime.unit_runtime_states.get(&assembler_tile)
        else {
            panic!("assembler sidecar should be commandable");
        };
        assert_eq!(assembler.command_pos, Some(target));

        let Some(GameRuntimePayloadBlockState::Source { source, .. }) =
            runtime.payload_runtime_states.get(&payload_source_tile)
        else {
            panic!("payload-source sidecar should be commandable");
        };
        assert_eq!(
            source.command_pos,
            Some(Vec2 {
                x: target.x,
                y: target.y
            })
        );

        assert_eq!(
            runtime.storage_runtime_states.get(&core_tile),
            Some(&GameRuntimeStorageBlockState::Core(CoreBuildState {
                command_pos: Some(target),
                ..CoreBuildState::default()
            }))
        );
    }

    #[test]
    fn game_runtime_clears_incompatible_unit_factory_command_when_plan_changes_like_java() {
        let mut content = ContentLoader::create_base_content().unwrap();
        let factory_block = content.block_by_name("air-factory").unwrap().base().clone();
        let move_id = content.unit_command_by_name("move").unwrap().id();
        let mine_id = content.unit_command_by_name("mine").unwrap().id();
        for unit in &mut content.catalog_mut().units {
            match unit.name() {
                "flare" => unit.commands = vec!["move".into()],
                "mono" => unit.commands = vec!["mine".into()],
                _ => {}
            }
        }
        let tile_pos = point2_pack(15, 14);
        let mut runtime = GameRuntime::default();
        let mut building = BuildingComp::new(tile_pos, factory_block, TeamId(2));
        building.config = Some(TypeValue::Int(0));
        runtime.add_building(building);
        runtime.unit_runtime_states.insert(
            tile_pos,
            GameRuntimeUnitBlockState::Factory {
                common: PayloadBlockBuildState::default(),
                factory: UnitFactoryState {
                    current_plan: 0,
                    command_id: Some(move_id as u8),
                    base: UnitBlockState {
                        progress: 7.0,
                        ..UnitBlockState::default()
                    },
                    ..UnitFactoryState::default()
                },
            },
        );

        assert_eq!(
            runtime.configure_owned_unit_factory_plan(&content, tile_pos, Some(1)),
            GameRuntimeUnitFactoryConfigureResult::Configured
        );
        let Some(GameRuntimeUnitBlockState::Factory { factory, .. }) =
            runtime.unit_runtime_states.get(&tile_pos)
        else {
            panic!("unit factory sidecar should stay present after plan config");
        };
        assert_eq!(factory.current_plan, 1);
        assert_eq!(factory.command_id, None);
        assert_eq!(factory.base.progress, 0.0);

        {
            let GameRuntimeUnitBlockState::Factory { factory, .. } =
                runtime.unit_runtime_states.get_mut(&tile_pos).unwrap()
            else {
                panic!("unit factory sidecar should stay a factory");
            };
            factory.current_plan = 0;
            factory.command_id = Some(mine_id as u8);
            factory.base.progress = 11.0;
        }
        assert_eq!(
            runtime.configure_owned_unit_factory_plan(&content, tile_pos, Some(1)),
            GameRuntimeUnitFactoryConfigureResult::Configured
        );
        let Some(GameRuntimeUnitBlockState::Factory { factory, .. }) =
            runtime.unit_runtime_states.get(&tile_pos)
        else {
            panic!("unit factory sidecar should stay present after compatible command config");
        };
        assert_eq!(factory.current_plan, 1);
        assert_eq!(factory.command_id, Some(mine_id as u8));
        assert_eq!(factory.base.progress, 0.0);

        {
            let GameRuntimeUnitBlockState::Factory { factory, .. } =
                runtime.unit_runtime_states.get_mut(&tile_pos).unwrap()
            else {
                panic!("unit factory sidecar should stay a factory");
            };
            factory.command_id = Some(mine_id as u8);
        }
        assert_eq!(
            runtime.configure_owned_unit_factory_plan(&content, tile_pos, Some(99)),
            GameRuntimeUnitFactoryConfigureResult::Cleared
        );
        let Some(GameRuntimeUnitBlockState::Factory { factory, .. }) =
            runtime.unit_runtime_states.get(&tile_pos)
        else {
            panic!("unit factory sidecar should stay present after invalid plan clear");
        };
        assert_eq!(factory.current_plan, -1);
        assert_eq!(factory.command_id, None);
    }

