    #[test]
    fn game_runtime_reconstructor_respects_team_activation_delay_like_java() {
        let content = ContentLoader::create_base_content().unwrap();
        let mono = content.unit_by_name("mono").unwrap().clone();
        let reconstructor_def = content.block_by_name("additive-reconstructor").unwrap();
        let BlockDef::UnitReconstructor(reconstructor_block) = reconstructor_def else {
            panic!("additive-reconstructor should be a unit reconstructor");
        };
        let tile_pos = point2_pack(19, 17);
        let mut runtime = GameRuntime::default();
        runtime.state.set(GameStateState::Playing);
        runtime.state.world.resize(32, 24);
        runtime
            .state
            .rules
            .teams
            .get_or_insert(2)
            .unit_factory_activation_delay = 120.0;
        runtime.add_building(BuildingComp::new(
            tile_pos,
            reconstructor_def.base().clone(),
            TeamId(2),
        ));
        if let Some(items) = runtime.buildings[0].items.as_mut() {
            for requirement in &reconstructor_block.consume_items {
                items.set(requirement.item, requirement.amount);
            }
        }
        let mut unit = UnitComp::new(8921, mono, TeamId(2));
        unit.set_pos(runtime.buildings[0].x, runtime.buildings[0].y);
        assert!(runtime.attach_unit_payload_to_building(&content, tile_pos, &unit));
        {
            let Some(GameRuntimeUnitBlockState::Reconstructor {
                common,
                reconstructor,
            }) = runtime.unit_runtime_states.get_mut(&tile_pos)
            else {
                panic!("reconstructor sidecar should exist after payload attach");
            };
            common.pay_vector = Vec2::ZERO;
            reconstructor.base.progress = 0.0;
        }

        let inactive_report = runtime
            .advance_owned_unit_reconstructors(&content, 1.0)
            .expect("playing runtime should advance one reconstructor frame");
        assert_eq!(runtime.state.tick, 60.0);
        assert_eq!(inactive_report.reconstructor_candidates, 1);
        assert_eq!(inactive_report.inactive_reconstructors, 1);
        assert_eq!(inactive_report.upgraded_payloads, 0);
        let Some(GameRuntimeUnitBlockState::Reconstructor { reconstructor, .. }) =
            runtime.unit_runtime_states.get(&tile_pos)
        else {
            panic!("reconstructor sidecar should remain present while inactive");
        };
        assert_eq!(reconstructor.base.progress, 0.0);

        let active_report = runtime
            .advance_owned_unit_reconstructors(&content, 1.0)
            .expect("playing runtime should advance second reconstructor frame");
        assert_eq!(runtime.state.tick, 120.0);
        assert_eq!(active_report.inactive_reconstructors, 0);
        let Some(GameRuntimeUnitBlockState::Reconstructor { reconstructor, .. }) =
            runtime.unit_runtime_states.get(&tile_pos)
        else {
            panic!("reconstructor sidecar should remain present after activation");
        };
        assert!(reconstructor.base.progress > 0.0);
    }

    #[test]
    fn game_runtime_unit_factory_outputs_payload_to_front_conveyor() {
        let content = ContentLoader::create_base_content().unwrap();
        let factory_def = content.block_by_name("air-factory").unwrap();
        let conveyor_def = content.block_by_name("payload-conveyor").unwrap();
        let flare = content.unit_by_name("flare").unwrap();
        let BlockDef::UnitFactory(factory_block) = factory_def else {
            panic!("air-factory should be a unit factory");
        };
        let BlockDef::Payload(conveyor_block) = conveyor_def else {
            panic!("payload-conveyor should be a payload block");
        };
        let plan = &factory_block.plans[0];
        let factory_tile = point2_pack(6, 16);
        let conveyor_tile = point2_pack(
            6 + factory_block.base.size / 2 + 1 + (conveyor_block.base.size - 1) / 2,
            16,
        );
        let mut runtime = GameRuntime::default();
        runtime.state.rules.default_team = 2;
        runtime.state.set_sector(Some(Sector::new(23)));
        runtime.state.set(GameStateState::Playing);
        runtime.state.world.resize(24, 24);
        let mut factory_building =
            BuildingComp::new(factory_tile, factory_def.base().clone(), TeamId(2));
        factory_building.set_rotation(0);
        runtime.add_building(factory_building);
        runtime.add_building(BuildingComp::new(
            conveyor_tile,
            conveyor_def.base().clone(),
            TeamId(2),
        ));
        runtime.payload_runtime_states.insert(
            conveyor_tile,
            GameRuntimePayloadBlockState::Conveyor(PayloadConveyorState::default()),
        );
        if let Some(items) = runtime.buildings[0].items.as_mut() {
            for requirement in &plan.requirements {
                items.set(requirement.item, requirement.amount);
            }
        }
        runtime.unit_runtime_states.insert(
            factory_tile,
            GameRuntimeUnitBlockState::Factory {
                common: PayloadBlockBuildState::default(),
                factory: UnitFactoryState {
                    current_plan: 0,
                    base: UnitBlockState {
                        progress: plan.time - 1.0,
                        ..UnitBlockState::default()
                    },
                    ..UnitFactoryState::default()
                },
            },
        );

        let produced = runtime.advance_owned_unit_factories(&content, 1.0).unwrap();
        assert_eq!(produced.produced_unit_payloads, 1);
        assert_eq!(runtime.unit_create_events.len(), 1);
        assert_eq!(runtime.unit_create_events[0].unit_name, flare.name());
        assert_eq!(runtime.unit_create_events[0].team, TeamId(2));
        assert_eq!(
            runtime.unit_create_events[0].spawner_tile,
            Some(factory_tile)
        );
        assert_eq!(runtime.state.stats.units_created, 1);
        assert_eq!(runtime.campaign_stats.get_unit_produced(flare.name()), 1);
        let moved = runtime.advance_owned_unit_factories(&content, 1.0).unwrap();

        assert_eq!(moved.arrived_output_payloads, 1);
        assert_eq!(moved.transferred_payloads, 1);
        assert_eq!(moved.spawned_tiles, vec![factory_tile]);
        let Some(GameRuntimeUnitBlockState::Factory { common, factory }) =
            runtime.unit_runtime_states.get(&factory_tile)
        else {
            panic!("unit factory sidecar should remain present");
        };
        assert!(common.payload.is_none());
        assert!(!factory.base.has_payload);
        let Some(GameRuntimePayloadBlockState::Conveyor(conveyor)) =
            runtime.payload_runtime_states.get(&conveyor_tile)
        else {
            panic!("front payload conveyor should keep sidecar");
        };
        assert_eq!(
            payload_ref_sort_key(conveyor.item.as_ref().unwrap())
                .unwrap()
                .id,
            flare.id()
        );
    }

