    fn game_runtime_unit_cargo_unload_point_dumps_item_to_adjacent_router() {
        let content = ContentLoader::create_base_content().unwrap();
        let unload_def = content.block_by_name("unit-cargo-unload-point").unwrap();
        let router_def = content.block_by_name("router").unwrap();
        let copper = content.item_by_name("copper").unwrap();
        let BlockDef::Distribution(unload_block) = unload_def else {
            panic!("unit-cargo-unload-point should be a distribution block");
        };
        let unload_tile = point2_pack(20, 18);
        let router_tile = point2_pack(22, 18);
        let mut runtime = GameRuntime::default();
        runtime.state.set(GameStateState::Playing);
        runtime.state.world.resize(32, 32);
        let mut unload = BuildingComp::new(unload_tile, unload_def.base().clone(), TeamId(4));
        if let Some(items) = unload.items.as_mut() {
            items.set(
                copper.base.mappable.base.id,
                unload_def.base().item_capacity,
            );
        }
        runtime.add_building(unload);
        runtime.add_building(BuildingComp::new(
            router_tile,
            router_def.base().clone(),
            TeamId(4),
        ));
        assert!(
            runtime.buildings[0]
                .proximity
                .iter()
                .any(|reference| reference.tile_pos == router_tile),
            "unit cargo unload point should see the adjacent router"
        );
        runtime.distribution_runtime_states.insert(
            unload_tile,
            GameRuntimeDistributionBlockState::UnitCargoUnload(UnitCargoUnloadPointState {
                item_id: Some(copper.base.mappable.base.id as i32),
                stale_timer: unload_block.stale_time_duration - 1.0,
                stale: false,
            }),
        );

        let mut bullets = Vec::new();
        let mut units = Vec::new();
        let mut bullet_type = |_: ContentId| -> Option<&BulletType> { None };
        let mut suppressed = |_: &BuildingComp| false;
        let mut force_coolant = |_: &BuildingComp| (0.0, 0.0);
        let mut spark_random = |_: &UnitComp| 1.0;
        let report = runtime
            .advance_owned_runtime_blocks(
                &content,
                1.0,
                owned_noop_resources(
                    &mut bullets,
                    &mut units,
                    &mut bullet_type,
                    &mut suppressed,
                    &mut force_coolant,
                    &mut spark_random,
                ),
            )
            .unwrap();

        assert_eq!(report.item_transport.unit_cargo_unload_dumped_items, 1);
        assert_eq!(report.item_transport.unit_cargo_unload_stale_points, 0);
        let unload = runtime
            .buildings()
            .iter()
            .find(|building| building.tile_pos == unload_tile)
            .unwrap();
        let router = runtime
            .buildings()
            .iter()
            .find(|building| building.tile_pos == router_tile)
            .unwrap();
        assert_eq!(
            unload
                .items
                .as_ref()
                .unwrap()
                .get(copper.base.mappable.base.id),
            unload_def.base().item_capacity - 1
        );
        assert_eq!(
            router
                .items
                .as_ref()
                .unwrap()
                .get(copper.base.mappable.base.id),
            1
        );
        let Some(GameRuntimeDistributionBlockState::UnitCargoUnload(state)) =
            runtime.distribution_runtime_states.get(&unload_tile)
        else {
            panic!("unit cargo unload state should remain present");
        };
        assert!(!state.stale);
        assert_eq!(state.stale_timer, 0.0);
    }

    #[test]
    fn game_runtime_configures_unit_cargo_unload_point_item_value() {
        let content = ContentLoader::create_base_content().unwrap();
        let unload_def = content.block_by_name("unit-cargo-unload-point").unwrap();
        let router_def = content.block_by_name("router").unwrap();
        let copper = content.item_by_name("copper").unwrap();
        let unload_tile = point2_pack(20, 18);
        let router_tile = point2_pack(22, 18);
        let mut runtime = GameRuntime::default();
        runtime.state.world.resize(32, 32);
        runtime.add_building(BuildingComp::new(
            unload_tile,
            unload_def.base().clone(),
            TeamId(4),
        ));
        runtime.add_building(BuildingComp::new(
            router_tile,
            router_def.base().clone(),
            TeamId(4),
        ));

        let item_value = TypeValue::Content(type_io::ContentRef::new(
            ContentType::Item,
            copper.base.mappable.base.id,
        ));
        assert_eq!(
            runtime.configure_owned_unit_cargo_unload_value(&content, unload_tile, &item_value),
            GameRuntimeUnitCargoUnloadConfigureResult::Configured
        );
        assert_eq!(runtime.buildings[0].config, Some(item_value.clone()));
        let Some(GameRuntimeDistributionBlockState::UnitCargoUnload(state)) =
            runtime.distribution_runtime_states.get(&unload_tile)
        else {
            panic!("unit cargo unload state should be created by config");
        };
        assert_eq!(state.item_id, Some(copper.base.mappable.base.id as i32));

        assert_eq!(
            runtime.configure_owned_unit_cargo_unload_value(
                &content,
                unload_tile,
                &TypeValue::Null
            ),
            GameRuntimeUnitCargoUnloadConfigureResult::Cleared
        );
        assert_eq!(runtime.buildings[0].config, None);
        let Some(GameRuntimeDistributionBlockState::UnitCargoUnload(state)) =
            runtime.distribution_runtime_states.get(&unload_tile)
        else {
            panic!("unit cargo unload state should remain present after clear");
        };
        assert_eq!(state.item_id, None);

        assert_eq!(
            runtime.configure_owned_unit_cargo_unload_value(&content, router_tile, &item_value),
            GameRuntimeUnitCargoUnloadConfigureResult::NotUnitCargoUnload
        );
        assert_eq!(
            runtime.configure_owned_unit_cargo_unload_value(
                &content,
                unload_tile,
                &TypeValue::Content(type_io::ContentRef::new(ContentType::Block, 0))
            ),
            GameRuntimeUnitCargoUnloadConfigureResult::UnknownItem
        );
        assert_eq!(
            runtime.configure_owned_unit_cargo_unload_value(
                &content,
                unload_tile,
                &TypeValue::Int(7)
            ),
            GameRuntimeUnitCargoUnloadConfigureResult::UnsupportedValue
        );
    }

    #[test]
    fn game_runtime_applies_client_unit_tether_block_spawned_packet_to_unit_cargo_loader() {
        let content = ContentLoader::create_base_content().unwrap();
        let loader_def = content.block_by_name("unit-cargo-loader").unwrap();
        let tile_pos = point2_pack(18, 18);
        let mut runtime = GameRuntime::default();
        runtime.state.world.resize(32, 32);
        runtime.add_building(BuildingComp::new(
            tile_pos,
            loader_def.base().clone(),
            TeamId(4),
        ));
        runtime.distribution_runtime_states.insert(
            tile_pos,
            GameRuntimeDistributionBlockState::UnitCargoLoader(UnitCargoLoaderState {
                build_progress: 0.75,
                has_unit: false,
                ..UnitCargoLoaderState::default()
            }),
        );

        assert!(runtime.apply_client_unit_tether_block_spawned_packet(
            &content,
            &UnitTetherBlockSpawnedCallPacket {
                tile: Some(tile_pos),
                id: 77,
            },
        ));

        let Some(GameRuntimeDistributionBlockState::UnitCargoLoader(state)) =
            runtime.distribution_runtime_states.get(&tile_pos)
        else {
            panic!("unit cargo loader state should remain present");
        };
        assert_eq!(state.read_unit_id, 77);
        assert_eq!(state.build_progress, 0.0);
        assert!(!state.has_unit);
        let spawned = runtime
            .client_unit_snapshot_entities
            .get(&77)
            .expect("client tether packet should materialize manifold cargo unit snapshot");
        assert_eq!(spawned.type_info.name(), "manifold");
        assert_eq!(spawned.team_id(), TeamId(4));
        assert_eq!(spawned.x(), runtime.buildings()[0].x);
        assert_eq!(spawned.y(), runtime.buildings()[0].y);
        assert!(spawned.controller.is_cargo());
        assert_eq!(
            spawned
                .cargo_ai
                .as_ref()
                .and_then(|cargo| cargo.tether_tile_pos),
            Some(tile_pos)
        );
        let tether = spawned
            .building_tether
            .as_ref()
            .expect("client materialized cargo unit should keep a formal building tether");
        assert_eq!(tether.team, TeamId(4));
        assert_eq!(
            tether.building,
            Some(BuildingTetherRef {
                tile_pos,
                team: TeamId(4),
                valid: true,
            })
        );
        assert_eq!(
            tether.update(),
            crate::mindustry::entities::comp::BuildingTetherAction::Keep
        );
        assert_eq!(runtime.client_unit_tether_block_spawned_packets_applied, 1);
    }

    #[test]
    fn game_runtime_preserves_client_cargo_tether_when_unit_snapshot_arrives() {
        let content = ContentLoader::create_base_content().unwrap();
        let loader_def = content.block_by_name("unit-cargo-loader").unwrap();
        let tile_pos = point2_pack(18, 18);
        let mut runtime = GameRuntime::default();
        runtime.state.world.resize(32, 32);
        runtime.add_building(BuildingComp::new(
            tile_pos,
            loader_def.base().clone(),
            TeamId(4),
        ));
        runtime.distribution_runtime_states.insert(
            tile_pos,
            GameRuntimeDistributionBlockState::UnitCargoLoader(UnitCargoLoaderState::default()),
        );

        assert!(runtime.apply_client_unit_tether_block_spawned_packet(
            &content,
            &UnitTetherBlockSpawnedCallPacket {
                tile: Some(tile_pos),
                id: 77,
            },
        ));
        let sync = runtime
            .client_unit_snapshot_entities
            .get(&77)
            .expect("tether packet should materialize cargo unit")
            .to_sync_wire();
        assert_eq!(
            sync.controller,
            type_io::ControllerWire::Ground,
            "CargoAI is a local runtime sidecar and currently serializes through the Java ground controller wire"
        );

        let mut sync_bytes = Vec::new();
        type_io::write_unit_sync(&mut sync_bytes, &content, &sync).unwrap();
        let mut data = Vec::new();
        data.extend_from_slice(&77i32.to_be_bytes());
        data.push(2);
        data.extend_from_slice(&sync_bytes);

        let report = runtime.apply_client_entity_snapshot_packet_with_content(&content, 1, &data);
        assert_eq!(report.entity_records_applied, 1);
        assert_eq!(report.entity_typed_records_applied, 1);
        let unit = runtime.client_unit_snapshot_entities.get(&77).unwrap();
        assert!(
            unit.controller.is_cargo(),
            "entity snapshot ground controller must not erase UnitTetherBlockSpawned cargo sidecar"
        );
        assert_eq!(
            unit.cargo_ai
                .as_ref()
                .and_then(|cargo| cargo.tether_tile_pos),
            Some(tile_pos)
        );
        assert_eq!(
            unit.building_tether
                .as_ref()
                .and_then(|tether| tether.building.as_ref().map(|building| building.tile_pos)),
            Some(tile_pos)
        );
    }

