    #[test]
    fn game_runtime_applies_client_unit_block_spawn_packet_to_unit_block_state_like_java() {
        let content = ContentLoader::create_base_content().unwrap();
        let factory_def = content.block_by_name("air-factory").unwrap();
        let reconstructor_def = content.block_by_name("additive-reconstructor").unwrap();
        let flare = content.unit_by_name("flare").unwrap().clone();
        let mono = content.unit_by_name("mono").unwrap().clone();
        let factory_tile = point2_pack(19, 18);
        let reconstructor_tile = point2_pack(24, 18);
        let mut runtime = GameRuntime::default();
        runtime.state.world.resize(32, 32);
        runtime.add_building(BuildingComp::new(
            factory_tile,
            factory_def.base().clone(),
            TeamId(4),
        ));
        runtime.add_building(BuildingComp::new(
            reconstructor_tile,
            reconstructor_def.base().clone(),
            TeamId(4),
        ));

        let factory_payload = GameRuntime::unit_payload_ref_from_unit(
            &content,
            &UnitComp::new(901, flare, TeamId(4)),
        )
        .unwrap();
        let reconstructor_payload =
            GameRuntime::unit_payload_ref_from_unit(&content, &UnitComp::new(902, mono, TeamId(4)))
                .unwrap();
        runtime.unit_runtime_states.insert(
            factory_tile,
            GameRuntimeUnitBlockState::Factory {
                common: PayloadBlockBuildState {
                    payload: Some(factory_payload),
                    ..PayloadBlockBuildState::default()
                },
                factory: UnitFactoryState {
                    base: UnitBlockState {
                        progress: 17.0,
                        has_payload: true,
                        ..UnitBlockState::default()
                    },
                    current_plan: 0,
                    command_id: Some(1),
                    ..UnitFactoryState::default()
                },
            },
        );
        runtime.unit_runtime_states.insert(
            reconstructor_tile,
            GameRuntimeUnitBlockState::Reconstructor {
                common: PayloadBlockBuildState {
                    payload: Some(reconstructor_payload),
                    ..PayloadBlockBuildState::default()
                },
                reconstructor: ReconstructorState {
                    base: UnitBlockState {
                        progress: 23.0,
                        has_payload: true,
                        ..UnitBlockState::default()
                    },
                    command_id: Some(2),
                    constructing: true,
                    ..ReconstructorState::default()
                },
            },
        );

        assert!(runtime.apply_client_unit_block_spawn_packet(
            &content,
            &UnitBlockSpawnCallPacket {
                tile: Some(factory_tile),
            },
        ));
        let Some(GameRuntimeUnitBlockState::Factory { common, factory }) =
            runtime.unit_runtime_states.get(&factory_tile)
        else {
            panic!("factory sidecar should remain present after unitBlockSpawn");
        };
        assert!(common.payload.is_none());
        assert_eq!(factory.base.progress, 0.0);
        assert!(!factory.base.has_payload);
        assert_eq!(factory.current_plan, 0);
        assert_eq!(factory.command_id, Some(1));

        assert!(runtime.apply_client_unit_block_spawn_packet(
            &content,
            &UnitBlockSpawnCallPacket {
                tile: Some(reconstructor_tile),
            },
        ));
        let Some(GameRuntimeUnitBlockState::Reconstructor {
            common,
            reconstructor,
        }) = runtime.unit_runtime_states.get(&reconstructor_tile)
        else {
            panic!("reconstructor sidecar should remain present after unitBlockSpawn");
        };
        assert!(common.payload.is_none());
        assert_eq!(reconstructor.base.progress, 0.0);
        assert!(!reconstructor.base.has_payload);
        assert_eq!(reconstructor.command_id, Some(2));
        assert!(!reconstructor.constructing);
        assert!(!runtime.apply_client_unit_block_spawn_packet(
            &content,
            &UnitBlockSpawnCallPacket { tile: None },
        ));
    }

    #[test]
    fn game_runtime_applies_client_assembler_unit_spawned_packet_like_java() {
        let content = ContentLoader::create_base_content().unwrap();
        let assembler_def = content.block_by_name("tank-assembler").unwrap();
        let BlockDef::UnitAssembler(assembler_block) = assembler_def else {
            panic!("tank-assembler should be a unit assembler");
        };
        let stell = content.unit_by_name("stell").unwrap();
        let large_wall = content.block_by_name("tungsten-wall-large").unwrap();
        let router = content.block_by_name("router").unwrap();
        let tile_pos = point2_pack(17, 18);
        let mut runtime = GameRuntime::default();
        runtime.set_network_context(GameRuntimeNetworkContext::client());
        runtime.state.rules.default_team = 4;
        runtime.state.set_sector(Some(Sector::new(5)));
        runtime.state.world.resize(32, 32);
        runtime.add_building(BuildingComp::new(
            tile_pos,
            assembler_def.base().clone(),
            TeamId(4),
        ));

        let mut blocks = PayloadSeq::new();
        blocks.add(PayloadKey::new(ContentType::Unit, stell.id()), 4);
        blocks.add(
            PayloadKey::new(ContentType::Block, large_wall.base().id),
            10,
        );
        blocks.add(PayloadKey::new(ContentType::Block, router.base().id), 2);
        runtime.unit_runtime_states.insert(
            tile_pos,
            GameRuntimeUnitBlockState::Assembler {
                common: PayloadBlockBuildState::default(),
                assembler: UnitAssemblerState {
                    progress: 1.25,
                    blocks,
                    command_pos: Some(IoVec2::new(14.0, 15.0)),
                    ..UnitAssemblerState::default()
                },
            },
        );

        assert!(runtime.apply_client_assembler_unit_spawned_packet(
            &content,
            &AssemblerUnitSpawnedCallPacket {
                tile: Some(tile_pos),
            },
        ));
        let Some(GameRuntimeUnitBlockState::Assembler { assembler, .. }) =
            runtime.unit_runtime_states.get(&tile_pos)
        else {
            panic!("assembler sidecar should remain present after assemblerUnitSpawned");
        };
        assert_eq!(runtime.unit_create_events.len(), 1);
        assert_eq!(runtime.unit_create_events[0].unit_id, None);
        assert_eq!(
            runtime.unit_create_events[0].unit_name,
            assembler_block.plans[0].unit
        );
        assert_eq!(runtime.unit_create_events[0].team, TeamId(4));
        assert_eq!(runtime.unit_create_events[0].spawner_tile, Some(tile_pos));
        assert_eq!(runtime.state.stats.units_created, 1);
        assert_eq!(
            runtime
                .campaign_stats
                .get_unit_produced(&assembler_block.plans[0].unit),
            0
        );
        assert_eq!(assembler.progress, 0.0);
        assert_eq!(assembler.blocks.total(), 0);
        assert_eq!(assembler.command_pos, Some(IoVec2::new(14.0, 15.0)));
        let expected_spawn_x = runtime.buildings()[0].x
            + TILE_SIZE as f32 * (assembler_block.area_size + assembler_block.base.size) as f32
                / 2.0;
        let expected_spawn_y = runtime.buildings()[0].y;
        assert_eq!(runtime.client_local_sound_at_events.len(), 1);
        let sound = &runtime.client_local_sound_at_events[0];
        assert_eq!(sound.sound_id, 191);
        assert_eq!(sound.x, expected_spawn_x);
        assert_eq!(sound.y, expected_spawn_y);
        assert_eq!(sound.volume, assembler_block.create_sound_volume);
        assert_eq!(sound.pitch, 1.0);
        assert_eq!(runtime.client_local_effect_events.len(), 1);
        let effect = &runtime.client_local_effect_events[0];
        assert_eq!(effect.effect.effect_id, FX_UNIT_ASSEMBLE_ID as u16);
        assert_eq!(effect.effect.x, expected_spawn_x);
        assert_eq!(effect.effect.y, expected_spawn_y);
        assert_eq!(effect.effect.rotation, -90.0);
        assert_eq!(
            effect.data,
            TypeValue::Content(type_io::ContentRef::new(
                ContentType::Unit,
                content
                    .unit_by_name(&assembler_block.plans[0].unit)
                    .unwrap()
                    .id()
            ))
        );
        assert!(!runtime.apply_client_assembler_unit_spawned_packet(
            &content,
            &AssemblerUnitSpawnedCallPacket { tile: None },
        ));
    }

