    #[test]
    fn game_runtime_applies_client_assembler_drone_spawned_packet_like_java() {
        let content = ContentLoader::create_base_content().unwrap();
        let assembler_def = content.block_by_name("tank-assembler").unwrap();
        let tile_pos = point2_pack(18, 18);
        let mut runtime = GameRuntime::default();
        runtime.state.world.resize(32, 32);
        runtime.add_building(BuildingComp::new(
            tile_pos,
            assembler_def.base().clone(),
            TeamId(4),
        ));
        runtime.unit_runtime_states.insert(
            tile_pos,
            GameRuntimeUnitBlockState::Assembler {
                common: PayloadBlockBuildState::default(),
                assembler: UnitAssemblerState {
                    drone_progress: 0.75,
                    read_unit_ids: vec![11],
                    ..UnitAssemblerState::default()
                },
            },
        );

        assert!(runtime.apply_client_assembler_drone_spawned_packet(
            &content,
            &AssemblerDroneSpawnedCallPacket {
                tile: Some(tile_pos),
                id: 77,
            },
        ));
        let Some(GameRuntimeUnitBlockState::Assembler { assembler, .. }) =
            runtime.unit_runtime_states.get(&tile_pos)
        else {
            panic!("assembler sidecar should remain present after assemblerDroneSpawned");
        };
        assert_eq!(assembler.drone_progress, 0.0);
        assert_eq!(assembler.read_unit_ids, vec![11, 77]);
        let spawned = runtime
            .client_unit_snapshot_entities
            .get(&77)
            .expect("client assembler drone packet should materialize drone snapshot");
        assert_eq!(spawned.type_info.name(), "assembly-drone");
        assert_eq!(spawned.team_id(), TeamId(4));
        assert_eq!(spawned.x(), runtime.buildings()[0].x);
        assert_eq!(spawned.y(), runtime.buildings()[0].y);
        assert_eq!(spawned.rotation(), 90.0);
        assert!(matches!(spawned.controller, UnitControllerState::Assembler));
        let tether = spawned
            .building_tether
            .as_ref()
            .expect("client materialized assembler drone should keep a tether");
        assert_eq!(
            tether.building,
            Some(BuildingTetherRef {
                tile_pos,
                team: TeamId(4),
                valid: true,
            })
        );
        assert_eq!(
            tether.update(),
            crate::mindustry::entities::comp::BuildingTetherAction::Keep
        );

        assert!(runtime.apply_client_assembler_drone_spawned_packet(
            &content,
            &AssemblerDroneSpawnedCallPacket {
                tile: Some(tile_pos),
                id: 77,
            },
        ));
        let Some(GameRuntimeUnitBlockState::Assembler { assembler, .. }) =
            runtime.unit_runtime_states.get(&tile_pos)
        else {
            panic!("assembler sidecar should remain present after duplicate drone packet");
        };
        assert_eq!(assembler.read_unit_ids, vec![11, 77]);
        assert!(!runtime.apply_client_assembler_drone_spawned_packet(
            &content,
            &AssemblerDroneSpawnedCallPacket {
                tile: Some(tile_pos),
                id: -1,
            },
        ));
    }

    #[test]
    fn game_runtime_applies_client_unit_spawn_packet_sync_container() {
        let content = ContentLoader::create_base_content().unwrap();
        let stell = content.unit_by_name("stell").unwrap().clone();
        let mut unit = UnitComp::new(5151, stell, TeamId(6));
        unit.set_pos(144.0, 96.0);
        unit.set_rotation(180.0);
        let mut sync = Vec::new();
        type_io::write_unit_sync(&mut sync, &content, &unit.to_sync_wire()).unwrap();
        let packet = UnitSpawnCallPacket {
            container: type_io::UnitSyncContainer::new(
                unit.id(),
                entity_class_id(unit.type_info.name()).unwrap(),
                sync,
            ),
        };

        let mut runtime = GameRuntime::default();
        assert!(runtime.apply_client_unit_spawn_packet(&content, &packet));
        let spawned = runtime
            .client_unit_snapshot_entities
            .get(&5151)
            .expect("unit spawn packet should materialize unit snapshot");
        assert_eq!(spawned.type_info.name(), "stell");
        assert_eq!(spawned.team_id(), TeamId(6));
        assert_eq!(spawned.x(), 144.0);
        assert_eq!(spawned.y(), 96.0);
        assert_eq!(spawned.rotation(), 180.0);

        let mut invalid = packet.clone();
        invalid.container.unit_type_id = crate::mindustry::entities::BULLET_CLASS_ID;
        assert!(!runtime.apply_client_unit_spawn_packet(&content, &invalid));
    }

