    #[test]
    fn game_runtime_reconstructor_outputs_upgraded_payload_to_front_conveyor() {
        let content = ContentLoader::create_base_content().unwrap();
        let flare = content.unit_by_name("flare").unwrap().clone();
        let horizon = content.unit_by_name("horizon").unwrap();
        let reconstructor_def = content.block_by_name("additive-reconstructor").unwrap();
        let conveyor_def = content.block_by_name("payload-conveyor").unwrap();
        let BlockDef::UnitReconstructor(reconstructor_block) = reconstructor_def else {
            panic!("additive-reconstructor should be a unit reconstructor");
        };
        let BlockDef::Payload(conveyor_block) = conveyor_def else {
            panic!("payload-conveyor should be a payload block");
        };
        let reconstructor_tile = point2_pack(8, 10);
        let conveyor_tile = point2_pack(
            8 + reconstructor_block.base.size / 2 + 1 + (conveyor_block.base.size - 1) / 2,
            10,
        );
        let mut runtime = GameRuntime::default();
        runtime.state.set(GameStateState::Playing);
        runtime.state.world.resize(32, 24);
        let mut reconstructor_building = BuildingComp::new(
            reconstructor_tile,
            reconstructor_def.base().clone(),
            TeamId(3),
        );
        reconstructor_building.set_rotation(0);
        runtime.add_building(reconstructor_building);
        runtime.add_building(BuildingComp::new(
            conveyor_tile,
            conveyor_def.base().clone(),
            TeamId(3),
        ));
        runtime.payload_runtime_states.insert(
            conveyor_tile,
            GameRuntimePayloadBlockState::Conveyor(PayloadConveyorState::default()),
        );
        if let Some(items) = runtime.buildings[0].items.as_mut() {
            for requirement in &reconstructor_block.consume_items {
                items.set(requirement.item, requirement.amount);
            }
        }
        let mut unit = UnitComp::new(5588, flare, TeamId(3));
        unit.set_pos(runtime.buildings[0].x, runtime.buildings[0].y);
        assert!(runtime.attach_unit_payload_to_building(&content, reconstructor_tile, &unit));
        {
            let Some(GameRuntimeUnitBlockState::Reconstructor {
                common,
                reconstructor,
            }) = runtime.unit_runtime_states.get_mut(&reconstructor_tile)
            else {
                panic!("reconstructor should have unit sidecar");
            };
            common.pay_vector = Vec2::ZERO;
            reconstructor.base.progress = reconstructor_block.construct_time - 1.0;
        }

        let upgraded = runtime
            .advance_owned_unit_reconstructors(&content, 1.0)
            .unwrap();
        assert_eq!(upgraded.upgraded_payloads, 1);
        let moved_out = runtime
            .advance_owned_unit_reconstructors(&content, 1.0)
            .unwrap();

        assert_eq!(moved_out.arrived_output_payloads, 1);
        assert_eq!(moved_out.transferred_payloads, 1);
        assert_eq!(moved_out.spawned_tiles, vec![reconstructor_tile]);
        let Some(GameRuntimeUnitBlockState::Reconstructor {
            common,
            reconstructor,
        }) = runtime.unit_runtime_states.get(&reconstructor_tile)
        else {
            panic!("reconstructor sidecar should remain present");
        };
        assert!(common.payload.is_none());
        assert!(!reconstructor.base.has_payload);
        let Some(GameRuntimePayloadBlockState::Conveyor(conveyor)) =
            runtime.payload_runtime_states.get(&conveyor_tile)
        else {
            panic!("front payload conveyor should keep sidecar");
        };
        assert_eq!(
            payload_ref_sort_key(conveyor.item.as_ref().unwrap())
                .unwrap()
                .id,
            horizon.id()
        );
        assert!(GameRuntime::payload_ref_fits_payload_limit(
            &content,
            conveyor.item.as_ref().unwrap(),
            conveyor_block.payload_limit
        ));
    }

    #[test]
    fn game_runtime_applies_multi_unit_entity_snapshot_packet_with_content() {
        let content = ContentLoader::create_base_content().unwrap();
        let dagger = content.unit_by_name("dagger").unwrap();
        let flare = content.unit_by_name("flare").unwrap();
        let first_sync = type_io::UnitSyncWire {
            abilities: Vec::new(),
            ammo: 3.0,
            controller: type_io::ControllerWire::Ground,
            elevation: 0.1,
            flag: 11.0,
            health: 55.0,
            is_shooting: false,
            mine_tile: None,
            mounts: Vec::new(),
            plans: None,
            rotation: 45.0,
            shield: 1.0,
            spawned_by_core: false,
            stack: ItemStack::new("", 0),
            statuses: Vec::new(),
            team: TeamId(1),
            type_id: dagger.id(),
            update_building: false,
            vel: IoVec2 { x: 0.5, y: 0.25 },
            x: 16.0,
            y: 24.0,
        };
        let second_sync = type_io::UnitSyncWire {
            abilities: Vec::new(),
            ammo: 5.0,
            controller: type_io::ControllerWire::Ground,
            elevation: 0.75,
            flag: 22.0,
            health: 66.0,
            is_shooting: true,
            mine_tile: None,
            mounts: Vec::new(),
            plans: None,
            rotation: 135.0,
            shield: 2.0,
            spawned_by_core: true,
            stack: ItemStack::new("", 0),
            statuses: Vec::new(),
            team: TeamId(2),
            type_id: flare.id(),
            update_building: false,
            vel: IoVec2 { x: -0.5, y: 1.25 },
            x: 32.0,
            y: 40.0,
        };

        let mut first_bytes = Vec::new();
        type_io::write_unit_sync(&mut first_bytes, &content, &first_sync).unwrap();
        let mut second_bytes = Vec::new();
        type_io::write_unit_sync(&mut second_bytes, &content, &second_sync).unwrap();
        let mut data = Vec::new();
        data.extend_from_slice(&5001i32.to_be_bytes());
        data.push(2);
        data.extend_from_slice(&first_bytes);
        data.extend_from_slice(&5002i32.to_be_bytes());
        data.push(2);
        data.extend_from_slice(&second_bytes);

        let mut runtime = GameRuntime::default();
        let report = runtime.apply_client_entity_snapshot_packet_with_content(&content, 2, &data);
        assert_eq!(report.entity_records_seen, 2);
        assert_eq!(report.entity_records_applied, 2);
        assert_eq!(report.entity_typed_records_applied, 2);
        assert_eq!(
            report.entity_opaque_bytes,
            first_bytes.len() + second_bytes.len()
        );
        assert_eq!(
            runtime
                .client_entity_snapshot_records
                .get(&5001)
                .map(|record| record.sync_bytes.as_slice()),
            Some(first_bytes.as_slice())
        );
        assert_eq!(
            runtime
                .client_entity_snapshot_records
                .get(&5002)
                .map(|record| record.sync_bytes.as_slice()),
            Some(second_bytes.as_slice())
        );

        let first = runtime.client_unit_snapshot_entities.get(&5001).unwrap();
        assert_eq!(first.type_info.id(), dagger.id());
        assert_eq!(first.team_id(), TeamId(1));
        assert_eq!(first.x(), 16.0);
        assert_eq!(first.y(), 24.0);
        assert_eq!(first.rotation(), 45.0);
        assert_eq!(first.sync.hooks.read_sync_calls, 1);
        assert_eq!(first.sync.hooks.snap_sync_calls, 1);

        let second = runtime.client_unit_snapshot_entities.get(&5002).unwrap();
        assert_eq!(second.type_info.id(), flare.id());
        assert_eq!(second.team_id(), TeamId(2));
        assert_eq!(second.x(), 32.0);
        assert_eq!(second.y(), 40.0);
        assert_eq!(second.rotation(), 135.0);
        assert!(second.weapons.is_shooting);
        assert_eq!(second.sync.hooks.read_sync_calls, 1);
        assert_eq!(second.sync.hooks.snap_sync_calls, 1);
    }

    fn single_building_network_map(
        width: u16,
        height: u16,
        index: usize,
        block_id: i16,
        building_bytes: Vec<u8>,
    ) -> LegacyShortChunkMap {
        let tile_count = width as usize * height as usize;
        assert!(index < tile_count);
        let mut blocks = Vec::new();

        if index > 0 {
            blocks.push(LegacyMapBlockRecord {
                index: 0,
                block_id: Tile::AIR,
                packed_flags: 0,
                has_entity: false,
                has_old_data: false,
                has_new_data: false,
                is_center: true,
                new_data: None,
                old_data: None,
                building: None,
                consecutives: (index - 1) as u8,
            });
        }

        blocks.push(LegacyMapBlockRecord {
            index,
            block_id,
            packed_flags: 1,
            has_entity: true,
            has_old_data: false,
            has_new_data: false,
            is_center: true,
            new_data: None,
            old_data: None,
            building: Some(building_bytes),
            consecutives: 0,
        });

        if index + 1 < tile_count {
            blocks.push(LegacyMapBlockRecord {
                index: index + 1,
                block_id: Tile::AIR,
                packed_flags: 0,
                has_entity: false,
                has_old_data: false,
                has_new_data: false,
                is_center: true,
                new_data: None,
                old_data: None,
                building: None,
                consecutives: (tile_count - index - 2) as u8,
            });
        }

        LegacyShortChunkMap {
            width,
            height,
            floors: vec![LegacyMapFloorRecord {
                index: 0,
                floor_id: 0,
                ore_id: 0,
                consecutives: (tile_count - 1) as u8,
            }],
            blocks,
        }
    }

    fn door_build_payload_ref(content: &ContentLoader, open: bool) -> PayloadRef {
        let door_def = content.block_by_name("door").unwrap();
        let door = BuildingComp::new(point2_pack(0, 0), door_def.base().clone(), TeamId(1));
        let mut build_bytes = Vec::new();
        door.write_base(&mut build_bytes, false).unwrap();
        write_door_state(&mut build_bytes, DoorState { open }).unwrap();
        PayloadRef::Block {
            block: door_def.base().id,
            version: 0,
            build_bytes,
        }
    }

