    #[test]
    fn game_runtime_exports_duct_bridge_without_item_bridge_tail() {
        let content = ContentLoader::create_base_content().unwrap();
        let bridge_def = content.block_by_name("duct-bridge").unwrap();
        let bridge_tile = point2_pack(4, 4);

        let mut base_runtime = GameRuntime::default();
        base_runtime.state.world.resize(10, 10);
        base_runtime.add_building(BuildingComp::new(
            bridge_tile,
            bridge_def.base().clone(),
            TeamId(6),
        ));
        let base_map = base_runtime.export_network_map_snapshot(&content);
        let center_index = 4usize + 4usize * 10usize;
        let base_payload = base_map
            .blocks
            .iter()
            .find(|record| record.index == center_index)
            .and_then(|record| record.building.as_ref())
            .cloned()
            .expect("duct bridge should export base building payload");

        let mut runtime = GameRuntime::default();
        runtime.state.world.resize(10, 10);
        runtime.add_building(BuildingComp::new(
            bridge_tile,
            bridge_def.base().clone(),
            TeamId(6),
        ));
        runtime.distribution_runtime_states.insert(
            bridge_tile,
            GameRuntimeDistributionBlockState::DuctBridge(DuctBridgeState {
                progress: 3.5,
                last_link: Some(point2_pack(7, 4)),
                occupied: [Some(point2_pack(1, 4)), None, None, None],
            }),
        );

        let map = runtime.export_network_map_snapshot(&content);
        let payload = map
            .blocks
            .iter()
            .find(|record| record.index == center_index)
            .and_then(|record| record.building.as_ref())
            .cloned()
            .expect("duct bridge should export base building payload");

        assert_eq!(payload.first().copied(), Some(0));
        assert_eq!(payload, base_payload);
    }

    #[test]
    fn game_runtime_configures_owned_item_mass_driver_relative_and_clears_link() {
        let content = ContentLoader::create_base_content().unwrap();
        let driver_def = content.block_by_name("mass-driver").unwrap();
        let router_def = content.block_by_name("router").unwrap();
        let source_tile = point2_pack(4, 4);
        let target_tile = point2_pack(12, 4);
        let router_tile = point2_pack(2, 2);

        let mut runtime = GameRuntime::default();
        runtime.state.world.resize(20, 10);
        runtime.add_building(BuildingComp::new(
            source_tile,
            driver_def.base().clone(),
            TeamId(6),
        ));
        runtime.add_building(BuildingComp::new(
            target_tile,
            driver_def.base().clone(),
            TeamId(6),
        ));
        runtime.add_building(BuildingComp::new(
            router_tile,
            router_def.base().clone(),
            TeamId(6),
        ));

        assert_eq!(
            runtime.configure_owned_item_mass_driver(
                &content,
                source_tile,
                Some(GameRuntimeItemMassDriverConfig::Relative { dx: 8, dy: 0 }),
            ),
            GameRuntimeItemMassDriverConfigureResult::Linked
        );
        let Some(GameRuntimeDistributionBlockState::MassDriver(state)) =
            runtime.distribution_runtime_states.get(&source_tile)
        else {
            panic!("item mass driver sidecar should be created by configure");
        };
        assert_eq!(state.link, target_tile);
        assert_eq!(
            runtime.buildings[0].config,
            Some(TypeValue::Point2(type_io::Point2::new(8, 0)))
        );

        runtime
            .item_mass_driver_waiting_shooters
            .insert(target_tile, vec![source_tile]);
        assert_eq!(
            runtime.configure_owned_item_mass_driver(
                &content,
                source_tile,
                Some(GameRuntimeItemMassDriverConfig::Packed(target_tile)),
            ),
            GameRuntimeItemMassDriverConfigureResult::Linked
        );
        assert_eq!(
            runtime.item_mass_driver_waiting_shooters.get(&target_tile),
            Some(&vec![source_tile]),
            "same link should keep an already valid waiting shooter queue"
        );

        assert_eq!(
            runtime.configure_owned_item_mass_driver(&content, source_tile, None),
            GameRuntimeItemMassDriverConfigureResult::Cleared
        );
        let Some(GameRuntimeDistributionBlockState::MassDriver(state)) =
            runtime.distribution_runtime_states.get(&source_tile)
        else {
            panic!("item mass driver sidecar should remain present after clear");
        };
        assert_eq!(state.link, -1);
        assert_eq!(runtime.buildings[0].config, None);
        assert!(runtime
            .item_mass_driver_waiting_shooters
            .get(&target_tile)
            .is_none());

        assert_eq!(
            runtime.configure_owned_item_mass_driver(
                &content,
                router_tile,
                Some(GameRuntimeItemMassDriverConfig::Packed(target_tile)),
            ),
            GameRuntimeItemMassDriverConfigureResult::NotMassDriver
        );
        assert_eq!(
            runtime.configure_owned_item_mass_driver(
                &content,
                point2_pack(1, 1),
                Some(GameRuntimeItemMassDriverConfig::Packed(target_tile)),
            ),
            GameRuntimeItemMassDriverConfigureResult::MissingBuilding
        );
    }

    #[test]
    fn game_runtime_item_mass_driver_sends_items_in_flight_and_delivers_after_delay() {
        let content = ContentLoader::create_base_content().unwrap();
        let driver_def = content.block_by_name("mass-driver").unwrap();
        let copper = content
            .item_by_name("copper")
            .unwrap()
            .base
            .mappable
            .base
            .id;
        let source_tile = point2_pack(4, 4);
        let target_tile = point2_pack(12, 4);
        let mut source_building =
            BuildingComp::new(source_tile, driver_def.base().clone(), TeamId(6));
        source_building.items.as_mut().unwrap().add(copper, 20);
        let target_building = BuildingComp::new(target_tile, driver_def.base().clone(), TeamId(6));

        let mut runtime = GameRuntime::default();
        runtime.state.set(GameStateState::Playing);
        runtime.state.world.resize(20, 10);
        runtime.add_building(source_building);
        runtime.add_building(target_building);
        runtime.distribution_runtime_states.insert(
            source_tile,
            GameRuntimeDistributionBlockState::MassDriver(MassDriverState {
                link: target_tile,
                rotation: 90.0,
                state: MassDriverStateKind::Idle,
            }),
        );

        let first_report = runtime
            .advance_owned_item_mass_drivers(&content, 1.0 / 60.0)
            .unwrap();

        assert_eq!(first_report.driver_candidates, 2);
        assert_eq!(first_report.attempted_shots, 1);
        assert_eq!(first_report.shots_fired, 0);
        assert_eq!(
            runtime
                .item_mass_driver_waiting_shooters
                .get(&target_tile)
                .cloned(),
            Some(vec![source_tile])
        );
        assert_eq!(runtime.buildings[0].items.as_ref().unwrap().get(copper), 20);
        assert_eq!(runtime.buildings[1].items.as_ref().unwrap().get(copper), 0);

        let mut aggregate = GameRuntimeItemMassDriverFrameReport::default();
        for _ in 0..24 {
            let report = runtime
                .advance_owned_item_mass_drivers(&content, 1.0 / 60.0)
                .unwrap();
            aggregate.attempted_shots += report.attempted_shots;
            aggregate.shots_fired += report.shots_fired;
            aggregate.transferred_items += report.transferred_items;
            if report.shots_fired > 0 {
                break;
            }
        }

        assert!(aggregate.attempted_shots > 0);
        assert_eq!(aggregate.shots_fired, 1);
        assert_eq!(aggregate.transferred_items, 0);
        assert_eq!(runtime.buildings[0].items.as_ref().unwrap().get(copper), 0);
        assert_eq!(runtime.buildings[1].items.as_ref().unwrap().get(copper), 0);
        assert_eq!(runtime.item_mass_driver_in_flight.len(), 1);
        let shot = &runtime.item_mass_driver_in_flight[0];
        let shot_from = (shot.from_x, shot.from_y);
        let shot_to = (shot.to_x, shot.to_y);
        assert_eq!(shot.from_tile, source_tile);
        assert_eq!(shot.to_tile, target_tile);
        assert_eq!(shot.items, vec![(copper, 20)]);
        assert_eq!(shot.x, shot.from_x);
        assert_eq!(shot.y, shot.from_y);
        assert!(shot.to_x > shot.from_x);
        assert!((shot.rotation - 0.0).abs() <= f32::EPSILON);
        assert_eq!(shot.travel_ticks, shot.remaining_ticks);
        assert_eq!(shot.elapsed_ticks, 0.0);
        assert_eq!(shot.lifetime_ticks, shot.expire_ticks);
        assert!(shot.speed > 0.0);
        assert_eq!(runtime.item_mass_driver_shoot_events.len(), 1);
        let shoot_event = &runtime.item_mass_driver_shoot_events[0];
        assert_eq!(shoot_event.from_tile, source_tile);
        assert_eq!(shoot_event.to_tile, target_tile);
        assert_eq!(shoot_event.shoot_effect, "shootBig2");
        assert_eq!(shoot_event.smoke_effect, "shootBigSmoke2");
        assert_eq!(shoot_event.shoot_sound, "massdriver");
        assert_eq!(shoot_event.shoot_sound_volume, 0.5);
        assert_eq!(shoot_event.shake, 3.0);
        assert_eq!((shoot_event.x, shoot_event.y), shot_from);
        assert_eq!(
            runtime
                .item_mass_driver_reload_counters
                .get(&source_tile)
                .copied(),
            Some(1.0)
        );

        let before_x = runtime.item_mass_driver_in_flight[0].x;
        let travel_report = runtime
            .advance_owned_item_mass_drivers(&content, 1.0 / 60.0)
            .unwrap();
        assert_eq!(travel_report.transferred_items, 0);
        assert!(runtime.item_mass_driver_in_flight[0].x > before_x);
        assert_eq!(runtime.buildings[1].items.as_ref().unwrap().get(copper), 0);

        let arrival_ticks = runtime.item_mass_driver_in_flight[0].remaining_ticks.ceil() as i32 + 1;
        let mut delivered = 0;
        for _ in 0..arrival_ticks {
            let report = runtime
                .advance_owned_item_mass_drivers(&content, 1.0 / 60.0)
                .unwrap();
            delivered += report.transferred_items;
            if delivered > 0 {
                break;
            }
        }
        assert_eq!(delivered, 20);
        assert!(runtime.item_mass_driver_in_flight.is_empty());
        assert_eq!(runtime.buildings[1].items.as_ref().unwrap().get(copper), 20);
        assert_eq!(runtime.item_mass_driver_receive_events.len(), 1);
        let receive_event = &runtime.item_mass_driver_receive_events[0];
        assert_eq!(receive_event.from_tile, source_tile);
        assert_eq!(receive_event.to_tile, target_tile);
        assert_eq!(receive_event.receive_effect, "mineBig");
        assert_eq!(receive_event.receive_sound, "massdriverReceive");
        assert_eq!(receive_event.shoot_sound_volume, 0.5);
        assert_eq!(receive_event.shake, 3.0);
        assert_eq!((receive_event.x, receive_event.y), shot_to);
        let target_reload = runtime
            .item_mass_driver_reload_counters
            .get(&target_tile)
            .copied()
            .expect("target reload counter should be initialized");
        assert!(target_reload > 0.99 && target_reload <= 1.0);
        let Some(GameRuntimeDistributionBlockState::MassDriver(source_state)) =
            runtime.distribution_runtime_states.get(&source_tile)
        else {
            panic!("source mass driver sidecar should be kept");
        };
        assert_eq!(source_state.state, MassDriverStateKind::Shooting);
        assert!((source_state.rotation - 0.0).abs() <= f32::EPSILON);
        assert!(runtime
            .item_mass_driver_waiting_shooters
            .get(&target_tile)
            .is_none());
    }

    #[test]
    fn game_runtime_item_mass_driver_resolves_on_bolt_hit_plan_before_remaining_ticks_zero() {
        let content = ContentLoader::create_base_content().unwrap();
        let driver_def = content.block_by_name("mass-driver").unwrap();
        let copper = content
            .item_by_name("copper")
            .unwrap()
            .base
            .mappable
            .base
            .id;
        let source_tile = point2_pack(4, 4);
        let target_tile = point2_pack(12, 4);
        let source_building = BuildingComp::new(source_tile, driver_def.base().clone(), TeamId(6));
        let target_building = BuildingComp::new(target_tile, driver_def.base().clone(), TeamId(6));

        let mut runtime = GameRuntime::default();
        runtime.state.set(GameStateState::Playing);
        runtime.state.world.resize(20, 10);
        runtime.add_building(source_building);
        runtime.add_building(target_building);
        runtime
            .item_mass_driver_waiting_shooters
            .insert(target_tile, vec![source_tile]);

        let Some(BlockDef::Distribution(driver_block)) = content.block(driver_def.base().id) else {
            panic!("mass-driver should be a distribution block");
        };
        let from_x = runtime.buildings[0].x;
        let from_y = runtime.buildings[0].y;
        let to_x = runtime.buildings[1].x;
        let to_y = runtime.buildings[1].y;
        let speed = driver_block.bullet_speed;
        let elapsed_inside_hit_radius = ((to_x - from_x).abs() - 6.0) / speed;
        let travel_ticks = elapsed_inside_hit_radius + 30.0;
        runtime
            .item_mass_driver_in_flight
            .push(GameRuntimeItemMassDriverInFlight {
                from_tile: source_tile,
                to_tile: target_tile,
                to_block_id: runtime.buildings[1].block.id,
                to_team: runtime.buildings[1].team,
                from_x,
                from_y,
                to_x,
                to_y,
                x: from_x,
                y: from_y,
                rotation: 0.0,
                speed,
                travel_ticks,
                remaining_ticks: travel_ticks - elapsed_inside_hit_radius,
                elapsed_ticks: elapsed_inside_hit_radius,
                lifetime_ticks: driver_block.bullet_lifetime,
                expire_ticks: driver_block.bullet_lifetime,
                target_lost: false,
                items: vec![(copper, 3)],
            });

        let remaining_before = runtime.item_mass_driver_in_flight[0].remaining_ticks;
        let report = runtime.advance_item_mass_driver_in_flight_ticks(&content, 0.0);

        assert!(
            remaining_before > 1.0,
            "test setup must keep this shot far away from the old remaining_ticks delivery path"
        );
        assert_eq!(report.transferred_items, 3);
        assert_eq!(report.despawned_shots, 0);
        assert!(runtime.item_mass_driver_in_flight.is_empty());
        assert_eq!(runtime.buildings[1].items.as_ref().unwrap().get(copper), 3);
        assert!(runtime
            .item_mass_driver_waiting_shooters
            .get(&target_tile)
            .is_none());
    }

    #[test]
    fn game_runtime_item_mass_driver_keeps_flight_after_target_removed_until_lifetime() {
        let content = ContentLoader::create_base_content().unwrap();
        let driver_def = content.block_by_name("mass-driver").unwrap();
        let copper = content
            .item_by_name("copper")
            .unwrap()
            .base
            .mappable
            .base
            .id;
        let source_tile = point2_pack(4, 4);
        let target_tile = point2_pack(12, 4);
        let mut source_building =
            BuildingComp::new(source_tile, driver_def.base().clone(), TeamId(6));
        source_building.items.as_mut().unwrap().add(copper, 20);
        let target_building = BuildingComp::new(target_tile, driver_def.base().clone(), TeamId(6));

        let mut runtime = GameRuntime::default();
        runtime.state.set(GameStateState::Playing);
        runtime.state.world.resize(20, 10);
        runtime.add_building(source_building);
        runtime.add_building(target_building);
        runtime.distribution_runtime_states.insert(
            source_tile,
            GameRuntimeDistributionBlockState::MassDriver(MassDriverState {
                link: target_tile,
                rotation: 90.0,
                state: MassDriverStateKind::Idle,
            }),
        );

        for _ in 0..32 {
            let report = runtime
                .advance_owned_item_mass_drivers(&content, 1.0 / 60.0)
                .unwrap();
            if report.shots_fired > 0 {
                break;
            }
        }
        assert_eq!(runtime.item_mass_driver_in_flight.len(), 1);
        assert_eq!(runtime.item_mass_driver_shoot_events.len(), 1);
        assert_eq!(runtime.buildings[0].items.as_ref().unwrap().get(copper), 0);
        assert!(runtime.remove_building_by_tile_pos(target_tile).is_some());

        let arrival_ticks = runtime.item_mass_driver_in_flight[0].remaining_ticks.ceil() as i32 + 1;
        for _ in 0..arrival_ticks {
            runtime
                .advance_owned_item_mass_drivers(&content, 1.0 / 60.0)
                .unwrap();
        }
        assert_eq!(
            runtime.building_index_by_tile_pos(target_tile),
            None,
            "removed target must not be recreated by in-flight delivery"
        );
        assert_eq!(runtime.item_mass_driver_in_flight.len(), 1);
        assert!(runtime.item_mass_driver_in_flight[0].target_lost);

        let expiry_ticks = runtime.item_mass_driver_in_flight[0].expire_ticks.ceil() as i32 + 1;
        let mut expiry_report = GameRuntimeItemMassDriverFrameReport::default();
        for _ in 0..expiry_ticks {
            let report = runtime
                .advance_owned_item_mass_drivers(&content, 1.0 / 60.0)
                .unwrap();
            expiry_report.despawned_shots += report.despawned_shots;
            expiry_report.dropped_items += report.dropped_items;
            expiry_report.explosion_events += report.explosion_events;
            if runtime.item_mass_driver_in_flight.is_empty() {
                break;
            }
        }
        assert!(
            runtime.item_mass_driver_in_flight.is_empty(),
            "target-lost mass driver shot should be discarded after bullet lifetime"
        );
        assert_eq!(expiry_report.despawned_shots, 1);
        assert_eq!(expiry_report.dropped_items, 20);
        assert_eq!(expiry_report.explosion_events, 1);
        assert!(
            runtime.item_mass_driver_receive_events.is_empty(),
            "target-lost mass driver shot must not emit a receive event"
        );
        assert_eq!(runtime.item_mass_driver_despawn_events.len(), 1);
        let event = &runtime.item_mass_driver_despawn_events[0];
        assert_eq!(event.from_tile, source_tile);
        assert_eq!(event.to_tile, target_tile);
        assert_eq!(event.drops.len(), 1);
        assert_eq!(event.drops[0].item_index, copper as usize);
        assert_eq!(event.drops[0].amount_dropped, 20);
        assert!(event.explosion.damage_explosions);
    }

